Transform the Python function `_extract_chapter_title` into Go 1.22, applying R04 (list comprehension → explicit loop), R09 (negative slice), R10 (for-in loop), R11 (truthiness checks). Preserve the two-phase skip-separators then consume-uppercase-words logic.

def _extract_chapter_title(text: str, pos: int) -> tuple[str, int]:
    while pos < len(text) and text[pos] in ". -\t\u2013\u2014":
        pos += 1
    words: list[str] = []
    i = pos
    while i < len(text):
        while i < len(text) and text[i] == " ":
            i += 1
        j = i
        while j < len(text) and text[j] not in " \t\n":
            j += 1
        word = text[i:j]
        if not word:
            break
        alpha = [c for c in word if c.isalpha()]
        if not alpha:
            if word.isdigit():
                break  # page number -> TOC entry, stop
            i = j
            continue
        if all(c.isupper() for c in alpha):
            words.append(word.rstrip(".,;:"))
            i = j
        else:
            break
    return " ".join(words).strip().rstrip(".,;:\u2013\u2014-"), i

import (
	"strings"
	"unicode"
)

// extractChapterTitle extracts ALL-CAPS title words from text starting at pos.
// Returns (titleString, endPos) where endPos is the start of prose.
func extractChapterTitle(text string, pos int) (string, int) {
	skipChars := ". -\t\u2013\u2014"
	for pos < len(text) && strings.ContainsRune(skipChars, rune(text[pos])) {
		pos++
	}
	var words []string
	i := pos
	for i < len(text) {
		for i < len(text) && text[i] == ' ' {
			i++
		}
		j := i
		for j < len(text) && text[j] != ' ' && text[j] != '\t' && text[j] != '\n' {
			j++
		}
		word := text[i:j]
		if len(word) == 0 {
			break
		}
		var alpha []rune
		for _, c := range word {
			if unicode.IsLetter(c) {
				alpha = append(alpha, c)
			}
		}
		if len(alpha) == 0 {
			isDigit := true
			for _, c := range word {
				if !unicode.IsDigit(c) {
					isDigit = false
					break
				}
			}
			if isDigit {
				break // page number -> TOC entry, stop
			}
			i = j
			continue
		}
		allUpper := true
		for _, c := range alpha {
			if !unicode.IsUpper(c) {
				allUpper = false
				break
			}
		}
		if allUpper {
			words = append(words, strings.TrimRight(word, ".,;:"))
			i = j
		} else {
			break
		}
	}
	result := strings.TrimRight(strings.TrimSpace(strings.Join(words, " ")), ".,;:\u2013\u2014-")
	return result, i
}

Transform the Python function `_promote_structural_levels` into Go 1.22, applying R04 (comprehensions → loops), R05 (dict/set → map), R10 (for-in with enumerate), R11 (truthiness). Preserve TOC-cluster detection, right-to-left replacement, and strip_toc logic.

def _promote_structural_levels(
    text: str,
    structural_levels: list[tuple[str, int]],
    toc_proximity: int,
    strip_toc: bool,
) -> str:
    all_hits: list[tuple[int, int, str, int]] = []  # (pos, end, marker, level)
    for pattern_str, level in structural_levels:
        for m in re.compile(pattern_str).finditer(text):
            all_hits.append((m.start(), m.end(), m.group(0), level))
    all_hits.sort(key=lambda x: x[0])

    toc_idx: set[int] = set()
    by_level: dict[int, list[int]] = {}
    for idx, (_, _, _, lvl) in enumerate(all_hits):
        by_level.setdefault(lvl, []).append(idx)
    for level_indices in by_level.values():
        for k in range(len(level_indices) - 1):
            ia, ib = level_indices[k], level_indices[k + 1]
            if all_hits[ib][0] - all_hits[ia][0] < toc_proximity:
                toc_idx.add(ia)
                toc_idx.add(ib)

    for i in range(len(all_hits) - 1, -1, -1):
        pos, end, marker, level = all_hits[i]
        if i in toc_idx:
            if strip_toc:
                _, prose_start = _extract_chapter_title(text, end)
                text = text[:pos] + text[prose_start:]
            continue
        hashes = "#" * level
        title, prose_start = _extract_chapter_title(text, end)
        heading = f"\n\n{hashes} {marker}"
        if title:
            heading += f": {title}"
        heading += "\n\n"
        text = text[:pos] + heading + text[prose_start:]
    return text

import (
	"fmt"
	"regexp"
	"sort"
	"strings"
)

type hitEntry struct {
	pos, end int
	marker   string
	level    int
}

func promoteStructuralLevels(text string, structuralLevels [][2]interface{}, tocProximity int, stripToc bool) (string, error) {
	var allHits []hitEntry
	for _, pair := range structuralLevels {
		patternStr, ok1 := pair[0].(string)
		level, ok2 := pair[1].(int)
		if !ok1 || !ok2 {
			return "", fmt.Errorf("promoteStructuralLevels: invalid pair type")
		}
		re, err := regexp.Compile(patternStr)
		if err != nil {
			return "", fmt.Errorf("promoteStructuralLevels: compile pattern %q: %w", patternStr, err)
		}
		matches := re.FindAllStringIndex(text, -1)
		for _, loc := range matches {
			allHits = append(allHits, hitEntry{pos: loc[0], end: loc[1], marker: text[loc[0]:loc[1]], level: level})
		}
	}
	sort.Slice(allHits, func(a, b int) bool { return allHits[a].pos < allHits[b].pos })

	tocIdx := make(map[int]struct{})
	byLevel := make(map[int][]int)
	for idx, h := range allHits {
		byLevel[h.level] = append(byLevel[h.level], idx)
	}
	for _, levelIndices := range byLevel {
		for k := 0; k < len(levelIndices)-1; k++ {
			ia, ib := levelIndices[k], levelIndices[k+1]
			if allHits[ib].pos-allHits[ia].pos < tocProximity {
				tocIdx[ia] = struct{}{}
				tocIdx[ib] = struct{}{}
			}
		}
	}

	for i := len(allHits) - 1; i >= 0; i-- {
		h := allHits[i]
		if _, inToc := tocIdx[i]; inToc {
			if stripToc {
				_, proseStart := extractChapterTitle(text, h.end)
				text = text[:h.pos] + text[proseStart:]
			}
			continue
		}
		hashes := strings.Repeat("#", h.level)
		title, proseStart := extractChapterTitle(text, h.end)
		heading := fmt.Sprintf("\n\n%s %s", hashes, h.marker)
		if len(title) > 0 {
			heading += fmt.Sprintf(": %s", title)
		}
		heading += "\n\n"
		text = text[:h.pos] + heading + text[proseStart:]
	}
	return text, nil
}

Transform the Python function `_strip_index_paragraphs` into Go 1.22, applying R04 (list comprehension → explicit loop), R10 (for-in loop), R11 (truthiness). Preserve paragraph splitting, per-line index detection, and fraction-based filtering.

def _strip_index_paragraphs(text: str, index_line_threshold: float) -> str:
    _INDEX_LINE_RE = re.compile(r'^.{2,60},\s*\d[\d,\s\-\u2013]*$')
    paras = text.split("\n\n")
    cleaned = []
    for para in paras:
        lines = [l for l in para.splitlines() if l.strip()]
        if not lines:
            cleaned.append(para)
            continue
        index_lines = sum(1 for l in lines if _INDEX_LINE_RE.match(l.strip()))
        if index_lines / len(lines) >= index_line_threshold:
            continue  # drop entire paragraph
        cleaned.append(para)
    return "\n\n".join(cleaned)

import (
	"regexp"
	"strings"
)

var indexLineRE = regexp.MustCompile(`^.{2,60},\s*\d[\d,\s\-\x{2013}]*$`)

func stripIndexParagraphs(text string, indexLineThreshold float64) string {
	paras := strings.Split(text, "\n\n")
	var cleaned []string
	for _, para := range paras {
		rawLines := strings.Split(para, "\n")
		var lines []string
		for _, l := range rawLines {
			if len(strings.TrimSpace(l)) > 0 {
				lines = append(lines, l)
			}
		}
		if len(lines) == 0 {
			cleaned = append(cleaned, para)
			continue
		}
		indexLines := 0
		for _, l := range lines {
			if indexLineRE.MatchString(strings.TrimSpace(l)) {
				indexLines++
			}
		}
		if float64(indexLines)/float64(len(lines)) >= indexLineThreshold {
			continue // drop entire paragraph
		}
		cleaned = append(cleaned, para)
	}
	return strings.Join(cleaned, "\n\n")
}

Transform the Python function `_promote_question_sentences` into Go 1.22, applying R10 (for-in with index), R11 (truthiness), R08 (f-string → fmt.Sprintf), R09 (slice boundary). Preserve sentence splitting, question-run guard, and word/char count guards.

def _promote_question_sentences(
    text: str,
    max_header_words: int,
    max_header_chars: int,
) -> str:
    sentences = _SENT_END_RE.split(text)
    out: list[str] = []
    i = 0
    while i < len(sentences):
        s = sentences[i].strip()
        next_s = sentences[i + 1].strip() if i + 1 < len(sentences) else ""
        if (
            s.endswith("?")
            and not next_s.endswith("?")           # not a run of questions
            and len(s.split()) <= max_header_words * 2  # not a paragraph
            and len(s) <= max_header_chars * 2
        ):
            out.append(f"\n\n## {s}\n\n")
        else:
            out.append((" " if out and not out[-1].endswith("\n") else "") + s)
        i += 1
    return "".join(out).strip()

import (
	"fmt"
	"regexp"
	"strings"
)

var sentEndRE = regexp.MustCompile(`(?:[.?!])\s+`)

func promoteQuestionSentences(text string, maxHeaderWords, maxHeaderChars int) string {
	sentences := sentEndRE.Split(text, -1)
	var out []string
	for i := 0; i < len(sentences); i++ {
		s := strings.TrimSpace(sentences[i])
		nextS := ""
		if i+1 < len(sentences) {
			nextS = strings.TrimSpace(sentences[i+1])
		}
		wordCount := len(strings.Fields(s))
		if strings.HasSuffix(s, "?") &&
			!strings.HasSuffix(nextS, "?") &&
			wordCount <= maxHeaderWords*2 &&
			len(s) <= maxHeaderChars*2 {
			out = append(out, fmt.Sprintf("\n\n## %s\n\n", s))
		} else {
			prefix := ""
			if len(out) > 0 && !strings.HasSuffix(out[len(out)-1], "\n") {
				prefix = " "
			}
			out = append(out, prefix+s)
		}
	}
	return strings.TrimSpace(strings.Join(out, ""))
}

import "strings"

func mergeBlocks(paragraphs []string, separator string) []string {
	var merged []string
	i := 0
	for i < len(paragraphs) {
		para := paragraphs[i]
		var lines []string
		if strings.Contains(para, "\n") {
			lines = strings.Split(para, "\n")
		} else {
			lines = []string{para}
		}

		hasTableLine := false
		for _, l := range lines {
			if len(strings.TrimSpace(l)) > 0 && isTableLine(l) {
				hasTableLine = true
				break
			}
		}
		if hasTableLine {
			blockParts := []string{para}
			j := i + 1
			for j < len(paragraphs) {
				var nextLines []string
				if strings.Contains(paragraphs[j], "\n") {
					nextLines = strings.Split(paragraphs[j], "\n")
				} else {
					nextLines = []string{paragraphs[j]}
				}
				hasNext := false
				for _, l := range nextLines {
					if len(strings.TrimSpace(l)) > 0 && isTableLine(l) {
						hasNext = true
						break
					}
				}
				if hasNext {
					blockParts = append(blockParts, paragraphs[j])
					j++
				} else {
					break
				}
			}
			merged = append(merged, strings.Join(blockParts, separator))
			i = j
			continue
		}

		hasListLine := false
		for _, l := range lines {
			if len(strings.TrimSpace(l)) > 0 && isListLine(l) {
				hasListLine = true
				break
			}
		}
		if hasListLine {
			blockParts := []string{para}
			j := i + 1
			for j < len(paragraphs) {
				var nextLines []string
				if strings.Contains(paragraphs[j], "\n") {
					nextLines = strings.Split(paragraphs[j], "\n")
				} else {
					nextLines = []string{paragraphs[j]}
				}
				hasNext := false
				for _, l := range nextLines {
					if len(strings.TrimSpace(l)) > 0 && isListLine(l) {
						hasNext = true
						break
					}
				}
				if hasNext {
					blockParts = append(blockParts, paragraphs[j])
					j++
				} else {
					break
				}
			}
			merged = append(merged, strings.Join(blockParts, separator))
			i = j
			continue
		}

		merged = append(merged, para)
		i++
	}
	return merged
}

Transform the Python function `_split_at_words` into Go 1.22, applying R10 (for-in → range), R11 (truthiness), R05 (list → slice). Preserve the word-boundary greedy accumulation and the single-oversized-word pass-through.

def _split_at_words(text: str, max_size: int) -> list[str]:
    if len(text) <= max_size:
        return [text]
    words = _WORD_BOUNDARY_RE.split(text)
    pieces: list[str] = []
    current = ""
    for word in words:
        candidate = (current + " " + word) if current else word
        if len(candidate) <= max_size:
            current = candidate
        else:
            if current:
                pieces.append(current)
            current = word
    if current:
        pieces.append(current)
    return pieces or [text]

import (
	"regexp"
	"strings"
)

var wordBoundaryRE = regexp.MustCompile(`\s+`)

func splitAtWords(text string, maxSize int) []string {
	if len(text) <= maxSize {
		return []string{text}
	}
	words := wordBoundaryRE.Split(text, -1)
	var pieces []string
	current := ""
	for _, word := range words {
		var candidate string
		if len(current) > 0 {
			candidate = current + " " + word
		} else {
			candidate = word
		}
		if len(candidate) <= maxSize {
			current = candidate
		} else {
			if len(current) > 0 {
				pieces = append(pieces, current)
			}
			current = word
		}
	}
	if len(current) > 0 {
		pieces = append(pieces, current)
	}
	if len(pieces) == 0 {
		return []string{text}
	}
	return pieces
}

Transform the Python function `_split_at_sentences` into Go 1.22, applying R10 (for-in → range), R11 (truthiness), R05 (list → slice). Preserve sentence-boundary greedy accumulation, fallback to word-boundary splits for oversized pieces, and the `or [text]` guard.

def _split_at_sentences(text: str, max_size: int) -> list[str]:
    if len(text) <= max_size:
        return [text]
    raw_parts = _SENTENCE_END_RE.split(text)
    pieces: list[str] = []
    current = ""
    for part in raw_parts:
        candidate = (current + " " + part).strip() if current else part
        if len(candidate) <= max_size:
            current = candidate
        else:
            if current:
                pieces.append(current)
            current = part
    if current:
        pieces.append(current)
    result: list[str] = []
    for piece in (pieces or [text]):
        if len(piece) > max_size:
            result.extend(_split_at_words(piece, max_size))
        else:
            result.append(piece)
    return result or [text]

import (
	"regexp"
	"strings"
)

var sentenceEndRE = regexp.MustCompile(`(?:[.?!])\s+`)

func splitAtSentences(text string, maxSize int) []string {
	if len(text) <= maxSize {
		return []string{text}
	}
	rawParts := sentenceEndRE.Split(text, -1)
	var pieces []string
	current := ""
	for _, part := range rawParts {
		var candidate string
		if len(current) > 0 {
			candidate = strings.TrimSpace(current + " " + part)
		} else {
			candidate = part
		}
		if len(candidate) <= maxSize {
			current = candidate
		} else {
			if len(current) > 0 {
				pieces = append(pieces, current)
			}
			current = part
		}
	}
	if len(current) > 0 {
		pieces = append(pieces, current)
	}
	if len(pieces) == 0 {
		pieces = []string{text}
	}
	var result []string
	for _, piece := range pieces {
		if len(piece) > maxSize {
			result = append(result, splitAtWords(piece, maxSize)...)
		} else {
			result = append(result, piece)
		}
	}
	if len(result) == 0 {
		return []string{text}
	}
	return result
}

Transform the Python function `_lca_path` into Go 1.22, applying R04 (comprehension → loop), R05 (list → slice), R10 (for-in → range), R11 (truthiness). Preserve the non-empty filter, single-path shortcut, zip-based common-prefix loop, and empty-LCA fallback to last non-empty path.

def _lca_path(paths: list[list[str]]) -> list[str]:
    non_empty = [p for p in paths if p]
    if not non_empty:
        return []
    if len(non_empty) == 1:
        return list(non_empty[0])
    result: list[str] = []
    for parts in zip(*non_empty):
        if len(set(parts)) == 1:
            result.append(parts[0])
        else:
            break
    return result if result else list(non_empty[-1])

func lcaPath(paths [][]string) []string {
	var nonEmpty [][]string
	for _, p := range paths {
		if len(p) > 0 {
			nonEmpty = append(nonEmpty, p)
		}
	}
	if len(nonEmpty) == 0 {
		return []string{}
	}
	if len(nonEmpty) == 1 {
		result := make([]string, len(nonEmpty[0]))
		copy(result, nonEmpty[0])
		return result
	}
	minLen := len(nonEmpty[0])
	for _, p := range nonEmpty[1:] {
		if len(p) < minLen {
			minLen = len(p)
		}
	}
	var result []string
	for i := 0; i < minLen; i++ {
		val := nonEmpty[0][i]
		allSame := true
		for _, p := range nonEmpty[1:] {
			if p[i] != val {
				allSame = false
				break
			}
		}
		if allSame {
			result = append(result, val)
		} else {
			break
		}
	}
	if len(result) > 0 {
		return result
	}
	last := nonEmpty[len(nonEmpty)-1]
	out := make([]string, len(last))
	copy(out, last)
	return out
}

Transform the inner closure `_build_crumb` (extracted from `chunk_document`) into a standalone Go 1.22 function, applying R06 (None → nil/*string), R08 (f-string → fmt.Sprintf), R10 (for range), R11 (truthiness). Preserve the max_breadcrumb_chars compression loop that drops middle elements.

def _build_crumb(lca: list[str]) -> str:
        parts = ([name] if include_doc_name else []) + lca
        if not parts:
            return ""
        if max_breadcrumb_chars is not None:
            # Drop intermediate levels one at a time until within limit.
            # Always preserve first and last elements.
            compressed = list(parts)
            while len(f"[{' > '.join(compressed)}]") > max_breadcrumb_chars and len(compressed) > 2:
                mid = len(compressed) // 2
                if compressed[mid] == "...":
                    compressed.pop(mid + 1 if mid + 1 < len(compressed) - 1 else mid - 1)
                else:
                    compressed[mid] = "..."
                    if mid > 0 and compressed[mid - 1] == "...":
                        compressed.pop(mid)
            parts = compressed
        return f"[{' > '.join(parts)}]"

import (
	"fmt"
	"strings"
)

// buildCrumb builds the breadcrumb string from lca segments.
// name is prepended when includeDocName is true.
// maxBreadcrumbChars nil means no compression.
func buildCrumb(name string, includeDocName bool, lca []string, maxBreadcrumbChars *int) string {
	var parts []string
	if includeDocName {
		parts = append(parts, name)
	}
	parts = append(parts, lca...)
	if len(parts) == 0 {
		return ""
	}
	if maxBreadcrumbChars != nil {
		compressed := make([]string, len(parts))
		copy(compressed, parts)
		for len(fmt.Sprintf("[%s]", strings.Join(compressed, " > "))) > *maxBreadcrumbChars && len(compressed) > 2 {
			mid := len(compressed) / 2
			if compressed[mid] == "..." {
				target := mid + 1
				if target >= len(compressed)-1 {
					target = mid - 1
				}
				compressed = append(compressed[:target], compressed[target+1:]...)
			} else {
				compressed[mid] = "..."
				if mid > 0 && compressed[mid-1] == "..." {
					compressed = append(compressed[:mid], compressed[mid+1:]...)
				}
			}
		}
		parts = compressed
	}
	return fmt.Sprintf("[%s]", strings.Join(parts, " > "))
}

import (
	"fmt"
	"strings"
)

// flushChunk produces a DocumentChunk from accumulated text.
// currentSectionPaths and include* params are passed explicitly to avoid closure state.
func flushChunk(
	name string,
	text string,
	idx int,
	offset *int,
	paragraphContinuation bool,
	embeddingText *string,
	currentSectionPaths [][]string,
	includeBreadcrumb bool,
	includeDocName bool,
	maxBreadcrumbChars *int,
) DocumentChunk {
	lca := lcaPath(currentSectionPaths)
	var crumb *string
	var embedding *string
	base := text
	if embeddingText != nil {
		base = *embeddingText
	}
	if includeBreadcrumb && len(base) > 0 {
		c := buildCrumb(name, includeDocName, lca, maxBreadcrumbChars)
		if len(c) > 0 {
			crumb = &c
			e := fmt.Sprintf("%s\n\n%s", c, base)
			embedding = &e
		} else {
			embedding = &base
		}
	} else if embeddingText != nil {
		var lastSection string
		if len(lca) > 0 {
			lastSection = lca[len(lca)-1]
		}
		if len(lastSection) > 0 {
			e := fmt.Sprintf("%s\n\n%s", lastSection, base)
			embedding = &e
		} else {
			embedding = &base
		}
	}
	srcLen := len([]byte(text))
	section := make([]string, len(lca))
	copy(section, lca)
	_ = strings.Join // import anchor
	return DocumentChunk{
		DocumentName:          name,
		Content:               text,
		Section:               section,
		ChunkIndex:            idx,
		SourceOffset:          offset,
		SourceLength:          srcLen,
		Breadcrumb:            crumb,
		EmbeddingContent:      embedding,
		ParagraphContinuation: paragraphContinuation,
	}
}

Transform the inner function `_build_table_enrichment` (extracted from `chunk_document`) into a standalone Go 1.22 function, applying R08 (f-string → fmt.Sprintf), R09 (slice with i==0 guard), R10 (for range), R11 (truthiness). Preserve the header-skip for first piece, row-chunking loop, and three-way marker selection.

def _build_table_enrichment(
        pieces: list[str],
        table_headers: list[str],
        i: int,
        n: int,
        marker_start: str,
        marker_cont: str,
        marker_end: str,
    ) -> str | None:
        nh = len(table_headers)
        raw_cells = _table_cells_from_text(pieces[i])
        cells = raw_cells[nh:] if i == 0 else raw_cells
        rows_enriched = []
        for ri in range(0, len(cells), nh):
            row = cells[ri : ri + nh]
            if len(row) == nh:
                rows_enriched.append(
                    ' | '.join(f"{h.lower()}: {v}" for h, v in zip(table_headers, row))
                )
        if not rows_enriched:
            return None
        if i == 0:
            em_markers = f"{marker_start}\n{{body}}\n{marker_cont}"
        elif i < n - 1:
            em_markers = f"{marker_cont}\n{{body}}\n{marker_cont}"
        else:
            em_markers = f"{marker_cont}\n{{body}}\n{marker_end}"
        return em_markers.format(body='\n'.join(rows_enriched))

import (
	"fmt"
	"strings"
)

// buildTableEnrichment builds enriched col:val embedding for a table piece, or returns nil.
func buildTableEnrichment(
	pieces []string,
	tableHeaders []string,
	i, n int,
	markerStart, markerCont, markerEnd string,
) *string {
	nh := len(tableHeaders)
	rawCells := tableCellsFromText(pieces[i])
	var cells []string
	if i == 0 {
		if len(rawCells) > nh {
			cells = rawCells[nh:]
		}
	} else {
		cells = rawCells
	}
	var rowsEnriched []string
	for ri := 0; ri < len(cells); ri += nh {
		end := ri + nh
		if end > len(cells) {
			break
		}
		row := cells[ri:end]
		var parts []string
		for j, h := range tableHeaders {
			parts = append(parts, fmt.Sprintf("%s: %s", strings.ToLower(h), row[j]))
		}
		rowsEnriched = append(rowsEnriched, strings.Join(parts, " | "))
	}
	if len(rowsEnriched) == 0 {
		return nil
	}
	body := strings.Join(rowsEnriched, "\n")
	var emMarkers string
	if i == 0 {
		emMarkers = fmt.Sprintf("%s\n%%s\n%s", markerStart, markerCont)
	} else if i < n-1 {
		emMarkers = fmt.Sprintf("%s\n%%s\n%s", markerCont, markerCont)
	} else {
		emMarkers = fmt.Sprintf("%s\n%%s\n%s", markerCont, markerEnd)
	}
	result := fmt.Sprintf(emMarkers, body)
	return &result
}

import "fmt"

// buildPieceContent builds the marked content string for a non-para split piece.
func buildPieceContent(
	piece string,
	i, n int,
	tableHeader *string,
	markerStart, markerCont, markerEnd string,
) string {
	if n == 1 {
		return piece
	}
	headerPrefix := ""
	if tableHeader != nil && len(*tableHeader) > 0 {
		headerPrefix = fmt.Sprintf("%s\n", *tableHeader)
	}
	if i == 0 {
		return fmt.Sprintf("%s\n%s\n%s", markerStart, piece, markerCont)
	}
	if i < n-1 {
		return fmt.Sprintf("%s\n%s%s\n%s", markerCont, headerPrefix, piece, markerCont)
	}
	return fmt.Sprintf("%s\n%s%s\n%s", markerCont, headerPrefix, piece, markerEnd)
}

import "strings"

type headingEntry struct {
	level int
	text  string
}

// processHeadingPara handles a heading paragraph, updating stack and path.
// Returns (updatedCurrentPath, shouldFlush, flushClearPaths).
func processHeadingPara(
	para string,
	currentChunk string,
	minChunkSize int,
	headingStack []headingEntry,
	currentSectionPaths [][]string,
) (currentPath []string, updatedStack []headingEntry, flush bool, flushClearPaths bool) {
	level := len(para) - len(strings.TrimLeft(para, "#"))
	headingText := strings.TrimSpace(strings.TrimLeft(para, "#"))

	flush = false
	flushClearPaths = false
	if len(currentChunk) > 0 && len(currentChunk) >= minChunkSize && !headingOnly(currentChunk) {
		flush = true
		flushClearPaths = true
	}

	for len(headingStack) > 0 && headingStack[len(headingStack)-1].level >= level {
		headingStack = headingStack[:len(headingStack)-1]
	}
	headingStack = append(headingStack, headingEntry{level: level, text: headingText})

	var path []string
	for _, e := range headingStack {
		path = append(path, e.text)
	}
	return path, headingStack, flush, flushClearPaths
}

// headingOnly returns true when all non-empty lines start with '#'.
func headingOnly(text string) bool {
	for _, l := range strings.Split(text, "\n") {
		trimmed := strings.TrimSpace(l)
		if len(trimmed) > 0 && !strings.HasPrefix(trimmed, "#") {
			return false
		}
	}
	return true
}

