        raise ValueError(f"Unknown source type: {source_type!r}")

func (idx *Indexer) crawl(sourceConfig map[string]any) ([]*DocumentChunk, error) {
	sourceType, _ := sourceConfig["type"].(string)
	if sourceType == "" {
		sourceType = "directory"
	}
	uri, _ := sourceConfig["uri"].(string)

	loaderOpts := DocumentLoaderOptions{
