		return loaderWT.LoadCrawl(uri, crawler)
	case "http":
		return loader.Load(uri)
	default:
		return nil, fmt.Errorf("unknown source type: %q", sourceType)
	}
}

// Note: enrichOverride is a *bool; nil means "not set" (distinct from false).
func makeLoader(cfg map[string]any, enrichOverride *bool) (*DocumentLoader, error) {
