	seenDomain := map[string]string{}
	getDomainID := func(namespaceID, domainName string) (string, error) {
		key := fmt.Sprintf("%s:%s", namespaceID, domainName)
		if did, ok := seenDomain[key]; ok {
			return did, nil
		}
		var descPtr *string
		if nsD := nsDomains[namespaceID]; nsD != nil {
			if d, ok := nsD[domainName]; ok {
				descPtr = &d
			}
		}
		did := stableID(namespaceID, domainName)
		if err := store.RegisterDomain(did, namespaceID, domainName, descPtr); err != nil {
			return "", fmt.Errorf("register domain %q: %w", domainName, err)
		}
		seenDomain[key] = did
		return did, nil
	}

	sources, _ := cfg["sources"].([]any)
	var sourceChunks []sourceChunkEntry
	for _, rawSrc := range sources {
		src, _ := rawSrc.(map[string]any)
		stype, _ := src["type"].(string)
		fn := ingestFns[stype]
		if fn == nil {
			return nil, fmt.Errorf("unknown source type: %q", stype)
		}
		name, _ := src["name"].(string)
		if name == "" {
			name = stype
		}
		namespaceID, _ := src["namespace"].(string)
		domainName, _ := src["domain"].(string)
		if domainName == "" {
			domainName = name
		}
		var domainID string
		if namespaceID != "" {
			if nsDomains[namespaceID] == nil {
				if err := store.RegisterNamespace(namespaceID, nil); err != nil {
					return nil, err
				}
				nsDomains[namespaceID] = map[string]string{}
			}
			var err error
			domainID, err = getDomainID(namespaceID, domainName)
			if err != nil {
				return nil, err
			}
		}
		loader := defaultLoader
		if enrichRaw, ok := src["enrich_context"]; ok {
			enrich, _ := enrichRaw.(bool)
			var enrichPtr *bool
			enrichPtr = &enrich
			var err error
			loader, err = makeLoader(map[string]any{"loader": loaderCfg}, enrichPtr)
			if err != nil {
				return nil, err
			}
		}
		label := fmt.Sprintf("%q", name)
		if namespaceID != "" {
			label += fmt.Sprintf(" -> %s/%s", namespaceID, domainName)
		}
		fmt.Printf("Ingesting %s...\n", label)
		chunks, err := fn(loader, src)
		if err != nil {
			return nil, fmt.Errorf("ingest source %q: %w", name, err)
		}
		sourceChunks = append(sourceChunks, sourceChunkEntry{chunks: chunks, namespaceID: namespaceID, domainID: domainID})
		fmt.Printf("  %d chunks\n", len(chunks))
	}
	return sourceChunks, nil
}

Transform the Python `_build_svo_phase` function into Go 1.22, applying R03 (try/except ImportError → error return), R06 (None → nil), R11 (if llm_client is None → explicit nil check), R08 (f-string → fmt.Sprintf). Preserve LLM-client construction and fallback error.

def _build_svo_phase(
    store: Store,
    ic: dict[str, Any],
    svo_model: str,
    force: bool,
) -> None:
    """Phase: SVO — build subject-verb-object triple graph via LLM."""
    existing = store.vector._conn.execute("SELECT COUNT(*) FROM svo_triples").fetchone()[0]
    if existing == 0 or force:
        print(f"Building SVO graph via {svo_model!r} (calls LLM API)...")
        from .graph import EntityGraphPipeline, SVOExtractor

        llm_client = ic.get("svo_llm_client")
        if llm_client is None:
            try:
                from openai import OpenAI as _OpenAI

                class _OpenAILLMClient:
                    def __init__(self, model: str) -> None:
                        self._client = _OpenAI()
                        self._model = model

                    def complete(self, prompt: str) -> str:
                        resp = self._client.chat.completions.create(
                            model=self._model,
                            messages=[{"role": "user", "content": prompt}],
                        )
                        return resp.choices[0].message.content or ""

                llm_client = _OpenAILLMClient(svo_model)
            except ImportError:
                raise RuntimeError(
                    "index.svo=true requires openai installed or an LLMClient "
                    "passed as index.svo_llm_client in the config dict."
                )

        extractor = SVOExtractor(llm_client)
        pipeline = EntityGraphPipeline(extractor)
        stats = pipeline.build(store, force=force)
        print(f"  {stats.triples_written} triples.")
    else:
        print(f"SVO index: {existing:,} triples (skipped)")

func buildSVOPhase(store *Store, ic map[string]any, svoModel string, force bool) error {
	var existing int
	row := store.Vector.Conn.QueryRow("SELECT COUNT(*) FROM svo_triples")
	if err := row.Scan(&existing); err != nil {
		return fmt.Errorf("buildSVOPhase: count triples: %w", err)
	}
	if existing == 0 || force {
		fmt.Printf("Building SVO graph via %q (calls LLM API)...\n", svoModel)
		var llmClient LLMClient
		if v := ic["svo_llm_client"]; v != nil {
			var ok bool
			llmClient, ok = v.(LLMClient)
			if !ok {
				return fmt.Errorf("buildSVOPhase: svo_llm_client does not implement LLMClient")
			}
		}
		if llmClient == nil {
			openAIClient, err := NewOpenAILLMClient(svoModel)
			if err != nil {
				return fmt.Errorf("buildSVOPhase: index.svo=true requires an OpenAI client or LLMClient in config: %w", err)
			}
			llmClient = openAIClient
		}
		extractor := NewSVOExtractor(llmClient)
		pipeline := NewEntityGraphPipeline(extractor)
		stats, err := pipeline.Build(store, force)
		if err != nil {
			return fmt.Errorf("buildSVOPhase: pipeline.Build: %w", err)
		}
		fmt.Printf("  %d triples.\n", stats.TriplesWritten)
	} else {
		fmt.Printf("SVO index: %d triples (skipped)\n", existing)
	}
	return nil
}

func Build(configInput any, force bool) (*Index, error) {
	var cfg map[string]any
	switch v := configInput.(type) {
	case map[string]any:
		cfg = v
	case string:
		data, err := os.ReadFile(v)
		if err != nil {
			return nil, fmt.Errorf("Build: read config %q: %w", v, err)
		}
		if err := yaml.Unmarshal(data, &cfg); err != nil {
			return nil, fmt.Errorf("Build: parse config: %w", err)
		}
	default:
		return nil, fmt.Errorf("Build: config must be a file path (string) or map[string]any")
	}

	sc, _ := cfg["store"].(map[string]any)
	if sc == nil {
		sc = map[string]any{}
	}
	dbPathStr, _ := sc["path"].(string)
	if dbPathStr == "" {
		return nil, fmt.Errorf("Build: store.path is required")
	}
	embeddingDim := 1024
	if v, ok := sc["embedding_dim"].(int); ok && v > 0 {
		embeddingDim = v
	}

	embedCfg, _ := cfg["embed"].(map[string]any)
	if embedCfg == nil {
		embedCfg = map[string]any{}
	}
	embedModelName := "BAAI/bge-large-en-v1.5"
	if v, ok := embedCfg["model"].(string); ok && v != "" {
		embedModelName = v
	}

	loaderCfg, _ := cfg["loader"].(map[string]any)
	if loaderCfg == nil {
		loaderCfg = map[string]any{}
	}
	ic, _ := cfg["index"].(map[string]any)
	if ic == nil {
		ic = map[string]any{}
	}
	runNER := boolFromMap(ic, "ner", true)
	runCommunity := boolFromMap(ic, "community", true)
	runSVO := boolFromMap(ic, "svo", false)
	spacyModel := stringFromMap(ic, "spacy_model", "en_core_web_sm")
	svoModel := stringFromMap(ic, "svo_model", "gpt-4o-mini")
	communityAlpha := float64FromMap(ic, "community_alpha", 0.2)
	communitySimThreshold := float64FromMap(ic, "community_sim_threshold", 0.6)

	searchDefaults := map[string]any{
		"entity_ref_expansion": true,
		"lane_entity_min_sim":  0.60,
	}
	if sv, ok := cfg["search"].(map[string]any); ok {
		for k, v := range sv {
			searchDefaults[k] = v
		}
	}

	store, err := buildIngestPhase(cfg, dbPathStr, embeddingDim, loaderCfg, embedCfg, force)
	if err != nil {
		return nil, fmt.Errorf("Build: ingest phase: %w", err)
	}

	if runNER {
		var existing int
		row := store.Vector.Conn.QueryRow("SELECT COUNT(*) FROM chunk_entities")
		if err := row.Scan(&existing); err != nil {
			return nil, fmt.Errorf("Build: NER count: %w", err)
		}
		if existing == 0 || force {
			fmt.Println("Building NER index...")
			if err := BuildNER(store, spacyModel); err != nil {
				return nil, fmt.Errorf("Build: NER: %w", err)
			}
			fmt.Println("  NER done.")
		} else {
			fmt.Printf("NER index: %d associations (skipped)\n", existing)
		}
	}

	if runCommunity {
		var existing int
		row := store.Vector.Conn.QueryRow("SELECT COUNT(*) FROM chunk_communities")
		if err := row.Scan(&existing); err != nil {
			return nil, fmt.Errorf("Build: community count: %w", err)
		}
		if existing == 0 || force {
			fmt.Println("Building community index...")
			n, err := BuildCommunity(dbPathStr, embedModelName, communityAlpha, communitySimThreshold, force)
			if err != nil {
				return nil, fmt.Errorf("Build: community: %w", err)
			}
			fmt.Printf("  %d communities.\n", n)
		} else {
			fmt.Printf("Community index: %d assignments (skipped)\n", existing)
		}
	}

	if runSVO {
		if err := buildSVOPhase(store, ic, svoModel, force); err != nil {
			return nil, fmt.Errorf("Build: SVO: %w", err)
		}
	}

	return NewIndex(store, embedModelName, searchDefaults, ic, loaderCfg, embedCfg)
}

func (idx *Index) AddSource(src map[string]any, rebuild bool, cbs RebuildCallbacks) (*IndexHandle, error) {
	namespaceID, _ := src["namespace"].(string)
	if namespaceID == "" {
		namespaceID = "global"
	}
	domainName, _ := src["domain"].(string)
	if domainName == "" {
		if n, ok := src["name"].(string); ok && n != "" {
			domainName = n
		} else if t, ok := src["type"].(string); ok && t != "" {
			domainName = t
		} else {
			domainName = "unnamed"
		}
	}

	var enrichPtr *bool
	if v, ok := src["enrich_context"].(bool); ok {
		enrichPtr = &v
	}
	loader, err := makeLoader(map[string]any{"loader": idx.loaderCfg}, enrichPtr)
	if err != nil {
		return nil, fmt.Errorf("AddSource: make loader: %w", err)
	}

	if idx.domainMap[namespaceID] == nil {
		if err := idx.store.RegisterNamespace(namespaceID, nil); err != nil {
			return nil, fmt.Errorf("AddSource: register namespace: %w", err)
		}
		idx.domainMap[namespaceID] = map[string]string{}
	}
	domainID, err := idx.getOrRegisterDomain(namespaceID, domainName, nil)
	if err != nil {
		return nil, fmt.Errorf("AddSource: register domain: %w", err)
	}

	chunks, err := ingestSource(src, loader)
	if err != nil {
		return nil, fmt.Errorf("AddSource: ingest: %w", err)
	}
	if len(chunks) == 0 {
		return nil, nil
	}

	texts := make([]string, 0, len(chunks))
	for _, c := range chunks {
		texts = append(texts, c.Content)
	}
	batchSize := 256
	if v, ok := idx.embedCfg["batch_size"].(int); ok && v > 0 {
		batchSize = v
	}
	emb, err := embedTexts(texts, idx.embedModel, batchSize)
	if err != nil {
		return nil, fmt.Errorf("AddSource: embed: %w", err)
	}
	if err := idx.store.AddDocument(chunks, emb, namespaceID, domainID); err != nil {
		return nil, fmt.Errorf("AddSource: store: %w", err)
	}
	if err := idx.store.Vector.RebuildFTSIndex(); err != nil {
		return nil, fmt.Errorf("AddSource: rebuild FTS: %w", err)
	}
	idx.invalidateSearch()

	if rebuild {
		dbPath, err := idx.store.Vector.DBPath()
		if err != nil {
			return nil, fmt.Errorf("AddSource: get db path: %w", err)
		}
		return BuildNamespaceAsync(namespaceID, dbPath, idx.embedModel, BuildNamespaceOptions{
			OnProgress:            cbs.OnProgress,
			OnComplete:            cbs.OnComplete,
			OnError:               cbs.OnError,
			Force:                 true,
			RunNER:                boolFromMap(idx.indexCfg, "ner", true),
			RunCommunity:          boolFromMap(idx.indexCfg, "community", true),
			SpacyModel:            stringFromMap(idx.indexCfg, "spacy_model", "en_core_web_sm"),
			CommunityAlpha:        float64FromMap(idx.indexCfg, "community_alpha", 0.2),
			CommunitySimThreshold: float64FromMap(idx.indexCfg, "community_sim_threshold", 0.6),
		})
	}
	return nil, nil
}

func run(dbPath string, namespaceID string, force bool,
	store *Store,
	onComplete func(int),
	onProgress func(string, int, int),
	indexer *Indexer,
) error {
	defer store.Close()

	if !force && store.NamespaceCacheValid(namespaceID) {
		count, err := store.Vector.CountEmbeddings(namespaceID)
		if err != nil {
			return fmt.Errorf("count embeddings: %w", err)
		}
		onComplete(count)
		return nil
	}

	sources, err := store.Vector.QuerySources(namespaceID)
	if err != nil {
		return fmt.Errorf("query sources: %w", err)
	}

	totalChunks := 0
	for _, src := range sources {
		var config map[string]interface{}
		if len(src.ConfigJSON) > 0 {
			if jsonErr := json.Unmarshal([]byte(src.ConfigJSON), &config); jsonErr != nil {
				return fmt.Errorf("parse config json for source %s: %w", src.SourceID, jsonErr)
			}
		} else {
			config = map[string]interface{}{}
		}
		config["source_id"] = src.SourceID
		config["type"] = src.SType
		config["uri"] = src.URI
		config["domain_id"] = src.DomainID
		config["namespace"] = namespaceID
		n, indexErr := indexer.IndexSource(config)
		if indexErr != nil {
			return fmt.Errorf("index source %s: %w", src.SourceID, indexErr)
		}
		totalChunks += n
	}
	return nil
}

func runNERPhase(
	runNER bool,
	store *Store,
	spacyModel string,
	namespaceID string,
	onProgress func(string, int, int),
	onError func(string, error),
) error {
	if runNER {
		onProgress("ner", 0, 1)
		if err := BuildNER(store, spacyModel, namespaceID); err != nil {
			onError("ner", err)
			return fmt.Errorf("ner phase: %w", err)
		}
		store.MarkNamespaceBuilt(namespaceID, "ner")
		onProgress("ner", 1, 1)
	}
	return nil
}

func runCommunityPhase(
	runCommunity bool,
	dbPath string,
	embedModel string,
	namespaceID string,
	alpha float64,
	simThreshold float64,
	force bool,
	store *Store,
	onProgress func(string, int, int),
	onError func(string, error),
) error {
	if runCommunity {
		onProgress("community", 0, 1)
		if err := BuildCommunity(dbPath, embedModel, namespaceID, alpha, simThreshold, force); err != nil {
			onError("community", err)
			return fmt.Errorf("community phase: %w", err)
		}
		store.MarkNamespaceBuilt(namespaceID, "community")
		onProgress("community", 1, 1)
	}
	return nil
}

Transform the `DocumentLoader._find_transport` and `DocumentLoader._find_extractor` methods from loader.py into Go 1.22, applying R01 (pointer-receiver methods), R02 (raise ValueError → return nil, error), R10 (for transport in self._transport_registry → range), R11 (if transport.can_handle → explicit bool result).

def _find_transport(self, uri: str):
        for transport in self._transport_registry:
            if transport.can_handle(uri):
                return transport
        raise ValueError(f"No transport found for URI: {uri!r}")

    def _find_extractor(self, doc_type: str):
        for extractor in self._extra_extractors:
            if extractor.can_handle(doc_type):
                return extractor
        return detect_extractor(doc_type)

// findTransport iterates the registry and returns the first transport that can handle uri.
func (dl *DocumentLoader) findTransport(uri string) (Transport, error) {
	for _, transport := range dl.transportRegistry {
		if transport.CanHandle(uri) {
			return transport, nil
		}
	}
	return nil, fmt.Errorf("no transport found for URI: %q", uri)
}

// findExtractor checks extra extractors first, then falls back to DetectExtractor.
func (dl *DocumentLoader) findExtractor(docType string) (Extractor, error) {
	for _, extractor := range dl.extraExtractors {
		if extractor.CanHandle(docType) {
			return extractor, nil
		}
	}
	return DetectExtractor(docType)
}

var structuredExtensions = map[string]struct{}{
	".parquet": {}, ".arrow": {}, ".feather": {},
	".csv": {}, ".json": {}, ".jsonl": {}, ".ndjson": {},
}

// Load fetches, extracts, chunks, and enriches the document at uri.
// name is optional; pass empty string to derive from the URI path stem.
func (dl *DocumentLoader) Load(uri string, name string) ([]DocumentChunk, error) {
	ext := strings.ToLower(filepath.Ext(uri))
	if _, ok := structuredExtensions[ext]; ok {
		return dl.LoadStructuredFile(uri, name)
	}

	transport, err := dl.findTransport(uri)
	if err != nil {
		return nil, fmt.Errorf("load %s: %w", uri, err)
	}
	result, err := transport.Fetch(uri)
	if err != nil {
		return nil, fmt.Errorf("fetch %s: %w", uri, err)
	}

	sourcePath := result.SourcePath
	if sourcePath == "" {
		sourcePath = uri
	}
	docType, err := DetectTypeFromSource(sourcePath, result.DetectedMime)
	if err != nil {
		return nil, fmt.Errorf("detect type: %w", err)
	}
	extractor, err := dl.findExtractor(docType)
	if err != nil {
		return nil, fmt.Errorf("find extractor: %w", err)
	}
	text, err := extractor.Extract(result.Data, sourcePath)
	if err != nil {
		return nil, fmt.Errorf("extract text: %w", err)
	}

	docName := name
	if docName == "" {
		docName = strings.TrimSuffix(filepath.Base(sourcePath), filepath.Ext(sourcePath))
	}

	chunks, err := ChunkDocument(docName, text, dl.MinChunkSize, dl.MaxChunkSize, dl.OverflowMargin, dl.EnrichContext, dl.IncludeDocName)
	if err != nil {
		return nil, fmt.Errorf("chunk document: %w", err)
	}
	chunks, err = extractor.Annotate(chunks, result.Data, sourcePath)
	if err != nil {
		return nil, fmt.Errorf("annotate chunks: %w", err)
	}
	return dl.enrich(chunks)
}

// LoadBytes skips fetch and extracts from raw bytes.
// Pass docType="auto" to detect type from sourcePath or name.
// Note: sourcePath is optional; pass empty string when not available.
func (dl *DocumentLoader) LoadBytes(data []byte, name string, docType string, sourcePath string) ([]DocumentChunk, error) {
	var extractor Extractor
	var err error
	if docType == "auto" {
		hint := sourcePath
		if hint == "" {
			hint = name
		}
		resolvedType, typeErr := DetectTypeFromSource(hint, "")
		if typeErr != nil {
			return nil, fmt.Errorf("detect type: %w", typeErr)
		}
		extractor, err = dl.findExtractor(resolvedType)
	} else {
		extractor, err = dl.findExtractorRaw(docType)
	}
	if err != nil {
		return nil, fmt.Errorf("find extractor: %w", err)
	}

	text, err := extractor.Extract(data, sourcePath)
	if err != nil {
		return nil, fmt.Errorf("extract text: %w", err)
	}

	chunks, err := ChunkDocument(name, text, dl.MinChunkSize, dl.MaxChunkSize, dl.OverflowMargin, dl.EnrichContext, dl.IncludeDocName)
	if err != nil {
		return nil, fmt.Errorf("chunk document: %w", err)
	}
	chunks, err = extractor.Annotate(chunks, data, sourcePath)
	if err != nil {
		return nil, fmt.Errorf("annotate chunks: %w", err)
	}
	return dl.enrich(chunks)
}

// CassandraOptions holds optional Cassandra connection parameters.
// Note: Port uses *int so callers can distinguish explicit 0 from default 9042.
type CassandraOptions struct {
	Port     *int   // default 9042
	Keyspace string
	Username string
	Password string
	LocalDC  string
}

// LoadFromCassandra executes CQL queries against Cassandra and returns document chunks.
func (dl *DocumentLoader) LoadFromCassandra(
	contactPoints []string,
	datasetQueries []NameSQLPair,
	opts CassandraOptions,
) ([]DocumentChunk, error) {
	port := 9042
	if opts.Port != nil {
		port = *opts.Port
	}

	qMap := make(map[string]string, len(datasetQueries))
	for _, p := range datasetQueries {
		qMap[p.Name] = p.SQL
	}
	crawler := NewCassandraCrawler(contactPoints, port, opts.Keyspace, opts.Username, opts.Password, qMap, opts.LocalDC)
	if err := crawler.Crawl(); err != nil {
		return nil, fmt.Errorf("cassandra crawl: %w", err)
	}

	extractor := NewCsvExtractor()
	provenance := CassandraProvenance(contactPoints, port, opts.Keyspace)

	var allChunks []DocumentChunk
	for _, pair := range datasetQueries {
		uri := fmt.Sprintf("cassandra://%s/query/%s", contactPoints[0], pair.Name)
		result, ok := crawler.Cache()[uri]
		if !ok {
			continue
		}
		text, err := extractor.Extract(result.Data, pair.Name)
		if err != nil {
			return nil, fmt.Errorf("extract %s: %w", pair.Name, err)
		}
		chunks, err := ChunkDocument(pair.Name, text, dl.MinChunkSize, dl.MaxChunkSize, dl.OverflowMargin, dl.EnrichContext, dl.IncludeDocName)
		if err != nil {
			return nil, fmt.Errorf("chunk %s: %w", pair.Name, err)
		}
		chunks, err = extractor.Annotate(chunks, result.Data, pair.Name)
		if err != nil {
			return nil, fmt.Errorf("annotate %s: %w", pair.Name, err)
		}
		for i := range chunks {
			if chunks[i].SourceDetail == nil {
				chunks[i].SourceDetail = map[string]interface{}{}
			}
			chunks[i].SourceDetail["query"] = pair.SQL
			for k, v := range provenance {
				chunks[i].SourceDetail[k] = v
			}
		}
		enriched, enrichErr := dl.enrich(chunks)
		if enrichErr != nil {
			return nil, fmt.Errorf("enrich %s: %w", pair.Name, enrichErr)
		}
		allChunks = append(allChunks, enriched...)
	}
	return allChunks, nil
}

// LoadIMAP fetches and indexes email messages from an IMAP mailbox.
// limit is optional; pass nil to fetch all available messages.
func (dl *DocumentLoader) LoadIMAP(uri string, includeAttachments bool, limit *int) ([]DocumentChunk, error) {
	transport := NewImapTransport()
	extractor := NewEmailExtractor(includeAttachments)

	messages, err := transport.FetchMessages(uri, limit)
	if err != nil {
		return nil, fmt.Errorf("imap fetch messages: %w", err)
	}

	var allChunks []DocumentChunk
	for _, result := range messages {
		text, extractErr := extractor.Extract(result.Data, result.SourcePath)
		if extractErr != nil {
			log.Printf("load_imap: skipping message %s: %v", result.SourcePath, extractErr)
			continue
		}
		if len(strings.TrimSpace(text)) == 0 {
			continue
		}
		name := result.SourcePath
		if name == "" {
			name = "email"
		}
		chunks, chunkErr := ChunkDocument(name, text, dl.MinChunkSize, dl.MaxChunkSize, dl.OverflowMargin, dl.EnrichContext, dl.IncludeDocName)
		if chunkErr != nil {
			log.Printf("load_imap: chunk error for %s: %v", name, chunkErr)
			continue
		}
		enriched, enrichErr := dl.enrich(chunks)
		if enrichErr != nil {
			log.Printf("load_imap: enrich error for %s: %v", name, enrichErr)
			continue
		}
		allChunks = append(allChunks, enriched...)
	}
	return allChunks, nil
}

