def load_structured_file(
        self, path_or_uri: str, name: str | None = None
    ) -> list[DocumentChunk]:
        import os
        ext = os.path.splitext(path_or_uri)[1].lower()
        doc_name = name or os.path.splitext(os.path.basename(path_or_uri))[0]

        _supported = {".parquet", ".arrow", ".feather", ".csv", ".json", ".jsonl", ".ndjson"}
        if ext not in _supported:
            raise ValueError(
                f"Unsupported structured file extension: {ext!r}. "
                "Supported: .parquet, .arrow, .feather, .csv, .json, .jsonl, .ndjson"
            )

        transport = self._find_transport(path_or_uri)
        result = transport.fetch(path_or_uri)
        data = result.data

        if ext in (".parquet", ".arrow", ".feather"):
            table_meta = infer_parquet(data, ext, doc_name)
        elif ext == ".csv":
            table_meta = infer_csv(data, doc_name)
        elif ext == ".json":
            table_meta = infer_json(data, doc_name)
        else:  # .jsonl / .ndjson
            table_meta = infer_jsonl(data, doc_name)

        return self.load_schema([table_meta])

var supportedStructuredExts = map[string]struct{}{
	".parquet": {}, ".arrow": {}, ".feather": {},
	".csv": {}, ".json": {}, ".jsonl": {}, ".ndjson": {},
}

// LoadStructuredFile infers schema from a structured file and returns N+1 DocumentChunks.
// name is optional; pass empty string to derive from the file stem.
func (dl *DocumentLoader) LoadStructuredFile(pathOrURI string, name string) ([]DocumentChunk, error) {
	ext := strings.ToLower(filepath.Ext(pathOrURI))
	docName := name
	if docName == "" {
		base := filepath.Base(pathOrURI)
		docName = strings.TrimSuffix(base, filepath.Ext(base))
	}

	if _, ok := supportedStructuredExts[ext]; !ok {
		return nil, fmt.Errorf("unsupported structured file extension: %q; supported: .parquet, .arrow, .feather, .csv, .json, .jsonl, .ndjson", ext)
	}

	transport, err := dl.findTransport(pathOrURI)
	if err != nil {
		return nil, fmt.Errorf("find transport: %w", err)
	}
	result, err := transport.Fetch(pathOrURI)
	if err != nil {
		return nil, fmt.Errorf("fetch: %w", err)
	}
	data := result.Data

	var tableMeta TableMeta
	switch ext {
	case ".parquet", ".arrow", ".feather":
		tableMeta, err = InferParquet(data, ext, docName)
	case ".csv":
		tableMeta, err = InferCSV(data, docName)
	case ".json":
		tableMeta, err = InferJSON(data, docName)
	default: // .jsonl / .ndjson
		tableMeta, err = InferJSONL(data, docName)
	}
	if err != nil {
		return nil, fmt.Errorf("infer schema: %w", err)
	}
	return dl.LoadSchema([]TableMeta{tableMeta})
}

