import (
	"database/sql"
	"fmt"
	"log/slog"
	"time"
)

// workerLoop runs the main poll-and-process loop until ctx is cancelled.
func workerLoop(
	log *slog.Logger,
	queueDB *sql.DB,
	backend Backend,
	workerID string,
	embedModel string,
	batchSize int,
	runNER bool,
	spacyModel string,
	idleSleep time.Duration,
) error {
	for {
		// Check pause flag
		var pausedVal string
		err := queueDB.QueryRow("SELECT value FROM control WHERE key = 'workers_paused'").Scan(&pausedVal)
		if err != nil && err != sql.ErrNoRows {
			return fmt.Errorf("workerLoop: query pause flag: %w", err)
		}
		if pausedVal == "1" {
			time.Sleep(idleSleep)
			continue
		}

		// Claim next pending item (SKIP LOCKED prevents double-assignment)
		tx, err := queueDB.Begin()
		if err != nil {
			return fmt.Errorf("workerLoop: begin tx: %w", err)
		}
		var jobID int64
		var sourceURI, namespace string
		err = tx.QueryRow(`
			UPDATE ingest_queue
			SET status = 'processing', worker_id = $1, leased_at = now()
			WHERE id = (
				SELECT id FROM ingest_queue
				WHERE status = 'pending'
				LIMIT 1
				FOR UPDATE SKIP LOCKED
			)
			RETURNING id, source_uri, namespace`,
			workerID,
		).Scan(&jobID, &sourceURI, &namespace)
		if err == sql.ErrNoRows {
			_ = tx.Rollback()
			time.Sleep(idleSleep)
			continue
		}
		if err != nil {
			_ = tx.Rollback()
			return fmt.Errorf("workerLoop: claim job: %w", err)
		}
		if err := tx.Commit(); err != nil {
			return fmt.Errorf("workerLoop: commit claim: %w", err)
		}

		log.Info("Worker processing job", "worker_id", workerID, "job_id", jobID, "source_uri", sourceURI)

		processErr := processQueueJob(log, backend, sourceURI, namespace, embedModel, batchSize, runNER, spacyModel)
		newStatus := "done"
		if processErr != nil {
			log.Error("Job failed", "job_id", jobID, "error", processErr)
			newStatus = "failed"
		}
		if _, err := queueDB.Exec("UPDATE ingest_queue SET status = $1 WHERE id = $2", newStatus, jobID); err != nil {
			return fmt.Errorf("workerLoop: update job status: %w", err)
		}
	}
}

