def infer_json(data: bytes, name: str) -> TableMeta:
    import json

    try:
        obj = json.loads(data)
    except json.JSONDecodeError as exc:
        raise ValueError(f"Cannot parse JSON for {name!r}: {exc}") from exc

    if isinstance(obj, list):
        key_types: dict[str, str] = {}
        for item in obj[:100]:
            if isinstance(item, dict):
                for k, v in item.items():
                    if k not in key_types:
                        key_types[k] = _python_type_to_str(v)
        columns = [ColumnMeta(name=k, data_type=v) for k, v in key_types.items()]
        return TableMeta(name=name, columns=columns, row_count=len(obj))

    if isinstance(obj, dict):
        columns = [
            ColumnMeta(name=k, data_type=_python_type_to_str(v)) for k, v in list(obj.items())[:100]
        ]
        return TableMeta(name=name, columns=columns, row_count=1)

    return TableMeta(name=name)

import (
	"encoding/json"
	"fmt"
)

func inferJSON(data []byte, name string) (*TableMeta, error) {
	var raw interface{}
	if err := json.Unmarshal(data, &raw); err != nil {
		return nil, fmt.Errorf("inferJSON: cannot parse JSON for %q: %w", name, err)
	}

	switch obj := raw.(type) {
	case []interface{}:
		keyTypes := make(map[string]string)
		keyOrder := make([]string, 0)
		limit := 100
		if len(obj) < limit {
			limit = len(obj)
		}
		for i := 0; i < limit; i++ {
			item := obj[i]
			if m, ok := item.(map[string]interface{}); ok {
				for k, v := range m {
					if _, exists := keyTypes[k]; !exists {
						keyTypes[k] = pythonTypeToStr(v)
						keyOrder = append(keyOrder, k)
					}
				}
			}
		}
		columns := make([]ColumnMeta, 0, len(keyOrder))
		for _, k := range keyOrder {
			columns = append(columns, ColumnMeta{Name: k, DataType: keyTypes[k]})
		}
		rowCount := len(obj)
		return &TableMeta{Name: name, Columns: columns, RowCount: &rowCount}, nil

	case map[string]interface{}:
		type kv struct{ k string; v interface{} }
		pairs := make([]kv, 0, len(obj))
		for k, v := range obj {
			pairs = append(pairs, kv{k, v})
			if len(pairs) == 100 {
				break
			}
		}
		columns := make([]ColumnMeta, 0, len(pairs))
		for _, p := range pairs {
			columns = append(columns, ColumnMeta{Name: p.k, DataType: pythonTypeToStr(p.v)})
		}
		rowCount := 1
		return &TableMeta{Name: name, Columns: columns, RowCount: &rowCount}, nil
	}

	return &TableMeta{Name: name}, nil
}

