	"bufio"
	"bytes"
	"encoding/json"
	"fmt"
)

func inferJSONL(data []byte, name string) (*TableMeta, error) {
	keyTypes := make(map[string]string)
	keyOrder := make([]string, 0)
	count := 0
	total := 0
	parseFailures := 0

	scanner := bufio.NewScanner(bytes.NewReader(data))
	for scanner.Scan() {
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		total++
		if count < 100 {
			var obj map[string]interface{}
			if err := json.Unmarshal(line, &obj); err != nil {
				parseFailures++
			} else {
				for k, v := range obj {
					if _, exists := keyTypes[k]; !exists {
						keyTypes[k] = pythonTypeToStr(v)
						keyOrder = append(keyOrder, k)
					}
				}
				count++
			}
		}
	}
	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("inferJSONL: scanner: %w", err)
	}

	if total > 0 && count == 0 {
		return nil, fmt.Errorf("inferJSONL: all %d non-empty lines in %q failed JSON parsing", parseFailures, name)
	}

	columns := make([]ColumnMeta, 0, len(keyOrder))
	for _, k := range keyOrder {
		columns = append(columns, ColumnMeta{Name: k, DataType: keyTypes[k]})
	}
	return &TableMeta{Name: name, Columns: columns, RowCount: &total}, nil
}

