}

// edgeKey is used as a dedup set key.
type edgeKey struct{ a, b int }

// loadEntityEdges builds cross-document entity bridge edges from chunk_entities.
func loadEntityEdges(db *sql.DB, rows []EmbeddingRow) ([]EdgeTuple, error) {
	ceRows, err := db.Query("SELECT entity_id, chunk_id FROM chunk_entities WHERE frequency > 0")
	if err != nil {
		return nil, fmt.Errorf("loadEntityEdges: query: %w", err)
	}
	defer ceRows.Close()

	type ceRow struct{ entityID, chunkID string }
	var fetched []ceRow
	for ceRows.Next() {
		var r ceRow
		if err := ceRows.Scan(&r.entityID, &r.chunkID); err != nil {
			return nil, fmt.Errorf("loadEntityEdges: scan: %w", err)
		}
		fetched = append(fetched, r)
	}
	if err := ceRows.Err(); err != nil {
		return nil, fmt.Errorf("loadEntityEdges: rows: %w", err)
	}
	if len(fetched) == 0 {
		return nil, nil
	}

	// Build chunk_id -> index map
	chunkIDsList := make([]string, len(rows))
	for i, r := range rows {
		chunkIDsList[i] = r.ChunkID
	}
	idToIdx := make(map[string]int, len(chunkIDsList))
	for i, cid := range chunkIDsList {
		idToIdx[cid] = i
	}

	entityToChunks := make(map[string][]int)
	for _, r := range fetched {
		if idx, ok := idToIdx[r.chunkID]; ok {
			entityToChunks[r.entityID] = append(entityToChunks[r.entityID], idx)
		}
	}

	var extraEdges []EdgeTuple
	seen := make(map[edgeKey]struct{})
	for _, idxs := range entityToChunks {
		if len(idxs) < 2 {
			continue
		}
		for a := 0; a < len(idxs); a++ {
			for b := a + 1; b < len(idxs); b++ {
				ia, ib := idxs[a], idxs[b]
				// rsplit("_", 2)[0] equivalent: last two "_"-separated parts stripped
				docA := strings.Join(strings.Split(chunkIDsList[ia], "_")[:len(strings.Split(chunkIDsList[ia], "_"))-2], "_")
				docB := strings.Join(strings.Split(chunkIDsList[ib], "_")[:len(strings.Split(chunkIDsList[ib], "_"))-2], "_")
				if docA != docB {
					k := edgeKey{a: min(ia, ib), b: max(ia, ib)}
					if _, exists := seen[k]; !exists {
						seen[k] = struct{}{}
						extraEdges = append(extraEdges, EdgeTuple{A: ia, B: ib, Weight: 1.0})
					}
				}
			}
		}
	}
	return extraEdges, nil
}

