class CommunityIndexBuilder:
    def __init__(self, initial: CommunityIndex | None = None) -> None:
        self.ref: VersionedRef[CommunityIndex] = VersionedRef(initial)
        self._thread: threading.Thread | None = None

    def build(
        self,
        chunk_ids: list[str],
        content_vecs: np.ndarray,
        *,
        on_complete: Callable[[CommunityIndex], None] | None = None,
        **kwargs,
    ) -> None:
        def _run() -> None:
            try:
                idx = CommunityIndex.build(chunk_ids, content_vecs, **kwargs)
                new_version = self.ref.update(idx)
                logger.debug("CommunityIndex version %d ready (%d levels, %d chunks)",
                             new_version, idx.level_count(), idx.chunk_count())
                if on_complete is not None:
                    on_complete(idx)
            except Exception:
                logger.exception("CommunityIndexBuilder background build failed")

        t = threading.Thread(target=_run, daemon=True, name="community-index-builder")
        self._thread = t
        t.start()

// CommunityIndexBuilder builds a CommunityIndex in a background goroutine and atomically hot-swaps when done.
type CommunityIndexBuilder struct {
	Ref    *VersionedRef
	wg     sync.WaitGroup
	logger *slog.Logger
}

// NewCommunityIndexBuilder returns a CommunityIndexBuilder with an optional initial index.
func NewCommunityIndexBuilder(initial *CommunityIndex) *CommunityIndexBuilder {
	return &CommunityIndexBuilder{
		Ref:    NewVersionedRef(initial),
		logger: slog.Default(),
	}
}

// BuildParams holds parameters forwarded to the index build.
type BuildParams struct {
	ChunkIDs     []string
	ContentVecs  [][]float32
	ChunkTexts   []string
	HeadingVecs  [][]float32
	Alpha        float64
	SimThreshold float64
	ExtraEdges   []EdgeTuple
}

// Build starts a background build. Hot-swaps the Ref when complete.
// onComplete is called on the build goroutine with the new index; may be nil.
func (b *CommunityIndexBuilder) Build(params BuildParams, onComplete func(*CommunityIndex)) {
	b.wg.Add(1)
	go func() {
		defer b.wg.Done()
		idx, err := NewCommunityIndex(params)
		if err != nil {
			b.logger.Error("CommunityIndexBuilder background build failed", "err", err)
			return
		}
		newVersion := b.Ref.Update(idx)
		b.logger.Debug("CommunityIndex ready",
			"version", newVersion,
			"levels", idx.LevelCount(),
			"chunks", idx.ChunkCount(),
		)
		if onComplete != nil {
			onComplete(idx)
		}
	}()
}

