def _resolve_levels(
    resolutions: list[float] | None,
    n_levels: int,
    resolution_min: float,
    resolution_max: float,
) -> list[float]:
    """Return the ordered list of resolution values for community detection."""
    if resolutions is not None:
        return list(resolutions)
    if n_levels == 1:
        return [(resolution_min + resolution_max) / 2]
    return list(np.logspace(
        np.log10(resolution_min),
        np.log10(resolution_max),
        num=n_levels,
    ).tolist())

// resolveLevels returns the ordered list of resolution values for community detection.
// If resolutions is non-nil it is returned as-is. Otherwise n_levels values are
// log-spaced between resolutionMin and resolutionMax.
func resolveLevels(resolutions []float64, nLevels int, resolutionMin, resolutionMax float64) []float64 {
	if resolutions != nil {
		out := make([]float64, len(resolutions))
		copy(out, resolutions)
		return out
	}
	if nLevels == 1 {
		return []float64{(resolutionMin + resolutionMax) / 2}
	}
	// Log-space between resolutionMin and resolutionMax
	logMin := math.Log10(resolutionMin)
	logMax := math.Log10(resolutionMax)
	step := (logMax - logMin) / float64(nLevels-1)
	result := make([]float64, nLevels)
	for i := 0; i < nLevels; i++ {
		result[i] = math.Pow(10, logMin+step*float64(i))
	}
	return result
}

