def _run_louvain(
    n: int,
    edges: list[tuple[int, int, float]],
    seed: int | None,
) -> dict[int, int]:
    """Run Louvain (or connected-components fallback) and return partition."""
    import networkx as nx

    G = nx.Graph()
    G.add_nodes_from(range(n))
    for gi, j, w in edges:
        G.add_edge(gi, j, weight=w)

    try:
        import community as louvain_mod
        return louvain_mod.best_partition(
            G, random_state=seed if seed is not None else 42
        )
    except ImportError:
        partition: dict[int, int] = {}
        for cid, component in enumerate(nx.connected_components(G)):
            for node in component:
                partition[node] = cid
        return partition

// LouvainPartitioner is an interface for community-detection algorithm implementations.
type LouvainPartitioner interface {
	BestPartition(n int, edges []EdgeTuple, seed int) (map[int]int, error)
}

// runLouvain runs a Louvain partition or falls back to connected-components.
func runLouvain(partitioner LouvainPartitioner, n int, edges []EdgeTuple, seed *int) (map[int]int, error) {
	if partitioner != nil {
		s := 42
		if seed != nil {
			s = *seed
		}
		partition, err := partitioner.BestPartition(n, edges, s)
		if err != nil {
			return nil, fmt.Errorf("runLouvain: best partition: %w", err)
		}
		return partition, nil
	}
	// Fallback: connected-components (union-find)
	parent := make([]int, n)
	for i := range parent {
		parent[i] = i
	}
	var find func(int) int
	find = func(x int) int {
		if parent[x] != x {
			parent[x] = find(parent[x])
		}
		return parent[x]
	}
	for _, e := range edges {
		ra, rb := find(e.A), find(e.B)
		if ra != rb {
			parent[ra] = rb
		}
	}
	// Assign community IDs by canonical root
	rootToID := make(map[int]int)
	partition := make(map[int]int, n)
	nextID := 0
	for i := 0; i < n; i++ {
		root := find(i)
		if _, ok := rootToID[root]; !ok {
			rootToID[root] = nextID
			nextID++
		}
		partition[i] = rootToID[root]
	}
	return partition, nil
}

Transform the Python function `_run_partition` from _index.py into Go 1.22, applying R03 (error propagation), R05 (dict → map[int]int), R06 (None → nil), R10 (for range), and R11 (truthiness → explicit len/nil checks).

def _run_partition(
    n: int,
    edges: list[tuple[int, int, float]],
    algorithm: str,
    resolution: float,
    n_iterations: int,
    seed: int | None,
) -> dict[int, int]:
    """Dispatch to leiden or louvain; fall back to louvain if leiden unavailable."""
    partition: dict[int, int] | None = None

    if algorithm == "leiden":
        partition = _run_leiden(n, edges, resolution, n_iterations, seed)

    if partition is None:
        partition = _run_louvain(n, edges, seed)

    if not partition:
        partition = {i: i for i in range(n)}

    return partition

// runPartition dispatches to Leiden or Louvain; falls back to Louvain if Leiden is unavailable.
// Falls back further to identity partition if both return empty.
func runPartition(
	leidenPartitioner LeidenPartitioner,
	louvainPartitioner LouvainPartitioner,
	n int,
	edges []EdgeTuple,
	algorithm string,
	resolution float64,
	nIterations int,
	seed *int,
) (map[int]int, error) {
	var partition map[int]int

	if algorithm == "leiden" {
		var err error
		partition, err = runLeiden(leidenPartitioner, n, edges, resolution, nIterations, seed)
		if err != nil {
			return nil, fmt.Errorf("runPartition: leiden: %w", err)
		}
	}

	if partition == nil {
		var err error
		partition, err = runLouvain(louvainPartitioner, n, edges, seed)
		if err != nil {
			return nil, fmt.Errorf("runPartition: louvain: %w", err)
		}
	}

	if len(partition) == 0 {
		partition = make(map[int]int, n)
		for i := 0; i < n; i++ {
			partition[i] = i
		}
	}
	return partition, nil
}

// assignLabels populates ld.CommunityToLabel in-place.
// db may be nil; chunkTexts may be nil.
func assignLabels(
	ld *LevelData,
	communityMembers map[int][]int,
	chunkIDs []string,
	chunkTexts []string,
	labelStrategy string,
	db *sql.DB,
	topLabelTerms int,
	labelSynonymThreshold float64,
) error {
	if labelStrategy == "ner_embedding" && db != nil {
		for cid, indices := range communityMembers {
			var cids []string
			for _, i := range indices {
				if i < len(chunkIDs) {
					cids = append(cids, chunkIDs[i])
				}
			}
			label, err := nerEmbeddingLabels(db, cids, topLabelTerms, labelSynonymThreshold)
			if err != nil {
				return fmt.Errorf("assignLabels: ner_embedding cid %d: %w", cid, err)
			}
			if len(label) == 0 && len(chunkTexts) > 0 {
				var texts []string
				for _, i := range indices {
					if i < len(chunkTexts) {
						texts = append(texts, chunkTexts[i])
					}
				}
				label = topTerms(texts, topLabelTerms)
			}
			ld.CommunityToLabel[cid] = label
		}
	} else if len(chunkTexts) > 0 {
		for cid, indices := range communityMembers {
			var texts []string
			for _, i := range indices {
				if i < len(chunkTexts) {
					texts = append(texts, chunkTexts[i])
				}
			}
			ld.CommunityToLabel[cid] = topTerms(texts, topLabelTerms)
		}
	}
	return nil
}

// computeCoherence populates ld.CommunityToCoherence in-place.
func computeCoherence(ld *LevelData, communityMembers map[int][]int, vecs [][]float32) {
	for cid, indices := range communityMembers {
		if len(indices) < 2 {
			ld.CommunityToCoherence[cid] = 0.0
			continue
		}
		// Compute upper-triangle cosine similarities
		var sum float64
		var count int
		for a := 0; a < len(indices); a++ {
			for b := a + 1; b < len(indices); b++ {
				ia, ib := indices[a], indices[b]
				var sim float64
				for d := range vecs[ia] {
					sim += float64(vecs[ia][d]) * float64(vecs[ib][d])
				}
				sum += sim
				count++
			}
		}
		if count > 0 {
			ld.CommunityToCoherence[cid] = sum / float64(count)
		} else {
			ld.CommunityToCoherence[cid] = 0.0
		}
	}
}

// LevelData holds per-level community assignments, labels, and coherence scores.
type LevelData struct {
	Resolution            float64
	ChunkToCommunity      map[string]int
	CommunityToLabel      map[int]string
	CommunityToChunks     map[int][]string
	CommunityToCoherence  map[int]float64
}

// NewLevelData constructs an empty LevelData for the given resolution.
func NewLevelData(resolution float64) *LevelData {
	return &LevelData{
		Resolution:           resolution,
		ChunkToCommunity:     make(map[string]int),
		CommunityToLabel:     make(map[int]string),
		CommunityToChunks:    make(map[int][]string),
		CommunityToCoherence: make(map[int]float64),
	}
}

// buildLevelData constructs a LevelData from a partition map for one resolution level.
func buildLevelData(
	resolution float64,
	partition map[int]int,
	chunkIDs []string,
	chunkTexts []string,
	vecs [][]float32,
	labelStrategy string,
	db *sql.DB,
	topLabelTerms int,
	labelSynonymThreshold float64,
) (*LevelData, error) {
	ld := NewLevelData(resolution)
	communityMembers := make(map[int][]int)

	for idx, cid := range partition {
		ld.ChunkToCommunity[chunkIDs[idx]] = cid
		ld.CommunityToChunks[cid] = append(ld.CommunityToChunks[cid], chunkIDs[idx])
		communityMembers[cid] = append(communityMembers[cid], idx)
	}

	if err := assignLabels(ld, communityMembers, chunkIDs, chunkTexts, labelStrategy, db, topLabelTerms, labelSynonymThreshold); err != nil {
		return nil, fmt.Errorf("buildLevelData: %w", err)
	}
	computeCoherence(ld, communityMembers, vecs)
	return ld, nil
}

Transform the Python function `_load_multilevel_schema` from _index.py into Go 1.22, applying R01 (class → struct), R03 (error return), R05 (dict → map), R10 (for loops → range), and R11 (truthiness → explicit nil/len checks).

def _load_multilevel_schema(
    con,
    instance: CommunityIndex,
) -> None:
    """Populate instance._levels from the multi-level chunk_communities schema."""
    chunk_rows = con.execute(
        "SELECT chunk_id, level, community_id FROM chunk_communities ORDER BY level"
    ).fetchall()
    community_rows = con.execute(
        "SELECT community_id, level, topic_label, coherence, resolution FROM communities ORDER BY level"
    ).fetchall()
    con.close()

    levels_by_idx: dict[int, _LevelData] = {}
    for chunk_id, level_idx, cid in chunk_rows:
        if level_idx not in levels_by_idx:
            levels_by_idx[level_idx] = _LevelData(1.0)
        ld = levels_by_idx[level_idx]
        ld.chunk_to_community[chunk_id] = cid
        ld.community_to_chunks[cid].append(chunk_id)

    for cid, level_idx, label, coherence, resolution in community_rows:
        if level_idx not in levels_by_idx:
            levels_by_idx[level_idx] = _LevelData(resolution or 1.0)
        ld = levels_by_idx[level_idx]
        ld.resolution = resolution or 1.0
        ld.community_to_label[cid] = label or ""
        ld.community_to_coherence[cid] = coherence or 0.0

    for level_idx in sorted(levels_by_idx.keys()):
        instance._levels.append(levels_by_idx[level_idx])

// loadMultilevelSchema populates ci.Levels from the multi-level chunk_communities schema.
func loadMultilevelSchema(db *sql.DB, ci *CommunityIndex) error {
	chunkRows, err := db.Query("SELECT chunk_id, level, community_id FROM chunk_communities ORDER BY level")
	if err != nil {
		return fmt.Errorf("loadMultilevelSchema: query chunk_communities: %w", err)
	}
	defer chunkRows.Close()

	type chunkRow struct {
		chunkID  string
		levelIdx int
		cid      int
	}
	var cRows []chunkRow
	for chunkRows.Next() {
		var r chunkRow
		if err := chunkRows.Scan(&r.chunkID, &r.levelIdx, &r.cid); err != nil {
			return fmt.Errorf("loadMultilevelSchema: scan chunk_communities: %w", err)
		}
		cRows = append(cRows, r)
	}
	if err := chunkRows.Err(); err != nil {
		return fmt.Errorf("loadMultilevelSchema: chunk_communities rows: %w", err)
	}

	commRows, err := db.Query("SELECT community_id, level, topic_label, coherence, resolution FROM communities ORDER BY level")
	if err != nil {
		return fmt.Errorf("loadMultilevelSchema: query communities: %w", err)
	}
	defer commRows.Close()

	type commRow struct {
		cid        int
		levelIdx   int
		label      string
		coherence  float64
		resolution float64
	}
	var communityRows []commRow
	for commRows.Next() {
		var r commRow
		if err := commRows.Scan(&r.cid, &r.levelIdx, &r.label, &r.coherence, &r.resolution); err != nil {
			return fmt.Errorf("loadMultilevelSchema: scan communities: %w", err)
		}
		communityRows = append(communityRows, r)
	}
	if err := commRows.Err(); err != nil {
		return fmt.Errorf("loadMultilevelSchema: communities rows: %w", err)
	}

	levelsByIdx := make(map[int]*LevelData)
	for _, r := range cRows {
		if _, ok := levelsByIdx[r.levelIdx]; !ok {
			levelsByIdx[r.levelIdx] = NewLevelData(1.0)
		}
		ld := levelsByIdx[r.levelIdx]
		ld.ChunkToCommunity[r.chunkID] = r.cid
		ld.CommunityToChunks[r.cid] = append(ld.CommunityToChunks[r.cid], r.chunkID)
	}
	for _, r := range communityRows {
		resolution := r.resolution
		if resolution == 0 {
			resolution = 1.0
		}
		if _, ok := levelsByIdx[r.levelIdx]; !ok {
			levelsByIdx[r.levelIdx] = NewLevelData(resolution)
		}
		ld := levelsByIdx[r.levelIdx]
		ld.Resolution = resolution
		ld.CommunityToLabel[r.cid] = r.label
		ld.CommunityToCoherence[r.cid] = r.coherence
	}

	// Append levels in sorted order
	keys := make([]int, 0, len(levelsByIdx))
	for k := range levelsByIdx {
		keys = append(keys, k)
	}
	sort.Ints(keys)
	for _, k := range keys {
		ci.Levels = append(ci.Levels, levelsByIdx[k])
	}
	return nil
}

// legacyCommunityRow holds one row from the legacy communities table.
type legacyCommunityRow struct {
	cid       int
	label     string
	coherence float64
}

// fetchLegacyCommunityRows fetches community rows from legacy schema, with or without coherence column.
func fetchLegacyCommunityRows(db *sql.DB) ([]legacyCommunityRow, error) {
	rows, err := db.Query("SELECT community_id, topic_label, coherence FROM communities")
	if err != nil {
		// coherence column may be absent in very old schema — retry without it
		rows2, err2 := db.Query("SELECT community_id, topic_label FROM communities")
		if err2 != nil {
			return nil, fmt.Errorf("fetchLegacyCommunityRows: %w", err2)
		}
		defer rows2.Close()
		var result []legacyCommunityRow
		for rows2.Next() {
			var r legacyCommunityRow
			if err := rows2.Scan(&r.cid, &r.label); err != nil {
				return nil, fmt.Errorf("fetchLegacyCommunityRows: scan: %w", err)
			}
			result = append(result, r)
		}
		return result, rows2.Err()
	}
	defer rows.Close()
	var result []legacyCommunityRow
	for rows.Next() {
		var r legacyCommunityRow
		if err := rows.Scan(&r.cid, &r.label, &r.coherence); err != nil {
			return nil, fmt.Errorf("fetchLegacyCommunityRows: scan with coherence: %w", err)
		}
		result = append(result, r)
	}
	return result, rows.Err()
}

// loadLegacySchema populates ci.Levels from the legacy (no level column) schema.
func loadLegacySchema(db *sql.DB, ci *CommunityIndex) error {
	chunkRows, err := db.Query("SELECT chunk_id, community_id FROM chunk_communities")
	if err != nil {
		return fmt.Errorf("loadLegacySchema: query chunk_communities: %w", err)
	}
	defer chunkRows.Close()

	ld := NewLevelData(1.0)
	for chunkRows.Next() {
		var chunkID string
		var cid int
		if err := chunkRows.Scan(&chunkID, &cid); err != nil {
			return fmt.Errorf("loadLegacySchema: scan chunk_communities: %w", err)
		}
		ld.ChunkToCommunity[chunkID] = cid
		ld.CommunityToChunks[cid] = append(ld.CommunityToChunks[cid], chunkID)
	}
	if err := chunkRows.Err(); err != nil {
		return fmt.Errorf("loadLegacySchema: chunk_communities rows: %w", err)
	}

	communityRows, err := fetchLegacyCommunityRows(db)
	if err != nil {
		return fmt.Errorf("loadLegacySchema: fetch community rows: %w", err)
	}
	for _, r := range communityRows {
		ld.CommunityToLabel[r.cid] = r.label
		ld.CommunityToCoherence[r.cid] = r.coherence
	}
	ci.Levels = append(ci.Levels, ld)
	return nil
}

