def handle_starttag(self, tag: str, attrs):
        t = tag.lower()
        if t in self._SKIP or t.startswith("ix:"):
            self._skip_depth += 1
        if self._skip_depth:
            return
        if t in self._HEADING_MARKERS:
            self._heading_marker = self._HEADING_MARKERS[t]
            self._heading_prefixed = False
            self._parts.append("\n")
        elif t in self._BLOCK:
            self._parts.append("\n")

func (p *MarkdownParser) HandleStartTag(tag string, attrs []html.Attribute) {
	t := strings.ToLower(tag)
	_, inSkip := p.skip[t]
	if inSkip || strings.HasPrefix(t, "ix:") {
		p.skipDepth++
	}
	if p.skipDepth > 0 {
		return
	}
	if marker, ok := p.headingMarkers[t]; ok {
		p.headingMarker = &marker
		p.headingPrefixed = false
		p.parts = append(p.parts, "\n")
	} else if _, inBlock := p.block[t]; inBlock {
		p.parts = append(p.parts, "\n")
	}
}

