    sections: list[str] = []

    for anchor_id, item_num in toc_filtered:
        # Position of this anchor attribute in the raw HTML
        attr_pos = html.find(f'id="{anchor_id}"')
        if attr_pos == -1:
            continue

        tag_start = html.rfind("<", 0, attr_pos)
        pos_start = tag_start if tag_start != -1 else attr_pos

        try:
            idx = all_ids.index(anchor_id)
        except ValueError:
            continue

        if idx + 1 < len(all_ids):
            next_id = all_ids[idx + 1]
            next_attr = html.find(f'id="{next_id}"')
            pos_end = html.rfind("<", 0, next_attr) if next_attr != -1 else -1
            if pos_end <= pos_start:
                pos_end = len(html)
        else:
            pos_end = len(html)

        section_html = html[pos_start:pos_end]
        if infer_bold_headings:
            section_html = _promote_bold_headings(section_html, bold_heading_max_len)
            text = _to_markdown(section_html)
        else:
            text = _strip_tags(section_html)
        if not text.strip():
            continue

        name = _ITEM_NAMES.get(item_num, f"Item {item_num}")
        heading = f"# Item {item_num}.  {name}"
        sections.append(f"{heading}\n\n{text}")

    return "\n\n---\n\n".join(sections)

type ExtractEdgarProseOptions struct {
	ProseOnly           bool
	InferBoldHeadings   bool
	BoldHeadingMaxLen   int
}

func extractEdgarProse(htmlStr string, opts ExtractEdgarProseOptions) string {
	toc := parseTOC(htmlStr)
	if len(toc) == 0 {
		return stripTags(htmlStr)
	}

	var tocFiltered []TocEntry
	if opts.ProseOnly {
		for _, e := range toc {
			if _, ok := proseItems[e.ItemNum]; ok {
				tocFiltered = append(tocFiltered, e)
			}
		}
	} else {
		tocFiltered = toc
	}

	allIDs := make([]string, len(toc))
	for i, e := range toc {
		allIDs[i] = e.AnchorID
	}

	var sections []string
	for _, entry := range tocFiltered {
		attribTarget := fmt.Sprintf("id=\"%s\"", entry.AnchorID)
		attrPos := strings.Index(htmlStr, attribTarget)
		if attrPos == -1 {
			continue
		}
		tagStart := strings.LastIndex(htmlStr[:attrPos], "<")
		posStart := attrPos
		if tagStart != -1 {
			posStart = tagStart
		}

		idx := -1
		for i, id := range allIDs {
			if id == entry.AnchorID {
				idx = i
				break
			}
		}
		if idx == -1 {
			continue
		}

		posEnd := len(htmlStr)
		if idx+1 < len(allIDs) {
			nextID := allIDs[idx+1]
			nextAttr := strings.Index(htmlStr, fmt.Sprintf("id=\"%s\"", nextID))
			if nextAttr != -1 {
				pe := strings.LastIndex(htmlStr[:nextAttr], "<")
				if pe > posStart {
					posEnd = pe
				}
			}
		}

		sectionHTML := htmlStr[posStart:posEnd]
		var text string
		if opts.InferBoldHeadings {
			sectionHTML = promoteBoldHeadings(sectionHTML, opts.BoldHeadingMaxLen)
			text = toMarkdown(sectionHTML)
		} else {
			text = stripTags(sectionHTML)
		}
		if len(strings.TrimSpace(text)) == 0 {
			continue
		}

		name, ok := itemNames[entry.ItemNum]
		if !ok {
			name = fmt.Sprintf("Item %s", entry.ItemNum)
		}
		heading := fmt.Sprintf("# Item %s.  %s", entry.ItemNum, name)
		sections = append(sections, fmt.Sprintf("%s\n\n%s", heading, text))
	}

	return strings.Join(sections, "\n\n---\n\n")
}

func extractAttachments(msg *multipart.Reader, detectExtractor func(string) (Extractor, error), detectTypeFromSource func(string, string) string, log *slog.Logger) []string {
	var blocks []string
	for {
		part, err := msg.NextPart()
		if err != nil {
			break
		}
		disp := part.Header.Get("Content-Disposition")
		filename := getFilenameFromDisp(disp)
		if len(filename) == 0 && !strings.Contains(disp, "attachment") {
			continue
		}
		payload, err := io.ReadAll(part)
		if err != nil || len(payload) == 0 {
			continue
		}
		if len(filename) == 0 {
			filename = "attachment"
		}
		contentType := part.Header.Get("Content-Type")
		docType := detectTypeFromSource(filename, contentType)
		extractor, err := detectExtractor(docType)
		if err != nil {
			log.Debug("EmailExtractor: skipping attachment", "filename", filename, "err", err)
			continue
		}
		text, err := extractor.Extract(payload, filename)
		if err != nil {
			log.Debug("EmailExtractor: skipping attachment", "filename", filename, "err", err)
			continue
		}
		if len(strings.TrimSpace(text)) > 0 {
			blocks = append(blocks, fmt.Sprintf("[Attachment: %s]\n%s", filename, strings.TrimSpace(text)))
		}
	}
	return blocks
}

