func (e *EmailExtractor) Extract(data []byte, sourcePath string) (string, error) {
	msg, err := mail.ReadMessage(bytes.NewReader(data))
	if err != nil {
		return "", fmt.Errorf("EmailExtractor.Extract: parse message: %w", err)
	}

	// Headers
	var headerLines []string
	for _, field := range headerFields {
		raw := msg.Header.Get(field)
		if len(raw) > 0 {
			headerLines = append(headerLines, fmt.Sprintf("%s: %s", field, decodeHeaderValue(raw)))
		}
	}

	// Body
	body, err := getBody(msg)
	if err != nil {
		return "", fmt.Errorf("EmailExtractor.Extract: get body: %w", err)
	}
	body = strings.TrimSpace(body)

	// Attachments
	var attachmentBlocks []string
	if e.includeAttachments {
		attachmentBlocks = e.extractAttachments(msg)
	}

	var parts []string
	if len(headerLines) > 0 {
		parts = append(parts, strings.Join(headerLines, "\n"))
	}
	if len(body) > 0 {
		parts = append(parts, body)
	}
	parts = append(parts, attachmentBlocks...)

	return strings.Join(parts, "\n\n"), nil
}

