	if len(generic) > 0 && generic != brand {
		lines = append(lines, fmt.Sprintf("**Generic:** %s", generic))
	}
	if len(manufacturer) > 0 {
		lines = append(lines, fmt.Sprintf("**Manufacturer:** %s", manufacturer))
