    lines: list[str] = []
    val = res.get("valueQuantity")
    if val:
        v = val.get("value")
        unit = val.get("unit") or val.get("code", "")
        if v is not None:
            lines += ["", f"**Value:** {v} {unit}".strip()]
    val_str = res.get("valueString")
    if val_str:
        lines += ["", f"**Value:** {val_str}"]
    components = res.get("component", [])
    if components:
        lines += ["", "## Components", ""]
        for comp in components[:20]:
            comp_code = _code_text(comp.get("code"))
            comp_val = comp.get("valueQuantity", {})
            comp_v = comp_val.get("value")
            comp_u = comp_val.get("unit") or comp_val.get("code", "")
            if comp_code and comp_v is not None:
                lines.append(f"- {comp_code}: {comp_v} {comp_u}".strip())
    return lines

func renderObservationLines(res map[string]interface{}) []string {
	var lines []string
	if val, ok := res["valueQuantity"].(map[string]interface{}); ok {
		v := val["value"]
		unit, _ := val["unit"].(string)
		if len(unit) == 0 {
			unit, _ = val["code"].(string)
		}
		if v != nil {
			lines = append(lines, "", strings.TrimSpace(fmt.Sprintf("**Value:** %v %s", v, unit)))
		}
	}
	if valStr, ok := res["valueString"].(string); ok && len(valStr) > 0 {
		lines = append(lines, "", fmt.Sprintf("**Value:** %s", valStr))
	}
	compsRaw, _ := res["component"].([]interface{})
	if len(compsRaw) > 0 {
		lines = append(lines, "", "## Components", "")
		max := 20
		if len(compsRaw) < max {
			max = len(compsRaw)
		}
		for _, item := range compsRaw[:max] {
			comp, ok := item.(map[string]interface{})
			if !ok {
				continue
			}
			compCode := codeText(getMapField(comp, "code"))
			compVal, _ := comp["valueQuantity"].(map[string]interface{})
			var compV interface{}
			compU := ""
			if compVal != nil {
				compV = compVal["value"]
				compU, _ = compVal["unit"].(string)
				if len(compU) == 0 {
					compU, _ = compVal["code"].(string)
				}
			}
			if len(compCode) > 0 && compV != nil {
				lines = append(lines, strings.TrimSpace(fmt.Sprintf("- %s: %v %s", compCode, compV, compU)))
			}
		}
	}
	return lines
}

