func stripHTMLChrome(html string) string {
	for _, tag := range stripChromeBlockTags {
		re := regexp.MustCompile(fmt.Sprintf(`(?is)<%s[\s>].*?</%s>`, tag, tag))
		html = re.ReplaceAllString(html, "")
	}
	html = navAttrRe.ReplaceAllString(html, "")
	html = supRefRe.ReplaceAllString(html, "")
	return html
}

