def annotate(self, chunks: list, data: bytes, source_path: str | None = None) -> list:
        html = data.decode("utf-8", errors="replace")

        scanner = _HeadingScanner()
        scanner.feed(html)
        if not scanner.records:
            return chunks

        # Build (anchor, heading_path) for each heading in document order
        heading_stack: list[tuple[int, str | None, str]] = []
        section_anchors: list[tuple[str | None, list[str]]] = []
        for level, anchor, text in scanner.records:
            heading_stack = [(l, a, t) for l, a, t in heading_stack if l < level]
            heading_stack.append((level, anchor, text))
            path = [t for _, _, t in heading_stack]
            top_anchor = next((a for _, a, _ in reversed(heading_stack) if a), None)
            section_anchors.append((top_anchor, path))

        # Convert to markdown and split into segments keyed by heading
        markdown = _convert_html_to_markdown(html)
        heading_idx = 0
        segments: list[tuple[str | None, list[str], str]] = []
        current_anchor: str | None = None
        current_path: list[str] = []
        current_buf: list[str] = []

        for line in markdown.split("\n"):
            m = re.match(r"^(#{1,6})\s+(.*)", line)
            if m and heading_idx < len(section_anchors):
                if current_buf:
                    segments.append((current_anchor, current_path, "\n".join(current_buf)))
                current_anchor, current_path = section_anchors[heading_idx]
                heading_idx += 1
                current_buf = [line]
            else:
                current_buf.append(line)
        if current_buf:
            segments.append((current_anchor, current_path, "\n".join(current_buf)))

        for chunk in chunks:
            content = chunk.content
            for anchor, path, seg_text in segments:
                if any(
                    frag in seg_text
                    for frag in content.split("\n")
                    if len(frag.strip()) > 20
                ):
                    detail: dict = {"heading_path": path}
                    if anchor:
                        detail["anchor"] = anchor
                    chunk.source_detail = detail
                    break

        return chunks

type headingRecord struct {
	Level  int
	Anchor string
	Text   string
}

type sectionAnchor struct {
	Anchor string
	Path   []string
}

func (e *HtmlExtractor) Annotate(chunks []Chunk, data []byte, sourcePath string) []Chunk {
	htmlStr := strings.ToValidUTF8(string(data), string(unicode.ReplacementChar))

	records := scanHeadings(htmlStr)
	if len(records) == 0 {
		return chunks
	}

	// Build section anchors from heading stack
	type stackEntry struct {
		Level  int
		Anchor string
		Text   string
	}
	var headingStack []stackEntry
	sectionAnchors := make([]sectionAnchor, 0, len(records))
	for _, rec := range records {
		var filtered []stackEntry
		for _, s := range headingStack {
			if s.Level < rec.Level {
				filtered = append(filtered, s)
			}
		}
		headingStack = append(filtered, stackEntry{rec.Level, rec.Anchor, rec.Text})

		path := make([]string, len(headingStack))
		for i, s := range headingStack {
			path[i] = s.Text
		}
		topAnchor := ""
		for j := len(headingStack) - 1; j >= 0; j-- {
			if len(headingStack[j].Anchor) > 0 {
				topAnchor = headingStack[j].Anchor
				break
			}
		}
		sectionAnchors = append(sectionAnchors, sectionAnchor{topAnchor, path})
	}

	// Split markdown into segments
	markdown := convertHTMLToMarkdown(htmlStr)
	headingIdx := 0
	type segment struct {
		Anchor string
		Path   []string
		Text   string
	}
	var segments []segment
	currentAnchor := ""
	var currentPath []string
	var currentBuf []string
	headingLineRe := regexp.MustCompile(`^(#{1,6})\s+(.*)`)

	for _, line := range strings.Split(markdown, "\n") {
		if headingLineRe.MatchString(line) && headingIdx < len(sectionAnchors) {
			if len(currentBuf) > 0 {
				segments = append(segments, segment{currentAnchor, currentPath, strings.Join(currentBuf, "\n")})
			}
			currentAnchor = sectionAnchors[headingIdx].Anchor
			currentPath = sectionAnchors[headingIdx].Path
			headingIdx++
			currentBuf = []string{line}
		} else {
			currentBuf = append(currentBuf, line)
		}
	}
	if len(currentBuf) > 0 {
		segments = append(segments, segment{currentAnchor, currentPath, strings.Join(currentBuf, "\n")})
	}

	for i := range chunks {
		content := chunks[i].Content
		for _, seg := range segments {
			matched := false
			for _, frag := range strings.Split(content, "\n") {
				if len(strings.TrimSpace(frag)) > 20 && strings.Contains(seg.Text, frag) {
					matched = true
					break
				}
			}
			if matched {
				detail := map[string]interface{}{"heading_path": seg.Path}
				if len(seg.Anchor) > 0 {
					detail["anchor"] = seg.Anchor
				}
				chunks[i].SourceDetail = detail
				break
			}
		}
	}
	return chunks
}

func collectJavaBody(lines []string, start int, currentDepth int) (string, int, int) {
	var collected []string
	depth := currentDepth
	foundOpen := false
	i := start
	for i < len(lines) {
		line := lines[i]
		collected = append(collected, line)
		opens := strings.Count(line, "{")
		closes := strings.Count(line, "}")
		if opens > 0 {
			foundOpen = true
		}
		depth += opens - closes
		i++
		if foundOpen && depth <= currentDepth {
			break
		}
	}
	return strings.Join(collected, "\n"), i, depth
}

