func NormalizeType(userType string) (string, error) {
	if len(userType) == 0 {
		return "auto", nil
	}
	lower := strings.ToLower(strings.TrimSpace(userType))
	if _, ok := knownShort[lower]; ok {
		return lower, nil
	}
	if _, ok := legacyTransportTypes[lower]; ok {
		return "auto", nil
	}
	if short, ok := mimeToShort[lower]; ok {
		return short, nil
	}
	var known []string
	for k := range knownShort {
		if k != "auto" {
			known = append(known, k)
		}
	}
	sort.Strings(known)
	return "", fmt.Errorf("Unknown document type: %q. Use one of: %v or a MIME type.", userType, known)
}

