def _parts_text(parts: list[dict], depth: int = 0) -> list[str]:
    """Recursively extract prose from OSCAL part trees."""
    lines: list[str] = []
    for part in parts:
        prose = (part.get("prose") or "").strip()
        sub = part.get("parts", [])
        if prose:
            prefix = "  " * depth
            lines.append(f"{prefix}{prose}")
        if sub:
            lines.extend(_parts_text(sub, depth + 1))
    return lines

// _partsText recursively extracts prose from OSCAL part trees with depth indentation.
func _partsText(parts []interface{}, depth int) []string {
	var lines []string
	for _, p := range parts {
		pm, ok := p.(map[string]interface{})
		if !ok {
			continue
		}
		prose := ""
		if v, ok := pm["prose"]; ok && v != nil {
			prose = strings.TrimSpace(fmt.Sprintf("%v", v))
		}
		var sub []interface{}
		if s, ok := pm["parts"]; ok {
			if sl, ok := s.([]interface{}); ok {
				sub = sl
			}
		}
		if len(prose) > 0 {
			prefix := strings.Repeat("  ", depth)
			lines = append(lines, fmt.Sprintf("%s%s", prefix, prose))
		}
		if len(sub) > 0 {
			lines = append(lines, _partsText(sub, depth+1)...)
		}
	}
	return lines
}

