type NistRenderer struct{}

// CanRender returns true when obj is an OSCAL catalog JSON with NIST-style control IDs.
func (r *NistRenderer) CanRender(sourcePath *string, obj interface{}) bool {
	objMap, ok := obj.(map[string]interface{})
	if !ok {
		return false
	}
	var catalog map[string]interface{}
	if c, ok := objMap["catalog"]; ok {
		if cm, ok := c.(map[string]interface{}); ok {
