def _walk(obj: Any, lines: list[str], depth: int, path: str) -> None:
    heading = "#" * min(depth, 6)
    if isinstance(obj, dict):
        for key, val in obj.items():
            child_path = f"{path} > {key}" if path else key
            if isinstance(val, (dict, list)):
                lines.append(f"{heading} {child_path}")
                _walk(val, lines, depth + 1, child_path)
            else:
                lines.append(f"{heading} {child_path}")
                if val is not None and str(val).strip():
                    lines.append(str(val))
    elif isinstance(obj, list):
        for i, item in enumerate(obj):
            child_path = f"{path}[{i}]" if path else f"[{i}]"
            if isinstance(item, (dict, list)):
                lines.append(f"{heading} {child_path}")
                _walk(item, lines, depth + 1, child_path)
            else:
                if item is not None and str(item).strip():
                    lines.append(str(item))
    else:
        if obj is not None and str(obj).strip():
            lines.append(str(obj))

// _walk recursively walks a JSON-like structure and appends markdown heading lines.
func _walk(obj interface{}, lines *[]string, depth int, path string) {
	d := depth
	if d > 6 {
		d = 6
	}
	heading := strings.Repeat("#", d)
	switch v := obj.(type) {
	case map[string]interface{}:
		for key, val := range v {
			var childPath string
			if len(path) > 0 {
				childPath = fmt.Sprintf("%s > %s", path, key)
			} else {
				childPath = key
			}
			*lines = append(*lines, fmt.Sprintf("%s %s", heading, childPath))
			switch val.(type) {
			case map[string]interface{}, []interface{}:
				_walk(val, lines, depth+1, childPath)
			default:
				if val != nil {
					if s := strings.TrimSpace(fmt.Sprintf("%v", val)); len(s) > 0 {
						*lines = append(*lines, s)
					}
				}
			}
		}
	case []interface{}:
		for i, item := range v {
			var childPath string
			if len(path) > 0 {
				childPath = fmt.Sprintf("%s[%d]", path, i)
			} else {
				childPath = fmt.Sprintf("[%d]", i)
			}
			switch item.(type) {
			case map[string]interface{}, []interface{}:
				*lines = append(*lines, fmt.Sprintf("%s %s", heading, childPath))
				_walk(item, lines, depth+1, childPath)
			default:
				if item != nil {
					if s := strings.TrimSpace(fmt.Sprintf("%v", item)); len(s) > 0 {
						*lines = append(*lines, s)
					}
				}
			}
		}
	default:
		if obj != nil {
			if s := strings.TrimSpace(fmt.Sprintf("%v", obj)); len(s) > 0 {
				*lines = append(*lines, s)
			}
		}
	}
}

