func extractODT(childNodes []ODFElement) string {
	var lines []string
	for _, elem := range childNodes {
		_, tag := elem.GetQName()
		if tag == "h" {
			levelStr := elem.GetAttribute("outlinelevel")
			level := 1
			if levelStr != "" {
				if n, err := strconv.Atoi(levelStr); err == nil {
					level = n
				}
			}
			if level > 6 {
				level = 6
			}
