	GetCells() []ODFCell
}
type ODFCell interface {
	ExtractText() string
}

// extractODS extracts markdown from an ODS spreadsheet document.
func extractODS(tables []ODFTable) string {
	var sheets []string
	for _, table := range tables {
		name := table.GetAttribute("name")
		if name == "" {
			name = "Sheet"
		}
		var rows []string
		for _, row := range table.GetRows() {
			var cells []string
			for _, cell := range row.GetCells() {
				cells = append(cells, strings.TrimSpace(cell.ExtractText()))
			}
			hasContent := false
			for _, c := range cells {
				if len(c) > 0 {
					hasContent = true
					break
				}
			}
			if hasContent {
				rows = append(rows, strings.Join(cells, " | "))
			}
		}
		if len(rows) > 0 {
			sheets = append(sheets, fmt.Sprintf("[Sheet: %s]\n%s", name, strings.Join(rows, "\n")))
		}
	}
	return strings.Join(sheets, "\n\n")
}

