def _extract_pptx_content(prs) -> str:
    """Extract text content from a python-pptx Presentation object."""
    slides = []

    for i, slide in enumerate(prs.slides, 1):
        slide_text = []

        for shape in slide.shapes:
            shape_text_val: Any = getattr(shape, "text", None)
            if shape_text_val and str(shape_text_val).strip():
                slide_text.append(str(shape_text_val).strip())

            if shape.has_table:
                table_rows = []
                for row in shape.table.rows:
                    cells = [cell.text.strip() for cell in row.cells]
                    table_rows.append(" | ".join(cells))
                if table_rows:
                    slide_text.append("\n".join(table_rows))

        if slide_text:
            slides.append(f"[Slide {i}]\n" + "\n".join(slide_text))

    return "\n\n".join(slides)

// Slide and Shape are domain types representing pptx structures.
type Slide struct {
	Shapes []Shape
}

type Shape struct {
	Text     string
	HasTable bool
	Table    *Table
}

type Table struct {
	Rows []Row
}

type Row struct {
	Cells []Cell
}

type Cell struct {
	Text string
}

type Presentation struct {
	Slides []Slide
}

func extractPptxContent(prs *Presentation) string {
	var slides []string

	for i, slide := range prs.Slides {
		slideNum := i + 1
		var slideText []string

		for _, shape := range slide.Shapes {
			trimmed := strings.TrimSpace(shape.Text)
			if len(trimmed) > 0 {
				slideText = append(slideText, trimmed)
			}

			if shape.HasTable && shape.Table != nil {
				var tableRows []string
				for _, row := range shape.Table.Rows {
					var cells []string
					for _, cell := range row.Cells {
						cells = append(cells, strings.TrimSpace(cell.Text))
					}
					tableRows = append(tableRows, strings.Join(cells, " | "))
				}
				if len(tableRows) > 0 {
					slideText = append(slideText, strings.Join(tableRows, "\n"))
				}
			}
		}

		if len(slideText) > 0 {
			header := fmt.Sprintf("[Slide %d]", slideNum)
			slides = append(slides, header+"\n"+strings.Join(slideText, "\n"))
		}
	}

	return strings.Join(slides, "\n\n")
}

