def extract(self, data: bytes, source_path: str | None = None) -> str:
        if not data:
            return ""

        try:
            source = data.decode("utf-8")
        except UnicodeDecodeError as exc:
            raise ValueError(f"UTF-8 decode failed in {source_path or '<unknown>'}: {exc}") from exc

        try:
            tree = ast.parse(source, filename=source_path or "<unknown>")
        except SyntaxError as exc:
            raise ValueError(f"Python syntax error in {source_path or '<unknown>'}: {exc}") from exc

        parts: list[str] = []

        # Collect top-level imports
        import_nodes = [
            node
            for node in ast.walk(tree)
            if isinstance(node, (ast.Import, ast.ImportFrom))
            and any(node is top for top in ast.iter_child_nodes(tree))
        ]
        if import_nodes:
            segments: list[str] = []
            for node in import_nodes:
                seg = ast.get_source_segment(source, node)
                if seg:
                    segments.append(seg)
            if segments:
                parts.append("## Imports\n\n```python\n" + "\n".join(segments) + "\n```")

        for node in ast.iter_child_nodes(tree):
            if isinstance(node, ast.ClassDef):
                parts.append(f"# {node.name}")
                docstring = ast.get_docstring(node)
                if docstring:
                    parts.append(docstring)
                methods = [
                    item
                    for item in ast.iter_child_nodes(node)
                    if isinstance(item, (ast.FunctionDef, ast.AsyncFunctionDef))
                ]
                if methods:
                    for item in methods:
                        parts.append(f"## {item.name}")
                        method_doc = ast.get_docstring(item)
                        if method_doc:
                            parts.append(method_doc)
                        seg = ast.get_source_segment(source, item)
                        if seg:
                            parts.append(f"```python\n{seg}\n```")
                else:
                    seg = ast.get_source_segment(source, node)
                    if seg:
                        parts.append(f"```python\n{seg}\n```")

            elif isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                parts.append(f"# {node.name}")
                docstring = ast.get_docstring(node)
                if docstring:
                    parts.append(docstring)
                seg = ast.get_source_segment(source, node)
                if seg:
                    parts.append(f"```python\n{seg}\n```")

        return "\n\n".join(parts)

// ASTNode is a simplified representation of a Python AST node for Go.
type ASTNode struct {
	Kind      string // "ClassDef", "FunctionDef", "Import", "ImportFrom"
	Name      string
	Docstring string
	Source    string
	Methods   []ASTNode
}

type PythonExtractor struct{}

func (p *PythonExtractor) Extract(data []byte, sourcePath *string) (string, error) {
	if len(data) == 0 {
		return "", nil
	}

	source, err := decodeUTF8(data)
	if err != nil {
		sp := "<unknown>"
		if sourcePath != nil {
			sp = *sourcePath
		}
		return "", fmt.Errorf("UTF-8 decode failed in %s: %w", sp, err)
	}

	tree, err := parsePythonAST(source, sourcePath)
	if err != nil {
		sp := "<unknown>"
		if sourcePath != nil {
			sp = *sourcePath
		}
		return "", fmt.Errorf("Python syntax error in %s: %w", sp, err)
	}

	var parts []string

	// Collect top-level imports
	var importNodes []ASTNode
	for _, node := range tree.Walk() {
		if (node.Kind == "Import" || node.Kind == "ImportFrom") && tree.IsTopLevel(node) {
			importNodes = append(importNodes, node)
		}
	}
	if len(importNodes) > 0 {
		var segments []string
		for _, node := range importNodes {
			seg := node.Source
			if len(seg) > 0 {
				segments = append(segments, seg)
			}
		}
		if len(segments) > 0 {
			parts = append(parts, "## Imports\n\n```python\n"+strings.Join(segments, "\n")+"\n```")
		}
	}

	for _, node := range tree.Children() {
		if node.Kind == "ClassDef" {
			parts = append(parts, fmt.Sprintf("# %s", node.Name))
			if len(node.Docstring) > 0 {
				parts = append(parts, node.Docstring)
			}
			if len(node.Methods) > 0 {
				for _, item := range node.Methods {
					parts = append(parts, fmt.Sprintf("## %s", item.Name))
					if len(item.Docstring) > 0 {
						parts = append(parts, item.Docstring)
					}
					if len(item.Source) > 0 {
						parts = append(parts, fmt.Sprintf("```python\n%s\n```", item.Source))
					}
				}
			} else {
				if len(node.Source) > 0 {
					parts = append(parts, fmt.Sprintf("```python\n%s\n```", node.Source))
				}
			}
		} else if node.Kind == "FunctionDef" || node.Kind == "AsyncFunctionDef" {
			parts = append(parts, fmt.Sprintf("# %s", node.Name))
			if len(node.Docstring) > 0 {
				parts = append(parts, node.Docstring)
			}
			if len(node.Source) > 0 {
				parts = append(parts, fmt.Sprintf("```python\n%s\n```", node.Source))
			}
		}
	}

	return strings.Join(parts, "\n\n"), nil
}

func advanceJSDoc(stripped, line string, inJSDoc bool, pendingJSDoc []string) (bool, []string) {
	if strings.HasPrefix(stripped, "/**") {
		pendingJSDoc = []string{line}
		inJSDoc = !strings.Contains(stripped, "*/")
		return inJSDoc, pendingJSDoc
	}
	// already inside a JSDoc block
	pendingJSDoc = append(pendingJSDoc, line)
	if strings.Contains(stripped, "*/") {
		inJSDoc = false
	}
	return inJSDoc, pendingJSDoc
}

var classRE = regexp.MustCompile(`^(?:export\s+)?(?:abstract\s+)?class\s+(\w+)`)
var interfaceRE = regexp.MustCompile(`^(?:export\s+)?interface\s+(\w+)`)

// ClassEntry holds the class name and the brace depth at which the class opened.
type ClassEntry struct {
	Name       string
	DepthBefore int
}

func handleClassOrInterface(
	stripped, line string,
	i, braceDepth int,
	classStack *[]ClassEntry,
	pendingJSDoc []string,
	parts *[]string,
) (matched bool, nextI, newBraceDepth int, clearedJSDoc []string) {
