		name := m[1]
		jsdoc := consumeJSDoc(pendingJSDoc)
		*parts = append(*parts, fmt.Sprintf("# %s", name))
		if len(jsdoc) > 0 {
			*parts = append(*parts, jsdoc)
		}
		braceDepth += strings.Count(line, "{") - strings.Count(line, "}")
		return true, i + 1, braceDepth, nil
	}

	return false, i, braceDepth, pendingJSDoc
}

var functionRE = regexp.MustCompile(`^(?:export\s+)?(?:async\s+)?function\s+(\w+)\s*\(`)
