	i, braceDepth int,
	classStack []ClassEntry,
	pendingJSDoc []string,
	parts *[]string,
	sectionMap map[string]SectionInfo,
	lines []string,
) (matched bool, nextI, newBraceDepth int, clearedJSDoc []string) {
