	lineStart := i + 1
	body, nextIdx, newDepth := collectBody(lines, i, braceDepth)
	sectionMap[sectionKeyStr(SectionKey{name})] = SectionInfo{
		LineStart: lineStart,
		LineEnd:   nextIdx,
		Symbol:    name,
