	*parts = append(*parts, fmt.Sprintf("## %s", mname))
	if len(jsdoc) > 0 {
		*parts = append(*parts, jsdoc)
	}
	lineStart := i + 1
	body, nextIdx, newDepth := collectBody(lines, i, braceDepth)
	sectionMap[sectionKeyStr(SectionKey{className, mname})] = SectionInfo{
		LineStart: lineStart,
		LineEnd:   nextIdx,
		Symbol:    fmt.Sprintf("%s.%s", className, mname),
