		line := lines[i]
		stripped := strings.TrimSpace(line)

		if strings.HasPrefix(stripped, "/**") || inJSDoc {
			inJSDoc, pendingJSDoc = advanceJSDoc(stripped, line, inJSDoc, pendingJSDoc)
