		matched, nextI, newDepth, newJSDoc = handleClassMethod(line, i, braceDepth, &classStack, pendingJSDoc, &parts, sectionMap, lines)
		if matched {
			i, braceDepth, pendingJSDoc = nextI, newDepth, newJSDoc
			continue
		}

