		delta := strings.Count(line, "{") - strings.Count(line, "}")
		braceDepth += delta
		for len(classStack) > 0 && braceDepth <= classStack[len(classStack)-1].DepthBefore {
			classStack = classStack[:len(classStack)-1]
		}

		i++
	}

	return strings.Join(parts, "\n\n"), sectionMap
}

