func collectBody(lines []string, start, currentDepth int) (body string, nextI, finalDepth int) {
	var collected []string
	depth := currentDepth
	foundOpen := false
	i := start

	for i < len(lines) {
		line := lines[i]
		collected = append(collected, line)
		opens := strings.Count(line, "{")
		closes := strings.Count(line, "}")
		if opens > 0 {
			foundOpen = true
		}
		depth += opens - closes
		i++
		if foundOpen && depth <= currentDepth {
			break
		}
	}

	return strings.Join(collected, "\n"), i, depth
}

