	Rows []SheetRow
}

// Workbook is a collection of sheets.
type Workbook struct {
	Sheets []Sheet
}

func extractXlsxContent(wb *Workbook) string {
	var sheets []string

	for _, sheet := range wb.Sheets {
		var rows []string
		for _, row := range sheet.Rows {
			var cells []string
			for _, cell := range row {
				if cell.Value != nil {
					cells = append(cells, *cell.Value)
				} else {
					cells = append(cells, "")
				}
			}
			hasContent := false
			for _, c := range cells {
				if len(strings.TrimSpace(c)) > 0 {
					hasContent = true
					break
				}
			}
			if hasContent {
				rows = append(rows, strings.Join(cells, " | "))
			}
		}
		if len(rows) > 0 {
			header := fmt.Sprintf("[Sheet: %s]", sheet.Name)
			sheets = append(sheets, header+"\n"+strings.Join(rows, "\n"))
		}
	}

	return strings.Join(sheets, "\n\n")
}

