            content = chunk.content
            matched_sheets: list[str] = []
            matched_rows: list[int] = []
            for sheet_name, row_text, row_idx in row_map:
                if row_text in content:
                    matched_sheets.append(sheet_name)
                    matched_rows.append(row_idx)
            if matched_rows:
