type XlsxExtractor struct{}

func (x *XlsxExtractor) Annotate(chunks []*DocumentChunk, data []byte, sourcePath *string) ([]*DocumentChunk, error) {
	wb, err := loadWorkbook(data)
	if err != nil {
		return nil, fmt.Errorf("xlsx annotate: load workbook: %w", err)
	}

	var rowMap []RowEntry
	for _, sheet := range wb.Sheets {
		for rowIdx, row := range sheet.Rows {
			var cells []string
			for _, cell := range row {
				if cell.Value != nil {
					cells = append(cells, *cell.Value)
				} else {
					cells = append(cells, "")
				}
			}
			hasContent := false
			for _, c := range cells {
				if len(strings.TrimSpace(c)) > 0 {
					hasContent = true
					break
				}
			}
			if hasContent {
				rowMap = append(rowMap, RowEntry{
					SheetName: sheet.Name,
					RowText:   strings.Join(cells, " | "),
					RowIdx:    rowIdx + 1,
				})
			}
		}
	}

	for _, chunk := range chunks {
		content := chunk.Content
		var matchedSheets []string
		var matchedRows []int
		for _, entry := range rowMap {
			if strings.Contains(content, entry.RowText) {
				matchedSheets = append(matchedSheets, entry.SheetName)
				matchedRows = append(matchedRows, entry.RowIdx)
			}
		}
		if len(matchedRows) > 0 {
			minRow, maxRow := matchedRows[0], matchedRows[0]
			for _, r := range matchedRows {
				if r < minRow {
