def _tag(element: ET.Element) -> str:
    tag = element.tag
    if tag.startswith("{"):
        tag = tag[tag.index("}") + 1 :]
    return tag


def _walk(element: ET.Element, lines: list[str], depth: int, path: str) -> None:
    tag = _tag(element)
    current_path = f"{path} > {tag}" if path else tag
    heading = "#" * min(depth, 6)
    lines.append(f"{heading} {current_path}")

    text = (element.text or "").strip()
    if text:
        lines.append(text)

    for child in element:
        _walk(child, lines, depth + 1, current_path)

    tail = (element.tail or "").strip()
    if tail:
        lines.append(tail)

// XMLElement is a simplified XML node for Go.
type XMLElement struct {
	Tag      string
	Text     string
	Tail     string
	Attrib   map[string]string
	Children []*XMLElement
}

func xmlTag(element *XMLElement) string {
	tag := element.Tag
	if strings.HasPrefix(tag, "{") {
		idx := strings.Index(tag, "}")
		if idx >= 0 {
			tag = tag[idx+1:]
		}
	}
	return tag
}

func xmlWalk(element *XMLElement, lines *[]string, depth int, path string) {
	tag := xmlTag(element)
	var currentPath string
	if len(path) > 0 {
		currentPath = fmt.Sprintf("%s > %s", path, tag)
	} else {
		currentPath = tag
	}
	headingLevel := depth
	if headingLevel > 6 {
		headingLevel = 6
	}
	heading := strings.Repeat("#", headingLevel)
	*lines = append(*lines, fmt.Sprintf("%s %s", heading, currentPath))

	text := strings.TrimSpace(element.Text)
	if len(text) > 0 {
		*lines = append(*lines, text)
	}

	for _, child := range element.Children {
		xmlWalk(child, lines, depth+1, currentPath)
	}

	tail := strings.TrimSpace(element.Tail)
	if len(tail) > 0 {
		*lines = append(*lines, tail)
	}
}

