def _to_dict(element: ET.Element) -> dict:
    """Convert an ElementTree element to a plain dict for renderer dispatch."""
    result: dict = {"_tag": _tag(element), **element.attrib}
    children = list(element)
    if children:
        child_dicts: dict[str, list] = {}
        for child in children:
            key = _tag(child)
            child_dicts.setdefault(key, []).append(_to_dict(child))
        for key, vals in child_dicts.items():
            result[key] = vals if len(vals) > 1 else vals[0]
    else:
        text = (element.text or "").strip()
        if text:
            result["_text"] = text
    return result

// XMLDict represents a parsed XML element as a generic map for renderer dispatch.
type XMLDict map[string]interface{}

func toDict(element *XMLElement) XMLDict {
	result := make(XMLDict)
	result["_tag"] = xmlTag(element)
	for k, v := range element.Attrib {
		result[k] = v
	}

	if len(element.Children) > 0 {
		childDicts := make(map[string][]XMLDict)
		for _, child := range element.Children {
			key := xmlTag(child)
			childDicts[key] = append(childDicts[key], toDict(child))
		}
		for key, vals := range childDicts {
			if len(vals) > 1 {
				result[key] = vals
			} else {
				result[key] = vals[0]
			}
		}
	} else {
		text := strings.TrimSpace(element.Text)
		if len(text) > 0 {
			result["_text"] = text
		}
	}
	return result
}

