	root, err := x.parse(data, sourcePath)
	if err != nil {
		return "", err
	}

	obj := toDict(root)
	renderer := x.findRenderer(sourcePath, obj)
	if renderer != nil {
		return renderer.Render(obj), nil
	}

	var lines []string
	xmlWalk(root, &lines, 1, "")
	return strings.Join(lines, "\n\n"), nil
