func (pb *PromptBuilder) SelectChunks(ctx *AnswerContext, tokenBudget int) []*ScoredChunk {
	sorted := make([]*ScoredChunk, len(ctx.Chunks))
	copy(sorted, ctx.Chunks)
	sort.Slice(sorted, func(i, j int) bool {
		return tierOf(sorted[i].Provenance) < tierOf(sorted[j].Provenance)
	})
	used := estimateTokens(pb.buildHeader(ctx))
	var selected []*ScoredChunk
	for _, sc := range sorted {
		cost := estimateTokens(sc.Chunk.Content)
		if used+cost > tokenBudget {
			break
		}
		used += cost
		selected = append(selected, sc)
	}
	return selected
}

