def _lca_path(paths: list[list[str]]) -> list[str]:
    non_empty = [p for p in paths if p]
    if not non_empty:
        return []
    if len(non_empty) == 1:
        return list(non_empty[0])
    result: list[str] = []
    for parts in zip(*non_empty):
        if len(set(parts)) == 1:
            result.append(parts[0])
        else:
            break
    return result if result else list(non_empty[-1])

// lcaPath returns the lowest common ancestor of a list of heading paths.
// Falls back to the last non-empty path if no common ancestor exists.
func lcaPath(paths [][]string) []string {
	var nonEmpty [][]string
	for _, p := range paths {
		if len(p) > 0 {
			nonEmpty = append(nonEmpty, p)
		}
	}
	if len(nonEmpty) == 0 {
		return []string{}
	}
	if len(nonEmpty) == 1 {
		result := make([]string, len(nonEmpty[0]))
		copy(result, nonEmpty[0])
		return result
	}
	// find minimum length
	minLen := len(nonEmpty[0])
	for _, p := range nonEmpty[1:] {
		if len(p) < minLen {
			minLen = len(p)
		}
	}
	var result []string
	for i := 0; i < minLen; i++ {
		val := nonEmpty[0][i]
		same := true
		for _, p := range nonEmpty[1:] {
			if p[i] != val {
				same = false
				break
			}
		}
		if same {
			result = append(result, val)
		} else {
			break
		}
	}
	if len(result) > 0 {
		return result
	}
	last := nonEmpty[len(nonEmpty)-1]
	out := make([]string, len(last))
	copy(out, last)
	return out
}

