    cleaned = []
    for para in paras:
        lines = [l for l in para.splitlines() if l.strip()]
        if not lines:
            cleaned.append(para)
            continue
        index_lines = sum(1 for l in lines if _INDEX_LINE_RE.match(l.strip()))
