				indexCount++
			}
		}
		if float64(indexCount)/float64(len(lines)) >= indexLineThreshold {
			continue
		}
		cleaned = append(cleaned, para)
	}
	return strings.Join(cleaned, "\n\n")
}

var _sentEndRE = regexp.MustCompile(`(?:[.!?])\s+`)

// promoteQuestionSentences promotes standalone question sentences to ## headings.
func promoteQuestionSentences(text string, maxHeaderWords, maxHeaderChars int) string {
	sentences := _sentEndRE.Split(text, -1)
	var out []string
	for i := 0; i < len(sentences); i++ {
		s := strings.TrimSpace(sentences[i])
		nextS := ""
		if i+1 < len(sentences) {
			nextS = strings.TrimSpace(sentences[i+1])
		}
		if strings.HasSuffix(s, "?") &&
			!strings.HasSuffix(nextS, "?") &&
			len(strings.Fields(s)) <= maxHeaderWords*2 &&
			len(s) <= maxHeaderChars*2 {
			out = append(out, fmt.Sprintf("\n\n## %s\n\n", s))
		} else {
			prefix := ""
			if len(out) > 0 && !strings.HasSuffix(out[len(out)-1], "\n") {
				prefix = " "
			}
			out = append(out, prefix+s)
		}
	}
	return strings.TrimSpace(strings.Join(out, ""))
}

// Indexer runs background source indexing with progress callbacks and safe abort.
type Indexer struct {
	store           *Store
	embedModelName  string
	onProgress      func(phase string, done, total int)
	onComplete      func(chunks int)
	onError         func(phase string, err error)
	onAbort         func(chunks int)
	batchSize       int
	minChunk        int
	maxChunk        int
	embedContentOnly bool
	abortCh         chan struct{}
}

// NewIndexer creates an Indexer. Callbacks may be nil.
func NewIndexer(
	store *Store,
	embedModelName string,
	onProgress func(string, int, int),
	onComplete func(int),
	onError func(string, error),
	onAbort func(int),
	embedBatchSize int,
	minChunkSize int,
	maxChunkSize int,
	embedContentOnly bool,
) (*Indexer, error) {
	if store == nil {
		return nil, fmt.Errorf("NewIndexer: store must not be nil")
	}
	if embedModelName == "" {
		return nil, fmt.Errorf("NewIndexer: embedModelName must not be empty")
	}
	noop3 := func(string, int, int) {}
	noop1i := func(int) {}
	noopE := func(string, error) {}
	if onProgress == nil {
		onProgress = noop3
	}
	if onComplete == nil {
		onComplete = noop1i
	}
	if onError == nil {
		onError = noopE
	}
	if onAbort == nil {
		onAbort = noop1i
	}
	if embedBatchSize <= 0 {
		embedBatchSize = 256
	}
	if minChunkSize <= 0 {
		minChunkSize = 400
	}
	if maxChunkSize <= 0 {
		maxChunkSize = 1200
	}
	return &Indexer{
		store:            store,
		embedModelName:   embedModelName,
		onProgress:       onProgress,
		onComplete:       onComplete,
		onError:          onError,
		onAbort:          onAbort,
		batchSize:        embedBatchSize,
		minChunk:         minChunkSize,
		maxChunk:         maxChunkSize,
		embedContentOnly: embedContentOnly,
		abortCh:          make(chan struct{}),
	}, nil
}

