def _resolve_domains(
        self,
        namespaces: list[str] | None,
        domains: list[str] | None,
    ) -> list[str] | None:
        if namespaces is None and domains is None:
            return None
        target_ns = namespaces or list(self._domain_map.keys())
        ids: list[str] = []
        if domains is not None:
            for ns in target_ns:
                ns_map = self._domain_map.get(ns, {})
                for name in domains:
                    if name in ns_map:
                        ids.append(ns_map[name])
        else:
            for ns in target_ns:
                ids.extend(self._domain_map.get(ns, {}).values())
        return ids or None

// resolveDomains converts namespace/domain name filters to domain ID lists.
// Returns nil when both namespaces and domains are nil (no filter).
func (idx *Index) resolveDomains(namespaces []string, domains []string) []string {
	if namespaces == nil && domains == nil {
		return nil
	}
	targetNS := namespaces
	if len(targetNS) == 0 {
		for ns := range idx.domainMap {
			targetNS = append(targetNS, ns)
		}
	}
	var ids []string
	if domains != nil {
		for _, ns := range targetNS {
			nsMap, ok := idx.domainMap[ns]
			if !ok {
				continue
			}
			for _, name := range domains {
				if did, found := nsMap[name]; found {
					ids = append(ids, did)
				}
			}
		}
	} else {
		for _, ns := range targetNS {
			if nsMap, ok := idx.domainMap[ns]; ok {
				for _, did := range nsMap {
					ids = append(ids, did)
				}
			}
		}
	}
	if len(ids) == 0 {
		return nil
	}
	return ids
}

// RemoveNamespace deletes a namespace and all its domains, chunks, and secondary index rows.
func (idx *Index) RemoveNamespace(namespaceID string) error {
	domainIDs := make([]string, 0)
	if nsMap, ok := idx.domainMap[namespaceID]; ok {
		for _, did := range nsMap {
			domainIDs = append(domainIDs, did)
		}
	}
	if len(domainIDs) > 0 {
		placeholders := make([]string, len(domainIDs))
		for i := range domainIDs {
			placeholders[i] = "?"
		}
		ph := strings.Join(placeholders, ", ")
		args := make([]interface{}, len(domainIDs))
		for i, did := range domainIDs {
			args[i] = did
		}
		queries := []string{
			fmt.Sprintf("DELETE FROM chunk_entities WHERE chunk_id IN (SELECT chunk_id FROM embeddings WHERE domain_id IN (%s))", ph),
			fmt.Sprintf("DELETE FROM svo_triples WHERE chunk_id IN (SELECT chunk_id FROM embeddings WHERE domain_id IN (%s))", ph),
			fmt.Sprintf("DELETE FROM embeddings WHERE domain_id IN (%s)", ph),
			fmt.Sprintf("DELETE FROM domains WHERE domain_id IN (%s)", ph),
		}
		for _, q := range queries {
			if _, err := idx.conn.Exec(q, args...); err != nil {
				return fmt.Errorf("RemoveNamespace: %w", err)
			}
		}
	}
	if _, err := idx.conn.Exec("DELETE FROM namespaces WHERE namespace_id = ?", namespaceID); err != nil {
		return fmt.Errorf("RemoveNamespace: delete namespace: %w", err)
	}
	delete(idx.domainMap, namespaceID)
	idx.invalidateSearch()
	return nil
}

// ingestGlob loads all files matching a glob pattern from a directory.
func ingestGlob(loader *DocumentLoader, src map[string]interface{}) ([]*DocumentChunk, error) {
	basePath, _ := src["path"].(string)
	pattern, ok := src["pattern"].(string)
	if !ok || pattern == "" {
		pattern = "*"
	}
	prefix, _ := src["name_prefix"].(string)
	docType, _ := src["doc_type"].(string)

	matches, err := filepath.Glob(filepath.Join(basePath, pattern))
	if err != nil {
		return nil, fmt.Errorf("ingestGlob: glob %q: %w", pattern, err)
	}
	sort.Strings(matches)

	var chunks []*DocumentChunk
	for _, p := range matches {
		base := filepath.Base(p)
		if strings.HasPrefix(base, ".") {
			continue
		}
		ext := filepath.Ext(base)
		stem := strings.TrimSuffix(base, ext)
		name := prefix + stem
		var loaded []*DocumentChunk
		if docType != "" {
			data, readErr := os.ReadFile(p)
			if readErr != nil {
				return nil, fmt.Errorf("ingestGlob: read %q: %w", p, readErr)
			}
			loaded, err = loader.LoadBytes(data, name, docType, nil)
		} else {
			loaded, err = loader.Load(p, &name)
		}
		if err != nil {
			return nil, fmt.Errorf("ingestGlob: load %q: %w", p, err)
		}
		chunks = append(chunks, loaded...)
	}
	return chunks, nil
}

// ingestJSONArray loads chunks from items in a JSON array field.
func ingestJSONArray(loader *DocumentLoader, src map[string]interface{}) ([]*DocumentChunk, error) {
	path, _ := src["path"].(string)
	arrayField, _ := src["array_field"].(string)
	idPathStr, _ := src["id_path"].(string)
	var idPath []string
	if idPathStr != "" {
		idPath = strings.Split(idPathStr, ".")
	}

	raw, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("ingestJSONArray: read %q: %w", path, err)
	}
	var obj interface{}
	if err := json.Unmarshal(raw, &obj); err != nil {
		return nil, fmt.Errorf("ingestJSONArray: parse JSON: %w", err)
	}

	var items []interface{}
	if m, ok := obj.(map[string]interface{}); ok {
		if v, ok2 := m[arrayField]; ok2 {
			if arr, ok3 := v.([]interface{}); ok3 {
				items = arr
			}
		}
	} else if arr, ok := obj.([]interface{}); ok {
		items = arr
	}

	stem := strings.TrimSuffix(filepath.Base(path), filepath.Ext(path))
	var chunks []*DocumentChunk
	for _, item := range items {
		var nameVal interface{} = item
		for _, key := range idPath {
			if m, ok := nameVal.(map[string]interface{}); ok {
				nameVal = m[key]
			} else {
				nameVal = "unknown"
				break
			}
		}
		name := stem
		if nameVal != nil {
			if s := fmt.Sprintf("%v", nameVal); s != "" && s != "<nil>" {
				name = s
			}
		}
		payload, err := json.Marshal(map[string]interface{}{arrayField: []interface{}{item}})
		if err != nil {
			return nil, fmt.Errorf("ingestJSONArray: marshal item: %w", err)
		}
		loaded, err := loader.LoadBytes(payload, name, "json", nil)
		if err != nil {
			return nil, fmt.Errorf("ingestJSONArray: load bytes: %w", err)
		}
		chunks = append(chunks, loaded...)
	}
	return chunks, nil
}

