def _find_transport(self, uri: str):
        for transport in self._transport_registry:
            if transport.can_handle(uri):
                return transport
        raise ValueError(f"No transport found for URI: {uri!r}")

    def _find_extractor(self, doc_type: str):
        for extractor in self._extra_extractors:
            if extractor.can_handle(doc_type):
                return extractor
        return detect_extractor(doc_type)

// findTransport returns the first transport that can handle the given URI.
func (dl *DocumentLoader) findTransport(uri string) (Transport, error) {
	for _, transport := range dl.transportRegistry {
		if transport.CanHandle(uri) {
			return transport, nil
		}
	}
	return nil, fmt.Errorf("no transport found for URI: %q", uri)
}

// findExtractor returns an extractor for the given doc type, checking extras first.
func (dl *DocumentLoader) findExtractor(docType string) Extractor {
	for _, extractor := range dl.extraExtractors {
