        if crawler is None:
            if uri.startswith("http://") or uri.startswith("https://"):
                crawler = WebCrawler()
            else:
                crawler = DirectoryCrawler()

        uris = crawler.crawl(uri, **crawler_kwargs)
        logger.info("load_crawl: %d URI(s) discovered from %s", len(uris), uri)

        all_chunks: list[DocumentChunk] = []
