// LoadCrawl crawls uri with the given crawler and loads each discovered document.
// If crawler is nil, WebCrawler is chosen for http(s) URIs, DirectoryCrawler otherwise.
func (dl *DocumentLoader) LoadCrawl(uri string, crawler Crawler) ([]*DocumentChunk, error) {
	if crawler == nil {
		if strings.HasPrefix(uri, "http://") || strings.HasPrefix(uri, "https://") {
			crawler = NewWebCrawler()
		} else {
			crawler = NewDirectoryCrawler()
		}
	}
	uris, err := crawler.Crawl(uri)
	if err != nil {
		return nil, fmt.Errorf("LoadCrawl: crawl %q: %w", uri, err)
	}
	log.Printf("load_crawl: %d URI(s) discovered from %s", len(uris), uri)
	var allChunks []*DocumentChunk
	for _, docURI := range uris {
		chunks, loadErr := dl.Load(docURI, nil)
		if loadErr != nil {
			log.Printf("load_crawl: skipping %s: %v", docURI, loadErr)
			continue
		}
		allChunks = append(allChunks, chunks...)
	}
	return allChunks, nil
}

// LoadIMAP fetches and indexes email messages from an IMAP mailbox.
// Each message becomes a separate indexed document.
func (dl *DocumentLoader) LoadIMAP(uri string, includeAttachments bool, limit *int) ([]*DocumentChunk, error) {
	transport := NewImapTransport()
	extractor := NewEmailExtractor(includeAttachments)

	var allChunks []*DocumentChunk
	messages, err := transport.FetchMessages(uri, limit)
	if err != nil {
		return nil, fmt.Errorf("LoadIMAP: fetch messages: %w", err)
	}
	for _, result := range messages {
		text, extractErr := extractor.Extract(result.Data, result.SourcePath)
		if extractErr != nil {
			log.Printf("load_imap: skipping message %s: %v", result.SourcePath, extractErr)
			continue
		}
		if strings.TrimSpace(text) == "" {
			continue
		}
		name := result.SourcePath
		if name == "" {
			name = "email"
		}
		chunks, chunkErr := chunkDocument(name, text, dl.minChunkSize, dl.maxChunkSize, dl.overflowMargin, dl.enrichContext, false)
		if chunkErr != nil {
			log.Printf("load_imap: chunk error %s: %v", name, chunkErr)
			continue
		}
		allChunks = append(allChunks, dl.enrich(chunks)...)
	}
	return allChunks, nil
}

