def load_schema(self, tables: list[TableMeta]) -> list[DocumentChunk]:
        chunks: list[DocumentChunk] = []
        for table in tables:
            db_prefix = table.source_db or "db"
            doc_name = f"schema:{db_prefix}.{table.name}"

            lines = [f"Table: {table.name}"]
            if table.schema_name:
                lines.append(f"Schema: {table.schema_name}")
            if table.source_db:
                lines.append(f"Source DB: {table.source_db}")
            if table.row_count is not None:
                lines.append(f"Row count: {table.row_count}")
            if table.description:
                lines.append(f"Description: {table.description}")
            if table.columns:
                lines.append(f"Columns: {', '.join(c.name for c in table.columns)}")

            chunks.append(DocumentChunk(
                document_name=doc_name,
                content="\n".join(lines),
                section=["table_description"],
                chunk_index=0,
                chunk_type="db_table",
            ))

            for col_idx, col in enumerate(table.columns, start=1):
                col_doc_name = f"schema:{db_prefix}.{table.name}.{col.name}"
                col_lines = [
                    f"Column: {col.name}",
                    f"Table: {table.name}",
                    f"Type: {col.data_type}",
                    f"Nullable: {'yes' if col.nullable else 'no'}",
                ]
                if col.is_primary_key:
                    col_lines.append("Primary key: yes")
                if col.is_foreign_key and col.foreign_key_ref:
                    col_lines.append(f"Foreign key: {col.foreign_key_ref}")
                if col.description:
                    col_lines.append(f"Description: {col.description}")

                chunks.append(DocumentChunk(
                    document_name=col_doc_name,
                    content="\n".join(col_lines),
                    section=["column_description"],
                    chunk_index=col_idx,
                    chunk_type="db_column",
                ))

        return self._enrich(chunks)

// LoadSchema builds N+1 DocumentChunks per table (one table chunk + one per column).
func (dl *DocumentLoader) LoadSchema(tables []*TableMeta) []*DocumentChunk {
	var chunks []*DocumentChunk
	for _, table := range tables {
		dbPrefix := "db"
		if table.SourceDB != "" {
			dbPrefix = table.SourceDB
		}
		docName := fmt.Sprintf("schema:%s.%s", dbPrefix, table.Name)

		lines := []string{fmt.Sprintf("Table: %s", table.Name)}
		if table.SchemaName != "" {
			lines = append(lines, fmt.Sprintf("Schema: %s", table.SchemaName))
		}
		if table.SourceDB != "" {
			lines = append(lines, fmt.Sprintf("Source DB: %s", table.SourceDB))
		}
		if table.RowCount != nil {
			lines = append(lines, fmt.Sprintf("Row count: %d", *table.RowCount))
		}
		if table.Description != "" {
			lines = append(lines, fmt.Sprintf("Description: %s", table.Description))
		}
		if len(table.Columns) > 0 {
			var colNames []string
			for _, c := range table.Columns {
				colNames = append(colNames, c.Name)
			}
			lines = append(lines, fmt.Sprintf("Columns: %s", strings.Join(colNames, ", ")))
		}
		chunks = append(chunks, &DocumentChunk{
			DocumentName: docName,
			Content:      strings.Join(lines, "\n"),
			Section:      []string{"table_description"},
			ChunkIndex:   0,
			ChunkType:    "db_table",
		})

		for colIdx, col := range table.Columns {
			colDocName := fmt.Sprintf("schema:%s.%s.%s", dbPrefix, table.Name, col.Name)
			nullableStr := "no"
			if col.Nullable {
				nullableStr = "yes"
			}
			colLines := []string{
				fmt.Sprintf("Column: %s", col.Name),
				fmt.Sprintf("Table: %s", table.Name),
				fmt.Sprintf("Type: %s", col.DataType),
				fmt.Sprintf("Nullable: %s", nullableStr),
			}
			if col.IsPrimaryKey {
				colLines = append(colLines, "Primary key: yes")
			}
			if col.IsForeignKey && col.ForeignKeyRef != "" {
				colLines = append(colLines, fmt.Sprintf("Foreign key: %s", col.ForeignKeyRef))
			}
			if col.Description != "" {
				colLines = append(colLines, fmt.Sprintf("Description: %s", col.Description))
			}
			chunks = append(chunks, &DocumentChunk{
				DocumentName: colDocName,
				Content:      strings.Join(colLines, "\n"),
				Section:      []string{"column_description"},
				ChunkIndex:   colIdx + 1,
				ChunkType:    "db_column",
			})
		}
	}
	return dl.enrich(chunks)
}

