type contextGraphHeader struct {
	chunkIDs        []string
	fullFingerprint string
}

func buildContextGraphEdgesHeader(conn DBConn, namespace string, force bool) (*ContextGraphStats, contextGraphHeader, error) {
	chunkRows, err := conn.Query(
		"SELECT chunk_id FROM embeddings WHERE COALESCE(namespace, 'global') = ?", namespace,
	)
	if err != nil {
		return nil, contextGraphHeader{}, fmt.Errorf("buildContextGraphEdges load chunk_ids: %w", err)
	}
	chunkIDs := make([]string, 0, len(chunkRows))
	for _, r := range chunkRows {
		chunkIDs = append(chunkIDs, r[0].(string))
	}
	fingerprint := chunkFingerprint(chunkIDs)

	svoCount := 0
	svoRows, err := conn.Query(
		"SELECT COUNT(*) FROM svo_triples WHERE COALESCE(namespace, 'global') = ?", namespace,
	)
	if err == nil && len(svoRows) > 0 {
		svoCount = int(svoRows[0][0].(int64))
	}

	raw := sha256.Sum256([]byte(fmt.Sprintf("%s:%d", fingerprint, svoCount)))
	fullFingerprint := fmt.Sprintf("%x", raw)[:16]

	if !force {
		cacheRows, err := conn.Query(
			"SELECT chunk_fingerprint, entity_count, edge_count FROM context_graph_cache WHERE namespace = ?",
			namespace,
		)
		if err != nil {
			return nil, contextGraphHeader{}, fmt.Errorf("buildContextGraphEdges cache read: %w", err)
		}
		if len(cacheRows) > 0 && cacheRows[0][0].(string) == fullFingerprint {
			stats := &ContextGraphStats{
				EntityCount: int(cacheRows[0][1].(int64)),
				EdgeCount:   int(cacheRows[0][2].(int64)),
				ChunkCount:  len(chunkIDs),
			}
			return stats, contextGraphHeader{}, nil
		}
	}
	return nil, contextGraphHeader{chunkIDs: chunkIDs, fullFingerprint: fullFingerprint}, nil
}

type entityMaps struct {
	entityToChunks   map[string]map[string]struct{}
	entityToClusters map[string]map[int]struct{}
	allEntities      []string
}

func buildEntityMaps(ceRows [][2]string, chunkClusterMap map[string]int) entityMaps {
	entityToChunks := make(map[string]map[string]struct{})
	for _, r := range ceRows {
		chunkID, entityID := r[0], r[1]
		if entityToChunks[entityID] == nil {
			entityToChunks[entityID] = make(map[string]struct{})
		}
		entityToChunks[entityID][chunkID] = struct{}{}
	}

	allEntities := make([]string, 0, len(entityToChunks))
	for e := range entityToChunks {
		allEntities = append(allEntities, e)
	}
	sort.Strings(allEntities)

	entityToClusters := make(map[string]map[int]struct{})
	for chunkID, clusterID := range chunkClusterMap {
		for eid, chunks := range entityToChunks {
			if _, ok := chunks[chunkID]; ok {
				if entityToClusters[eid] == nil {
					entityToClusters[eid] = make(map[int]struct{})
				}
				entityToClusters[eid][clusterID] = struct{}{}
			}
		}
	}
	return entityMaps{
		entityToChunks:   entityToChunks,
		entityToClusters: entityToClusters,
		allEntities:      allEntities,
	}
}

type SVOPairKey struct{ A, B string }

func buildSVOPairs(conn DBConn, namespace string) (map[SVOPairKey]struct{}, error) {
	svo_pairs := make(map[SVOPairKey]struct{})
	rows, err := conn.Query(
		"SELECT subject_id, object_id FROM svo_triples WHERE COALESCE(namespace, 'global') = ?",
		namespace,
	)
	if err != nil {
		// table may not exist yet; treat as empty
		return svo_pairs, nil
	}
	for _, r := range rows {
		subj, obj := r[0].(string), r[1].(string)
		a, b := subj, obj
		if a > b {
			a, b = b, a
		}
		svo_pairs[SVOPairKey{A: a, B: b}] = struct{}{}
	}
	return svo_pairs, nil
}

type rawEdge struct {
	A, B                           string
	RawWeight, SVOSignal, CoocSignal, ClustSignal float64
}

func computeRawEdges(
	allEntities []string,
	entityToChunks map[string]map[string]struct{},
	entityToClusters map[string]map[int]struct{},
	svoPairs map[SVOPairKey]struct{},
) []rawEdge {
	var edges []rawEdge
	for i := 0; i < len(allEntities); i++ {
		for j := i + 1; j < len(allEntities); j++ {
			a, b := allEntities[i], allEntities[j]

			ka, kb := a, b
			if ka > kb {
				ka, kb = kb, ka
			}
			svoSignal := 0.0
			if _, ok := svoPairs[SVOPairKey{A: ka, B: kb}]; ok {
				svoSignal = 1.0
			}

			sharedCount := 0
			for c := range entityToChunks[a] {
				if _, ok := entityToChunks[b][c]; ok {
					sharedCount++
				}
			}
			coocSignal := math.Min(float64(sharedCount)*0.8, 0.8)

			clustersA := entityToClusters[a]
			clustersB := entityToClusters[b]
			clustSignal := 0.0
			if len(clustersA) > 0 || len(clustersB) > 0 {
				sharedCl := 0
				for c := range clustersA {
					if _, ok := clustersB[c]; ok {
						sharedCl++
					}
				}
				unionCl := len(clustersA) + len(clustersB) - sharedCl
				if unionCl > 0 {
					clustSignal = 0.4 * (float64(sharedCl) / float64(unionCl))
				}
			}

			rawWeight := svoSignal + coocSignal + clustSignal
			if rawWeight > 0 || svoSignal > 0 || coocSignal > 0 || clustSignal > 0 {
				edges = append(edges, rawEdge{A: a, B: b, RawWeight: rawWeight, SVOSignal: svoSignal, CoocSignal: coocSignal, ClustSignal: clustSignal})
			}
		}
	}
	return edges
}

