func NewSVOExtractor(llm LLMClient, opts SVOExtractorOptions) (*SVOExtractor, error) {
	if llm == nil {
		return nil, fmt.Errorf("NewSVOExtractor: llm must implement LLMClient, got nil")
	}

	verbSet := opts.VerbSet
	if verbSet == nil {
		verbSet = DefaultVerbSet
	}

	sysTmpl := systemPrompt
	if opts.SystemPromptTemplate != nil {
		sysTmpl = *opts.SystemPromptTemplate
	}

	userTmpl := userTemplate
	if opts.UserTemplate != nil {
		userTmpl = *opts.UserTemplate
	}

	// Build sorted verb list for the system prompt.
	verbs := make([]string, 0, len(verbSet))
	for v := range verbSet {
		verbs = append(verbs, v)
	}
	sort.Strings(verbs)
	systemMsg := fmt.Sprintf(sysTmpl, strings.Join(verbs, ", "))

	return &SVOExtractor{
		llm:          llm,
		verbSet:      verbSet,
		userTemplate: userTmpl,
		system:       systemMsg,
	}, nil
}

