func (e *SVOExtractor) ExtractEntityAnchored(text string, chunkID *string, entities []map[string]interface{}) EntityAnchoredResult {
	empty := EntityAnchoredResult{
		Triples:         []SVOTriple{},
		Descriptions:    map[string]string{},
		Aliases:         map[string][]string{},
		RelDescriptions: map[string]string{},
	}
	if len(entities) < 2 {
		return empty
	}

	validIDs := make(map[string]struct{}, len(entities))
	for _, ent := range entities {
		if id, ok := ent["id"].(string); ok {
			validIDs[id] = struct{}{}
		}
	}

	lines := make([]string, 0, len(entities))
	for _, ent := range entities {
		id, _ := ent["id"].(string)
		descRaw, _ := ent["description"].(string)
		hasDesc := len(descRaw) > 0
		marker := " "
		if hasDesc {
			marker = "\u2713"
		}
		entType := "?"
		if t, ok := ent["type"].(string); ok && len(t) > 0 {
			entType = t
		}
		descPart := ""
		if hasDesc {
			descPart = fmt.Sprintf(" \u2014 %s", descRaw)
		}
		lines = append(lines, fmt.Sprintf("  [%s] %s [%s]%s", marker, id, entType, descPart))
	}
	entityList := strings.Join(lines, "\n")

	verbs := make([]string, 0, len(e.verbSet))
	for v := range e.verbSet {
		verbs = append(verbs, v)
	}
	sort.Strings(verbs)
	anchoredSystem := fmt.Sprintf(entityAnchoredSystemPrompt, strings.Join(verbs, ", "))

	cid := ""
	if chunkID != nil {
		cid = *chunkID
	}
	prompt := anchoredSystem + "\n\n" + fmt.Sprintf(entityAnchoredUserTemplate, entityList, cid, text)

	raw := e.llm.Complete(prompt)
	result, ok := e.parseEntityAnchored(raw, chunkID, validIDs)
	if !ok {
		raw = e.llm.Complete(prompt + retrySuffix)
		result, ok = e.parseEntityAnchored(raw, chunkID, validIDs)
		if !ok {
			return empty
		}
	}
	return result
}

