func (e *SVOExtractor) parse(raw string, chunkID *string) ([]SVOTriple, bool) {
	// Strip markdown code fences.
	cleaned := codeBlockRe.ReplaceAllString(raw, "")
	cleaned = strings.TrimSpace(cleaned)

	var rows []interface{}
	if err := json.Unmarshal([]byte(cleaned), &rows); err != nil {
		return nil, false
	}

	triples := make([]SVOTriple, 0, len(rows))
	for _, item := range rows {
		row, ok := item.(map[string]interface{})
		if !ok {
			continue
		}
		verb, ok := row["verb"].(string)
		if !ok {
			continue
		}
		if _, allowed := e.verbSet[verb]; !allowed {
			continue
		}
		subjID, ok := row["subject_id"].(string)
		if !ok {
			continue
		}
		objID, ok := row["object_id"].(string)
		if !ok {
			continue
		}
		conf, ok := row["confidence"].(float64)
		if !ok {
			continue
		}
		t, err := NewSVOTriple(subjID, verb, objID, conf, chunkID, "")
		if err != nil {
			continue
		}
