// variants returns all surface-form variants for a term, all lowercase.
func variants(term string) []string {
	normalized := NormalizeSchemaTerm(term, NormalizeSchemaTermOpts{})
	singular := NormalizeSchemaTerm(term, NormalizeSchemaTermOpts{ToSingular: true})

	seen := map[string]struct{}{
		normalized: {},
		singular:   {},
	}
	if strings.Contains(term, "_") {
		seen[strings.ToLower(term)] = struct{}{}
	}
	seen[strings.ReplaceAll(normalized, " ", "")] = struct{}{}
	seen[strings.ReplaceAll(singular, " ", "")] = struct{}{}

	var result []string
	for v := range seen {
		if len(v) > 1 {
			result = append(result, v)
		}
	}
	return result
}

