func NewSchemaMatcher(opts SchemaMatcherOptions) *SchemaMatcher {
	sm := &SchemaMatcher{
		lookup:   make(map[string]lookupRecord),
		entities: make(map[string]entityRecord),
	}
	type pair struct {
		terms []string
		etype string
	}
	groups := []pair{
		{terms: opts.SchemaTerms, etype: "schema"},
		{terms: opts.APITerms, etype: "api"},
		{terms: opts.BusinessTerms, etype: "term"},
	}
	for _, g := range groups {
