			if displayName == "" {
				displayName = item.Name
			}
			id := item.ID
			if id == "" {
				id = autoID(name)
			}
			dtype := item.Type
			if dtype == "" {
				dtype = item.EntityType
			}
			if dtype == "" {
				dtype = "concept"
			}
			aliases := item.Aliases
			if aliases == nil {
				aliases = []string{}
			}
