	if len(commIDs) == 0 {
		return nil, nil
	}
	names := make([]interface{}, 0, len(commIDs))
	placeholders := make([]string, 0, len(commIDs))
	for cid := range commIDs {
		names = append(names, fmt.Sprintf("community:%d", cid))
		placeholders = append(placeholders, "?")
	}
	q := fmt.Sprintf(
		"SELECT content FROM embeddings WHERE document_name IN (%s) AND chunk_type = 'community_summary'",
		strings.Join(placeholders, ", "),
	)
	rows, err := s.store.Vector.Conn.Query(q, names...)
	if err != nil {
		return nil, fmt.Errorf("collectCommunityTexts query: %w", err)
	}
