def sync_document(
    backend: DuckDBVectorBackend,
    document_name: str,
    raw: bytes | None = None,
    *,
    content_hash: str | None = None,
    source_uri: str = "",
) -> SyncResult:
    if content_hash is None:
        if raw is None:
            raise ValueError("Either raw or content_hash must be provided.")
        content_hash = hashlib.sha256(raw).hexdigest()

    stored_hash = backend.get_document_hash(document_name)

    if stored_hash == content_hash:
        return SyncResult(
            action="skipped",
            document_name=document_name,
            content_hash=content_hash,
        )

    prev_count = backend.delete_by_document(document_name)
    action = "updated" if stored_hash is not None else "added"
    return SyncResult(
        action=action,
        document_name=document_name,
        content_hash=content_hash,
        previous_chunk_count=prev_count,
    )

type SyncResult struct {
	Action             string
	DocumentName       string
	ContentHash        string
	ChunkCount         int
	PreviousChunkCount int
}

func SyncDocument(backend *DuckDBVectorBackend, documentName string, raw []byte, contentHash string, sourceURI string) (*SyncResult, error) {
	if contentHash == "" {
		if raw == nil {
			return nil, fmt.Errorf("either raw or contentHash must be provided")
		}
		hash := sha256.Sum256(raw)
		contentHash = hex.EncodeToString(hash[:])
	}
	storedHash, err := backend.GetDocumentHash(documentName)
	if err != nil {
		return nil, fmt.Errorf("get document hash: %w", err)
	}
	if storedHash == contentHash {
		return &SyncResult{
			Action:       "skipped",
			DocumentName: documentName,
			ContentHash:  contentHash,
		}, nil
	}
	prevCount, err := backend.DeleteByDocument(documentName)
	if err != nil {
		return nil, fmt.Errorf("delete by document: %w", err)
	}
	action := "added"
	if storedHash != "" {
		action = "updated"
	}
	return &SyncResult{
		Action:             action,
		DocumentName:       documentName,
		ContentHash:        contentHash,
		PreviousChunkCount: prevCount,
	}, nil
}

