		return nil, fmt.Errorf("iterate alias rows: %w", err)
	}
	return result, nil
}

var forwardHierarchyVerbs = []string{"classified_as", "extends", "instance_of", "member_of", "part_of", "type_of"}
var reverseHierarchyVerbs = []string{"composed_of", "contains"}

func (s *Store) GetEntityParents(entityNames []string, namespace string) (map[string][2]string, error) {
	if len(entityNames) == 0 {
		return map[string][2]string{}, nil
	}
	conn := s.vector.Conn()
	placeholders := strings.Join(strings.Fields(strings.Repeat("? ", len(entityNames))), ", ")
	fwdVerbs := "'" + strings.Join(forwardHierarchyVerbs, "', '") + "'"
	revVerbs := "'" + strings.Join(reverseHierarchyVerbs, "', '") + "'"
	query := fmt.Sprintf(
		"SELECT child_e.name, parent_e.name, st.verb "+
			"FROM svo_triples st "+
			"JOIN entities child_e ON st.subject_id = child_e.id "+
			"JOIN entities parent_e ON st.object_id = parent_e.id "+
			"WHERE child_e.name IN (%s) AND st.verb IN (%s) AND (st.namespace = ? OR st.namespace IS NULL) "+
			"UNION ALL "+
			"SELECT child_e.name, parent_e.name, st.verb "+
			"FROM svo_triples st "+
			"JOIN entities child_e ON st.object_id = child_e.id "+
			"JOIN entities parent_e ON st.subject_id = parent_e.id "+
			"WHERE child_e.name IN (%s) AND st.verb IN (%s) AND (st.namespace = ? OR st.namespace IS NULL)",
		placeholders, fwdVerbs, placeholders, revVerbs,
	)
	args := make([]interface{}, 0, len(entityNames)*2+2)
	for _, n := range entityNames {
		args = append(args, n)
	}
	args = append(args, namespace)
	for _, n := range entityNames {
		args = append(args, n)
	}
	args = append(args, namespace)
	rows, err := conn.Query(query, args...)
	if err != nil {
		return nil, fmt.Errorf("query entity parents: %w", err)
	}
	defer rows.Close()
	result := make(map[string][2]string)
	for rows.Next() {
		var childName, parentName, verb string
		if err := rows.Scan(&childName, &parentName, &verb); err != nil {
			return nil, fmt.Errorf("scan entity parent row: %w", err)
		}
		if _, exists := result[childName]; !exists {
			result[childName] = [2]string{parentName, verb}
		}
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("iterate entity parent rows: %w", err)
	}
	return result, nil
}

func (s *Store) ResolveDomainIDs(namespaceDomainPairs [][2]string, includeGlobal bool) ([]string, error) {
	domainsTable := "domains"
	if s.vector.IsGlobalAttached() {
		domainsTable = "all_domains"
	}
	pairs := make([][2]string, len(namespaceDomainPairs))
	copy(pairs, namespaceDomainPairs)
	if includeGlobal {
		rows, err := s.vector.Conn().Query(
			fmt.Sprintf("SELECT namespace_id, name FROM %s WHERE namespace_id = ?", domainsTable),
			GlobalNamespace,
		)
		if err != nil {
			return nil, fmt.Errorf("query global domains: %w", err)
		}
		defer rows.Close()
		existing := make(map[[2]string]struct{}, len(pairs))
		for _, p := range pairs {
			existing[p] = struct{}{}
		}
		for rows.Next() {
			var nsID, name string
			if err := rows.Scan(&nsID, &name); err != nil {
				return nil, fmt.Errorf("scan global domain: %w", err)
			}
			p := [2]string{nsID, name}
			if _, ok := existing[p]; !ok {
				pairs = append(pairs, p)
				existing[p] = struct{}{}
			}
		}
		if err := rows.Err(); err != nil {
			return nil, fmt.Errorf("iterate global domains: %w", err)
		}
	}
	if len(pairs) == 0 {
		return []string{}, nil
	}
	valuesPlaceholders := make([]string, len(pairs))
	params := make([]interface{}, 0, len(pairs)*2)
	for i, p := range pairs {
		valuesPlaceholders[i] = "(?, ?)"
		params = append(params, p[0], p[1])
	}
	sql := fmt.Sprintf(`WITH RECURSIVE domain_tree AS (SELECT domain_id FROM %s WHERE (namespace_id, name) IN (VALUES %s) UNION ALL SELECT d.domain_id FROM %s d JOIN domain_tree dt ON d.parent_id = dt.domain_id) SELECT DISTINCT domain_id FROM domain_tree`,
		domainsTable, strings.Join(valuesPlaceholders, ", "), domainsTable)
	resultRows, err := s.vector.Conn().Query(sql, params...)
	if err != nil {
		return nil, fmt.Errorf("resolve domain ids: %w", err)
	}
	defer resultRows.Close()
	var domainIDs []string
	for resultRows.Next() {
		var did string
		if err := resultRows.Scan(&did); err != nil {
			return nil, fmt.Errorf("scan domain id: %w", err)
		}
		domainIDs = append(domainIDs, did)
	}
	if err := resultRows.Err(); err != nil {
		return nil, fmt.Errorf("iterate domain ids: %w", err)
	}
	return domainIDs, nil
}

func (p *PgVectorBackend) GetAllChunks() ([]*DocumentChunk, error) {
	if err := p.ensureConnection(); err != nil {
		return nil, fmt.Errorf("ensure connection: %w", err)
	}
	query := fmt.Sprintf(`SELECT document_name, content, section, chunk_index, source_offset, source_length, breadcrumb, source_detail, chunk_type FROM %s ORDER BY document_name, chunk_index`, p.table)
	rows, err := p.pgconn.Query(query)
	if err != nil {
		return nil, fmt.Errorf("get all chunks query: %w", err)
	}
	defer rows.Close()
	var chunks []*DocumentChunk
	for rows.Next() {
		var docName, content string
		var section *string
		var chunkIdx int
		var srcOff, srcLen *int
		var breadcrumb, srcDetail *string
		var chunkType string
		if err := rows.Scan(&docName, &content, &section, &chunkIdx, &srcOff, &srcLen, &breadcrumb, &srcDetail, &chunkType); err != nil {
			return nil, fmt.Errorf("scan chunk row: %w", err)
		}
		var sectionVal string
		if section != nil {
			sectionVal = *section
		}
		var sourceDetail interface{}
		if srcDetail != nil && len(*srcDetail) > 0 {
			if err := json.Unmarshal([]byte(*srcDetail), &sourceDetail); err != nil {
				return nil, fmt.Errorf("unmarshal source_detail: %w", err)
			}
		}
		embeddingContent := content
		if breadcrumb != nil && len(*breadcrumb) > 0 {
			embeddingContent = fmt.Sprintf("%s\n\n%s", *breadcrumb, content)
		}
		if chunkType == "" {
			chunkType = "document"
		}
		chunks = append(chunks, &DocumentChunk{
			DocumentName:     docName,
			Content:          content,
			Section:          deserializeSection(sectionVal),
			ChunkIndex:       chunkIdx,
			SourceOffset:     srcOff,
			SourceLength:     srcLen,
			Breadcrumb:       breadcrumb,
			EmbeddingContent: embeddingContent,
			SourceDetail:     sourceDetail,
			ChunkType:        chunkType,
		})
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("iterate chunks: %w", err)
	}
	return chunks, nil
}

// CassandraOptions holds optional parameters for NewCassandraCrawler.
// Note: Port defaults to 9042 when zero-value is ambiguous; use PortPtr to distinguish unset.
type CassandraOptions struct {
	Port           int
	Keyspace       *string
	Keyspaces      []string
	Username       *string
	Password       *string
	IncludeViews   bool
	DatasetQueries map[string]string
	EntityQueries  map[string]string
	LocalDC        *string
}

type CassandraCrawler struct {
	contactPoints  []string
	port           int
	keyspaceFilter map[string]struct{}
	username       *string
	password       *string
	includeViews   bool
	datasetQueries map[string]string
	entityQueries  map[string]string
	localDC        *string
	cache          map[string]FetchResult
	tableMeta      []interface{}
	entityVocab    map[string][]string
	knownKeyspaces []string
}

func NewCassandraCrawler(contactPoints []string, opts CassandraOptions) (*CassandraCrawler, error) {
	if len(contactPoints) == 0 {
		return nil, fmt.Errorf("NewCassandraCrawler: contactPoints must not be empty")
	}
	port := opts.Port
	if port == 0 {
		port = 9042
	}
	var ksFilter map[string]struct{}
	if len(opts.Keyspaces) > 0 {
		ksFilter = make(map[string]struct{}, len(opts.Keyspaces))
		for _, k := range opts.Keyspaces {
			ksFilter[k] = struct{}{}
		}
	} else if opts.Keyspace != nil && *opts.Keyspace != "" {
		ksFilter = map[string]struct{}{*opts.Keyspace: {}}
	}
	dq := opts.DatasetQueries
	if dq == nil {
		dq = make(map[string]string)
	}
	eq := opts.EntityQueries
	if eq == nil {
		eq = make(map[string]string)
	}
	return &CassandraCrawler{
		contactPoints:  contactPoints,
		port:           port,
		keyspaceFilter: ksFilter,
		username:       opts.Username,
		password:       opts.Password,
		includeViews:   opts.IncludeViews,
		datasetQueries: dq,
		entityQueries:  eq,
		localDC:        opts.LocalDC,
		cache:          make(map[string]FetchResult),
		tableMeta:      []interface{}{},
		entityVocab:    make(map[string][]string),
		knownKeyspaces: []string{},
	}, nil
}

