def _collect_entity_vocab(self, session: Any) -> None:
        for entity_type, cql in self._entity_queries.items():
            try:
                rows = list(session.execute(cql))
                if not rows:
                    continue
                # First column of each row becomes an entity name
                names = [str(row[0]) for row in rows if row[0] is not None]
                if names:
                    self._entity_vocab[entity_type] = names
                    _log.debug(
                        "CassandraCrawler: entity_query %r → %d names",
                        entity_type, len(names),
                    )
            except Exception as exc:
                _log.warning(
                    "CassandraCrawler: entity_query %r failed: %s", entity_type, exc
                )

func (c *CassandraCrawler) collectEntityVocab(session CassandraSession) {
	for entityType, cql := range c.entityQueries {
		rows, err := session.Execute(cql)
		if err != nil {
			log.Printf("WARN CassandraCrawler: entity_query %q failed: %v", entityType, err)
			continue
		}
		if len(rows) == 0 {
			continue
		}
		var names []string
		for _, row := range rows {
			if len(row) == 0 || row[0] == nil {
				continue
			}
			names = append(names, fmt.Sprintf("%v", row[0]))
		}
		if len(names) > 0 {
			c.entityVocab[entityType] = names
			log.Printf("DEBUG CassandraCrawler: entity_query %q -> %d names", entityType, len(names))
		}
	}
}

