func (d *DatabaseSchemaCrawler) store(schema, name, objType, definition string) {
	if len(d.schemas) > 0 {
		if _, ok := d.schemas[schema]; !ok {
			return
		}
	}
	if strings.TrimSpace(definition) == "" {
		return
	}
	var qualified string
	if schema != "" && schema != "main" {
		qualified = schema + "." + name
	} else {
		qualified = name
	}
	uri := fmt.Sprintf("dbschema://%s/%s/%s", d.urlKey, strings.ToLower(objType), qualified)
	header := fmt.Sprintf("-- %s: %s\n", objType, qualified)
	text := []byte(header + strings.TrimSpace(definition) + "\n")
	mime := "text/x-sql"
	d.cache[uri] = FetchResult{
		Data:         text,
		DetectedMIME: &mime,
		SourcePath:   strPtr(fmt.Sprintf("%s: %s", objType, qualified)),
	}
}

