		log.Printf("WARN DatabaseSchemaCrawler mssql query failed: %v", err)
		return
	}
	typeMap := map[string]mssqlTypeEntry{
		"SQL_STORED_PROCEDURE":              {"PROCEDURE", d.includeProcs},
		"SQL_SCALAR_FUNCTION":               {"FUNCTION", d.includeProcs},
		"SQL_INLINE_TABLE_VALUED_FUNCTION":  {"FUNCTION", d.includeProcs},
		"SQL_TABLE_VALUED_FUNCTION":         {"FUNCTION", d.includeProcs},
		"VIEW":                             {"VIEW", d.includeViews},
		"SQL_TRIGGER":                      {"TRIGGER", d.includeTriggers},
	}
	for _, row := range rows {
		objTypeRaw := strings.TrimSpace(rowStr(row, "object_type", ""))
		entry, ok := typeMap[objTypeRaw]
		if !ok {
