Transform the Python DirectoryCrawler._walk_local method into a Go pointer-receiver method applying R01, R03, R10, R11.

def _walk_local(self, directory: Path, out: list[str]) -> None:
        if len(out) >= self.max_files:
            return
        try:
            entries = sorted(directory.iterdir())
        except PermissionError as exc:
            logger.warning("DirectoryCrawler: permission denied: %s", exc)
            return
        for entry in entries:
            if len(out) >= self.max_files:
                return
            if entry.is_dir():
                if entry.name in self._exclude_dirs or entry.name.startswith("."):
                    continue
                if self.recursive:
                    self._walk_local(entry, out)
            elif entry.is_file() and self._accept(entry):
                out.append(str(entry))

func (d *DirectoryCrawler) walkLocal(directory string, out *[]string) error {
	if len(*out) >= d.maxFiles {
		return nil
	}
	entries, err := os.ReadDir(directory)
	if err != nil {
		if os.IsPermission(err) {
			log.Printf("WARN DirectoryCrawler: permission denied: %v", err)
			return nil
		}
		return fmt.Errorf("DirectoryCrawler: readdir %q: %w", directory, err)
	}
	sort.Slice(entries, func(i, j int) bool { return entries[i].Name() < entries[j].Name() })
	for _, entry := range entries {
		if len(*out) >= d.maxFiles {
			return nil
		}
		name := entry.Name()
		if entry.IsDir() {
			if _, excluded := d.excludeDirs[name]; excluded {
				continue
			}
			if strings.HasPrefix(name, ".") {
				continue
			}
			if d.recursive {
				if err := d.walkLocal(filepath.Join(directory, name), out); err != nil {
					return err
				}
			}
		} else {
			fullPath := filepath.Join(directory, name)
			if d.accept(fullPath) {
				*out = append(*out, fullPath)
			}
		}
	}
	return nil
}

