func (e *ElasticsearchCrawler) walkMapping(props map[string]interface{}, lines *[]string, prefix string) {
	keys := make([]string, 0, len(props))
	for name := range props {
		keys = append(keys, name)
	}
	sort.Strings(keys)
	for _, name := range keys {
		meta, _ := props[name].(map[string]interface{})
		var path string
		if prefix != "" {
			path = prefix + "." + name
		} else {
			path = name
		}
		ftype := "object"
		if t, ok := meta["type"].(string); ok && t != "" {
			ftype = t
		}
		e.knownFields[path] = struct{}{}
		indent := strings.Repeat("  ", strings.Count(path, "."))
		*lines = append(*lines, fmt.Sprintf("  %-48s  %s", indent+path, ftype))
		if subProps, ok := meta["properties"].(map[string]interface{}); ok {
			e.walkMapping(subProps, lines, path)
		}
		if fields, ok := meta["fields"].(map[string]interface{}); ok {
			subNames := make([]string, 0, len(fields))
			for sn := range fields {
				subNames = append(subNames, sn)
			}
			sort.Strings(subNames)
			for _, subname := range subNames {
				submeta, _ := fields[subname].(map[string]interface{})
				subpath := path + "." + subname
				e.knownFields[subpath] = struct{}{}
				subtype := "unknown"
				if st, ok := submeta["type"].(string); ok && st != "" {
					subtype = st
				}
				*lines = append(*lines, fmt.Sprintf("  %s  %-46s  %s  (multi-field)", indent, subpath, subtype))
			}
		}
	}
}

func (f *FtpTransport) Fetch(uri string, opts FetchOptions) (FetchResult, error) {
	parsed, err := url.Parse(uri)
	if err != nil {
		return FetchResult{}, fmt.Errorf("FtpTransport: parse URI %q: %w", uri, err)
	}
	host := parsed.Hostname()
	if host == "" {
		return FetchResult{}, fmt.Errorf("FtpTransport: could not parse host from URI: %q", uri)
	}
	portStr := parsed.Port()
	port := 21
	if portStr != "" {
		port, err = strconv.Atoi(portStr)
		if err != nil {
			return FetchResult{}, fmt.Errorf("FtpTransport: invalid port %q: %w", portStr, err)
		}
	}
	username := "anonymous"
	if parsed.User != nil && parsed.User.Username() != "" {
		username = parsed.User.Username()
	}
	password := ""
	if parsed.User != nil {
		if pw, ok := parsed.User.Password(); ok {
			password = pw
		}
	}
	conn, err := ftp.Dial(fmt.Sprintf("%s:%d", host, port))
	if err != nil {
		return FetchResult{}, fmt.Errorf("FtpTransport: dial %s:%d: %w", host, port, err)
	}
	defer conn.Quit()
	if err := conn.Login(username, password); err != nil {
		return FetchResult{}, fmt.Errorf("FtpTransport: login: %w", err)
	}
	r, err := conn.Retr(parsed.Path)
	if err != nil {
