def _get_realm(self, requests_mod) -> str:
        """Fetch tenant realm GUID from SharePoint WWW-Authenticate header."""
        resp = requests_mod.get(
            f"{self._site_url}/_vti_bin/client.svc",
            headers={"Authorization": "Bearer"},
            timeout=15,
        )
        www_auth = resp.headers.get("WWW-Authenticate", "")
        for part in www_auth.split(","):
            part = part.strip()
            if part.startswith("realm="):
                return part.split("=", 1)[1].strip('"')
        # Fall back to tenant_id if realm auto-discovery fails
        return self._tenant_id or ""

func (s *SharePointCrawler) getRealm(ctx context.Context) (string, error) {
	req, err := http.NewRequestWithContext(ctx, http.MethodGet,
		s.siteURL+"/_vti_bin/client.svc", nil)
	if err != nil {
		return "", fmt.Errorf("SharePointCrawler.getRealm: build request: %w", err)
	}
	req.Header.Set("Authorization", "Bearer")
	resp, err := s.session.Do(req)
	if err != nil {
		return "", fmt.Errorf("SharePointCrawler.getRealm: request: %w", err)
	}
	defer resp.Body.Close()
	wwwAuth := resp.Header.Get("WWW-Authenticate")
	for _, part := range strings.Split(wwwAuth, ",") {
		part = strings.TrimSpace(part)
		if strings.HasPrefix(part, "realm=") {
			realm := strings.SplitN(part, "=", 2)[1]
			return strings.Trim(realm, `"`), nil
		}
	}
	// Fall back to tenantID if realm auto-discovery fails
	if s.tenantID != nil {
		return *s.tenantID, nil
	}
	return "", nil
}

