        parsed = urlparse(uri)
        qs = parse_qs(parsed.query)

        if "sql" in qs:
            sql = unquote_plus(qs["sql"][0])
        if not sql:
            raise ValueError(
                f"SqlQueryTransport: no SQL provided for {uri!r}. "
                "Pass sql= to fetch() or include ?sql=... in the URI."
            )

