func extractLinks(html, baseURL string) []string {
	matches := hrefRE.FindAllStringSubmatch(html, -1)
	seen := make(map[string]struct{})
	var result []string
	base, err := url.Parse(baseURL)
	if err != nil {
		return nil
	}
	for _, m := range matches {
		if len(m) < 2 {
			continue
		}
		href := strings.TrimSpace(m[1])
		if href == "" {
			continue
		}
		if strings.HasPrefix(href, "javascript:") ||
			strings.HasPrefix(href, "mailto:") ||
			strings.HasPrefix(href, "tel:") {
			continue
		}
		ref, err := url.Parse(href)
		if err != nil {
			continue
		}
		resolved := base.ResolveReference(ref)
		if resolved.Scheme != "http" && resolved.Scheme != "https" {
			continue
		}
		ext := ""
		pathBase := resolved.Path
		if idx := strings.LastIndex(pathBase, "/"); idx >= 0 {
			pathBase = pathBase[idx+1:]
		}
		if dotIdx := strings.LastIndex(pathBase, "."); dotIdx >= 0 {
			ext = strings.ToLower(pathBase[dotIdx:])
		}
		if _, isBin := binaryExtensions[ext]; isBin {
			continue
		}
		skip := false
		for _, p := range skipPathPrefixes {
			if strings.HasPrefix(resolved.Path, p) {
				skip = true
				break
			}
		}
		if skip {
			continue
		}
		norm := normalizeURL(resolved.String())
		if _, exists := seen[norm]; !exists {
			seen[norm] = struct{}{}
			result = append(result, resolved.String())
		}
	}
	return result
}

