		name := result.SourcePath
		if name == "" {
			name = "email"
		}
		chunks, err := chunkDocument(name, text, dl.MinChunkSize, dl.MaxChunkSize, dl.OverflowMargin, dl.EnrichContext)
		if err != nil {
			log.Printf("load_imap: skipping message %s: %v", result.SourcePath, err)
			continue
		}
		enriched, err := dl.enrich(chunks)
		if err != nil {
			log.Printf("load_imap: enrich error %s: %v", result.SourcePath, err)
