// StoreAdapter wraps a backend so BuildNER receives a .Vector field.
type StoreAdapter struct {
	Vector interface{}
}

// processQueueJob loads sourceURI, embeds chunks, writes to backend, and optionally runs NER.
func processQueueJob(
	backend Backend,
	sourceURI string,
	namespace string,
	embedModel string,
	batchSize int,
	runNER bool,
	spacyModel string,
) error {
	log := slog.Default()
	loader := NewDocumentLoader()
	chunks, err := loader.Load(sourceURI)
	if err != nil {
		return fmt.Errorf("failed to load %q: %w", sourceURI, err)
	}
	if len(chunks) == 0 {
		log.Warn("no chunks produced", "source_uri", sourceURI)
		return nil
	}
	var sb strings.Builder
	for i, c := range chunks {
		if i > 0 {
			sb.WriteByte('\n')
		}
		sb.WriteString(c.Content)
	}
	h := sha256.Sum256([]byte(sb.String()))
	contentHash := fmt.Sprintf("%x", h)[:32]
	texts := make([]string, len(chunks))
	for i, c := range chunks {
		texts[i] = c.Content
	}
	emb, err := embedTexts(texts, embedModel, batchSize)
	if err != nil {
		return fmt.Errorf("embed: %w", err)
	}
	if err := backend.AddChunks(chunks, emb, namespace); err != nil {
		return fmt.Errorf("add_chunks: %w", err)
	}
	if err := backend.RegisterDocument(chunks[0].DocumentName, contentHash, sourceURI, len(chunks)); err != nil {
		return fmt.Errorf("register_document: %w", err)
	}
	if runNER {
		adapter := &StoreAdapter{Vector: backend}
		if err := BuildNER(adapter, spacyModel); err != nil {
			return fmt.Errorf("ner: %w", err)
		}
	}
	return nil
}

// WorkerConfig holds optional parameters for RunWorker.
type WorkerConfig struct {
	EmbedModel string
	BatchSize  int
	RunNER     bool
	SpacyModel string
	IdleSleep  time.Duration
}

// RunWorker pulls jobs from ingest_queue and processes them until interrupted.
func RunWorker(queueDSN, backendDSN string, cfg WorkerConfig) error {
	log := slog.Default()
	hostname, _ := os.Hostname()
	workerID := fmt.Sprintf("%s:%s", hostname, randHex(8))
	log.Info("worker starting", "worker_id", workerID)
	backend, err := NewPgVectorBackend(backendDSN)
	if err != nil {
		return fmt.Errorf("backend: %w", err)
	}
	for {
		paused, err := workersPaused(queueDSN)
		if err != nil {
			return err
		}
		if paused {
			time.Sleep(cfg.IdleSleep)
			continue
		}
		jobID, sourceURI, namespace, found, err := claimNextJob(queueDSN, workerID)
		if err != nil {
			return err
		}
		if !found {
			time.Sleep(cfg.IdleSleep)
			continue
		}
		log.Info("processing job", "worker_id", workerID, "job_id", jobID, "source_uri", sourceURI)
		processErr := processQueueJob(backend, sourceURI, namespace, cfg.EmbedModel, cfg.BatchSize, cfg.RunNER, cfg.SpacyModel)
		if processErr != nil {
			log.Error("job failed", "job_id", jobID, "error", processErr)
			if err := setJobStatus(queueDSN, jobID, "failed"); err != nil {
				return err
			}
		} else {
			if err := setJobStatus(queueDSN, jobID, "done"); err != nil {
				return err
			}
			log.Info("job done", "job_id", jobID)
		}
	}
}

// CoordinatorConfig holds optional parameters for RunCoordinator.
type CoordinatorConfig struct {
	GraphInterval        int
	EmbedModel           string
	SpacyModel           string
	CommunityAlpha       float64
	CommunitySimThreshold float64
	LeaseTimeoutMinutes  int
	PollSleep            time.Duration
}

// RunCoordinator implements the DISPATCHING→DRAINING→BUILDING state machine.
func RunCoordinator(queueDSN, backendDSN string, cfg CoordinatorConfig) error {
	log := slog.Default()
	log.Info(fmt.Sprintf("coordinator starting (graph_interval=%ds)", cfg.GraphInterval))
	state := "DISPATCHING"
	var lastGraphBuild time.Time
	for {
		if state == "DISPATCHING" {
			if err := requeueStaleLeases(queueDSN, cfg.LeaseTimeoutMinutes); err != nil {
				return err
			}
			pending, err := queuePendingCount(queueDSN)
			if err != nil {
				return err
			}
			queueEmpty := pending == 0
			intervalElapsed := time.Since(lastGraphBuild) >= time.Duration(cfg.GraphInterval)*time.Second
			if queueEmpty || intervalElapsed {
				log.Info(fmt.Sprintf("transitioning DISPATCHING->DRAINING (queue_empty=%v, interval_elapsed=%v)", queueEmpty, intervalElapsed))
				state = "DRAINING"
			}
		} else if state == "DRAINING" {
			processing, err := queueProcessingCount(queueDSN)
			if err != nil {
				return err
			}
			if processing == 0 {
				log.Info("all workers drained; transitioning->BUILDING")
				state = "BUILDING"
			}
		} else if state == "BUILDING" {
			if err := setControl(queueDSN, "workers_paused", "1"); err != nil {
				return err
			}
			log.Info("workers paused; starting graph build")
			buildErr := runGraphBuild(backendDSN, cfg.EmbedModel, cfg.CommunityAlpha, cfg.CommunitySimThreshold)
			if buildErr != nil {
				log.Error("graph build failed", "error", buildErr)
			}
			if err := setControl(queueDSN, "workers_paused", "0"); err != nil {
				return err
			}
			log.Info("workers unpaused")
			lastGraphBuild = time.Now()
			state = "DISPATCHING"
		}
		time.Sleep(cfg.PollSleep)
	}
}

// requeueStaleLeases resets processing jobs whose lease has expired back to pending.
func requeueStaleLeases(dsn string, timeoutMinutes int) error {
	db, err := pgConnect(dsn)
	if err != nil {
		return err
	}
	defer db.Close()
	result, err := db.Exec(
		fmt.Sprintf(`UPDATE ingest_queue
			SET status = 'pending', worker_id = NULL, leased_at = NULL
			WHERE status = 'processing'
			  AND leased_at < now() - interval '%d minutes'`, timeoutMinutes),
	)
	if err != nil {
		return fmt.Errorf("requeue stale leases: %w", err)
	}
	count, err := result.RowsAffected()
	if err != nil {
		return fmt.Errorf("rows affected: %w", err)
	}
	if count != 0 {
		slog.Warn("requeued stale leases", "count", count)
	}
	return nil
}

// runGraphBuild fetches all namespaces from PG and runs community detection per namespace.
func runGraphBuild(backendDSN, embedModel string, alpha, simThreshold float64) error {
	log := slog.Default()
	pg, err := NewPgVectorBackend(backendDSN)
	if err != nil {
		return fmt.Errorf("pg backend: %w", err)
	}
	defer pg.Close()
	namespaceRows, err := pg.Conn.Query("SELECT DISTINCT namespace FROM embeddings WHERE namespace IS NOT NULL")
	if err != nil {
		return fmt.Errorf("query namespaces: %w", err)
	}
	var namespaces []string
	for namespaceRows.Next() {
		var ns string
		if err := namespaceRows.Scan(&ns); err != nil {
			return err
		}
		namespaces = append(namespaces, ns)
	}
	namespaceRows.Close()
	if len(namespaces) == 0 {
		log.Info("no namespaces found; skipping graph build")
		return nil
	}
	for _, ns := range namespaces {
		log.Info("building community graph", "namespace", ns)
		chunkRows, err := pg.Conn.Query(
			"SELECT chunk_id, document_name, content, section, chunk_index, "+
				"breadcrumb, chunk_type, source_offset, source_length, "+
				"source_detail, source_id, domain_id, embedding "+
				"FROM embeddings WHERE namespace = $1", ns,
		)
		if err != nil {
			return fmt.Errorf("query chunks for ns %s: %w", ns, err)
		}
