		for chunkRows.Next() {
			var r chunkRow
			if err := chunkRows.Scan(&r.ChunkID, &r.DocName, &r.Content, &r.SectionStr,
				&r.ChunkIdx, &r.Breadcrumb, &r.ChunkType, &r.SrcOff, &r.SrcLen,
				&r.SrcDetStr, &r.SrcID, &r.DomID, &r.EmbeddingVec); err != nil {
				return err
			}
			rows = append(rows, r)
		}
		chunkRows.Close()
		if len(rows) == 0 {
			continue
		}
		tmpFile, err := os.CreateTemp("", "*.duckdb")
		if err != nil {
			return fmt.Errorf("temp file: %w", err)
		}
		tmpPath := tmpFile.Name()
		tmpFile.Close()
		var tmpChunks []DocumentChunk
		var tmpEmbeddings [][]float32
		for _, row := range rows {
			var sec []string
			if row.SectionStr != "" {
				if err := json.Unmarshal([]byte(row.SectionStr), &sec); err != nil {
					return err
				}
			}
			chunkType := row.ChunkType
			if chunkType == "" {
				chunkType = "document"
			}
			tmpChunks = append(tmpChunks, DocumentChunk{
				DocumentName: row.DocName, Content: row.Content,
				Section: sec, ChunkIndex: row.ChunkIdx,
				Breadcrumb: row.Breadcrumb, ChunkType: chunkType,
				SourceOffset: row.SrcOff, SourceLength: row.SrcLen,
			})
			tmpEmbeddings = append(tmpEmbeddings, row.EmbeddingVec)
		}
		tmpStore, err := NewStore(tmpPath, pg.EmbeddingDim)
		if err != nil {
			return fmt.Errorf("tmp store: %w", err)
		}
		if err := tmpStore.AddDocument(tmpChunks, tmpEmbeddings, ns, ""); err != nil {
			tmpStore.Close()
			return err
		}
		n, err := BuildCommunity(tmpPath, embedModel, alpha, simThreshold, true)
		tmpStore.Close()
