        for a in range(len(idxs)):
            for b in range(a + 1, len(idxs)):
                ia, ib = idxs[a], idxs[b]
                doc_a = chunk_ids_list[ia].rsplit("_", 2)[0]
                doc_b = chunk_ids_list[ib].rsplit("_", 2)[0]
                if doc_a != doc_b:
                    key = (min(ia, ib), max(ia, ib))
                    if key not in seen:
                        seen.add(key)
                        extra_edges.append((ia, ib, 1.0))

    return extra_edges

type Edge struct {
	A, B   int
	Weight float64
}

type edgeKey struct{ a, b int }

func loadEntityEdges(conn *sql.DB, rows [][]interface{}) ([]Edge, error) {
	ceRows, err := conn.Query("SELECT entity_id, chunk_id FROM chunk_entities WHERE frequency > 0")
	if err != nil {
		return nil, fmt.Errorf("loadEntityEdges query: %w", err)
	}
	defer ceRows.Close()

	type ceRow struct{ entityID, chunkID string }
	var ceData []ceRow
	for ceRows.Next() {
		var r ceRow
		if err := ceRows.Scan(&r.entityID, &r.chunkID); err != nil {
			return nil, fmt.Errorf("loadEntityEdges scan: %w", err)
		}
		ceData = append(ceData, r)
	}
	if len(ceData) == 0 {
		return nil, nil
	}

	chunkIDsList := make([]string, len(rows))
	for i, r := range rows {
		chunkIDsList[i] = r[0].(string)
	}
	idToIdx := make(map[string]int, len(chunkIDsList))
	for i, cid := range chunkIDsList {
		idToIdx[cid] = i
	}

	entityToChunks := make(map[string][]int)
	for _, r := range ceData {
		if idx, ok := idToIdx[r.chunkID]; ok {
			entityToChunks[r.entityID] = append(entityToChunks[r.entityID], idx)
		}
	}

	var extraEdges []Edge
	seen := make(map[edgeKey]struct{})
	for _, idxs := range entityToChunks {
		if len(idxs) < 2 {
			continue
		}
		for a := 0; a < len(idxs); a++ {
			for b := a + 1; b < len(idxs); b++ {
				ia, ib := idxs[a], idxs[b]
				docA := rsplitN(chunkIDsList[ia], "_", 3)[0]
				docB := rsplitN(chunkIDsList[ib], "_", 3)[0]
				if docA != docB {
					lo, hi := ia, ib
					if lo > hi {
						lo, hi = hi, lo
					}
					key := edgeKey{lo, hi}
					if _, exists := seen[key]; !exists {
						seen[key] = struct{}{}
						extraEdges = append(extraEdges, Edge{ia, ib, 1.0})
					}
				}
			}
		}
	}
	return extraEdges, nil
}

type BuildCommunityOptions struct {
	NamespaceID  *string
	Alpha        float64
	SimThreshold float64
	Force        bool
}

func buildCommunity(dbPath string, embedModel interface{}, opts BuildCommunityOptions) (int, error) {
	if opts.Alpha == 0 {
		opts.Alpha = 0.2
	}
	if opts.SimThreshold == 0 {
		opts.SimThreshold = 0.6
	}

	if !opts.Force {
		n, err := checkExistingCount(dbPath)
		if err != nil {
			return 0, fmt.Errorf("buildCommunity check: %w", err)
		}
		if n > 0 {
			return n, nil
		}
	}

	rows, con, err := loadChunks(dbPath, opts.NamespaceID)
	if err != nil {
		return 0, fmt.Errorf("buildCommunity loadChunks: %w", err)
	}
	extraEdges, err := loadEntityEdges(con, rows)
	con.Close()
	if err != nil {
		return 0, fmt.Errorf("buildCommunity loadEntityEdges: %w", err)
	}

	if len(rows) == 0 {
		return 0, nil
	}

	chunkIDs := make([]string, len(rows))
	chunkTexts := make([]string, len(rows))
	breadcrumbs := make([]string, len(rows))
	contentVecs := make([][]float32, len(rows))
	for i, r := range rows {
		chunkIDs[i] = r[0].(string)
		s, _ := r[1].(string)
		chunkTexts[i] = s
		b, _ := r[2].(string)
		breadcrumbs[i] = b
		contentVecs[i] = r[3].([]float32)
	}

	headingVecs, err := embedBreadcrumbs(breadcrumbs, embedModel)
	if err != nil {
		return 0, fmt.Errorf("buildCommunity embedBreadcrumbs: %w", err)
	}

	var ee []Edge
	if len(extraEdges) > 0 {
		ee = extraEdges
	}
	idx, err := communityIndexBuild(chunkIDs, contentVecs, chunkTexts, headingVecs, opts.Alpha, opts.SimThreshold, ee)
	if err != nil {
		return 0, fmt.Errorf("buildCommunity index build: %w", err)
	}

	if err := idx.Persist(dbPath); err != nil {
		return 0, fmt.Errorf("buildCommunity persist: %w", err)
	}
	return idx.CommunityCount(), nil
}

func (b *CommunityIndexBuilder) Build(
	chunkIDs []string,
	contentVecs [][]float32,
	onComplete func(*CommunityIndex),
	kwargs BuildKwargs,
) {
	go func() {
		idx, err := CommunityIndexBuild(chunkIDs, contentVecs, kwargs)
		if err != nil {
			log.Printf("CommunityIndexBuilder background build failed: %v", err)
			return
		}
		newVersion := b.ref.Update(idx)
		log.Printf("CommunityIndex version %d ready (%d levels, %d chunks)",
			newVersion, idx.LevelCount(), idx.ChunkCount())
		if onComplete != nil {
			onComplete(idx)
		}
	}()
}

