func runPartition(
	n int,
	edges []Edge,
	algorithm string,
	resolution float64,
	nIterations int,
	seed *int,
) (map[int]int, error) {
	var partition map[int]int

	if algorithm == "leiden" {
		p, err := runLeiden(n, edges, resolution, nIterations, seed)
		if err != nil {
			return nil, fmt.Errorf("runPartition leiden: %w", err)
		}
		partition = p
	}

	if partition == nil {
		p, err := runLouvain(n, edges, seed)
		if err != nil {
			return nil, fmt.Errorf("runPartition louvain: %w", err)
		}
		partition = p
	}

	if len(partition) == 0 {
		partition = make(map[int]int, n)
		for i := 0; i < n; i++ {
			partition[i] = i
		}
	}

	return partition, nil
}

func assignLabels(
