func computeCoherence(
	levelData *LevelData,
	communityMembers map[int][]int,
	vecs [][]float32,
) {
	for cid, indices := range communityMembers {
		if len(indices) < 2 {
			levelData.CommunityToCoherence[cid] = 0.0
			continue
		}
		var upper []float64
		for i := 0; i < len(indices); i++ {
			for j := i + 1; j < len(indices); j++ {
				ia, ib := indices[i], indices[j]
				var dot float64
				for k := range vecs[ia] {
					dot += float64(vecs[ia][k]) * float64(vecs[ib][k])
				}
				upper = append(upper, dot)
			}
		}
		if len(upper) > 0 {
			var sum float64
			for _, v := range upper {
				sum += v
			}
			levelData.CommunityToCoherence[cid] = sum / float64(len(upper))
		} else {
			levelData.CommunityToCoherence[cid] = 0.0
		}
	}
}

