	}
	chunkRows.Close()

	commRows, err := conn.Query("SELECT community_id, level, topic_label, coherence, resolution FROM communities ORDER BY level")
	if err != nil {
		return fmt.Errorf("loadMultilevelSchema communities: %w", err)
	}
	defer commRows.Close()

	type commRow struct {
		commID     int
		level      int
		label      string
		coherence  float64
		resolution float64
	}
	var comms []commRow
	for commRows.Next() {
		var r commRow
		if err := commRows.Scan(&r.commID, &r.level, &r.label, &r.coherence, &r.resolution); err != nil {
