		}
		comms = append(comms, r)
	}

	levelsByIdx := make(map[int]*LevelData)
	for _, r := range chunks {
		if _, ok := levelsByIdx[r.level]; !ok {
			levelsByIdx[r.level] = NewLevelData(1.0)
		}
		ld := levelsByIdx[r.level]
		ld.ChunkToCommunity[r.chunkID] = r.commID
		ld.CommunityToChunks[r.commID] = append(ld.CommunityToChunks[r.commID], r.chunkID)
	}

	for _, r := range comms {
		res := r.resolution
		if res == 0 {
			res = 1.0
		}
		if _, ok := levelsByIdx[r.level]; !ok {
			levelsByIdx[r.level] = NewLevelData(res)
