def persist(self, db_path) -> None:
    import duckdb
    con = duckdb.connect(str(db_path))

    con.execute("DROP TABLE IF EXISTS chunk_communities")
    con.execute("DROP TABLE IF EXISTS communities")
    con.execute(
        "CREATE TABLE chunk_communities "
        "(chunk_id TEXT, level INTEGER, community_id INTEGER, "
        "PRIMARY KEY (chunk_id, level))"
    )
    con.execute(
        "CREATE TABLE communities "
        "(community_id INTEGER, level INTEGER, topic_label TEXT, "
        "size INTEGER, coherence REAL, resolution REAL, "
        "PRIMARY KEY (community_id, level))"
    )

    if self._levels:
        for level_idx, ld in enumerate(self._levels):
            for chunk_id, cid in ld.chunk_to_community.items():
                con.execute(
                    "INSERT INTO chunk_communities VALUES (?, ?, ?)",
                    [chunk_id, level_idx, cid],
                )
            for cid, label in ld.community_to_label.items():
                size = len(ld.community_to_chunks.get(cid, []))
                coherence = ld.community_to_coherence.get(cid, 0.0)
                con.execute(
                    "INSERT INTO communities VALUES (?, ?, ?, ?, ?, ?)",
                    [cid, level_idx, label, size, coherence, ld.resolution],
                )
    else:
        for chunk_id, cid in self._chunk_to_community.items():
            con.execute(
                "INSERT INTO chunk_communities VALUES (?, ?, ?)",
                [chunk_id, 0, cid],
            )
        for cid, label in self._community_to_label.items():
            size = len(self._community_to_chunks.get(cid, []))
            coherence = self._community_to_coherence.get(cid, 0.0)
            con.execute(
                "INSERT INTO communities VALUES (?, ?, ?, ?, ?, ?)",
                [cid, 0, label, size, coherence, 1.0],
            )

    con.close()

func (ci *CommunityIndex) Persist(dbPath string) error {
	db, err := sql.Open("duckdb", dbPath)
	if err != nil {
		return fmt.Errorf("CommunityIndex.Persist open: %w", err)
	}
	defer db.Close()

	for _, ddl := range []string{
		"DROP TABLE IF EXISTS chunk_communities",
		"DROP TABLE IF EXISTS communities",
		"CREATE TABLE chunk_communities (chunk_id TEXT, level INTEGER, community_id INTEGER, PRIMARY KEY (chunk_id, level))",
		"CREATE TABLE communities (community_id INTEGER, level INTEGER, topic_label TEXT, size INTEGER, coherence REAL, resolution REAL, PRIMARY KEY (community_id, level))",
	} {
		if _, err := db.Exec(ddl); err != nil {
			return fmt.Errorf("CommunityIndex.Persist DDL: %w", err)
		}
	}

	if len(ci.levels) > 0 {
		for levelIdx, ld := range ci.levels {
			for chunkID, cid := range ld.ChunkToCommunity {
				if _, err := db.Exec("INSERT INTO chunk_communities VALUES (?, ?, ?)", chunkID, levelIdx, cid); err != nil {
					return fmt.Errorf("CommunityIndex.Persist insert chunk_communities: %w", err)
				}
			}
			for cid, label := range ld.CommunityToLabel {
				size := len(ld.CommunityToChunks[cid])
				coherence := ld.CommunityToCoherence[cid]
				if _, err := db.Exec("INSERT INTO communities VALUES (?, ?, ?, ?, ?, ?)", cid, levelIdx, label, size, coherence, ld.Resolution); err != nil {
					return fmt.Errorf("CommunityIndex.Persist insert communities: %w", err)
				}
			}
		}
	} else {
		for chunkID, cid := range ci.chunkToCommunity {
			if _, err := db.Exec("INSERT INTO chunk_communities VALUES (?, ?, ?)", chunkID, 0, cid); err != nil {
				return fmt.Errorf("CommunityIndex.Persist insert flat chunk_communities: %w", err)
			}
		}
		for cid, label := range ci.communityToLabel {
			size := len(ci.communityToChunks[cid])
			coherence := ci.communityToCoherence[cid]
			if _, err := db.Exec("INSERT INTO communities VALUES (?, ?, ?, ?, ?, ?)", cid, 0, label, size, coherence, 1.0); err != nil {
				return fmt.Errorf("CommunityIndex.Persist insert flat communities: %w", err)
			}
		}
	}
	return nil
}

func (cs *CommunitySummarizer) SummarizeAll(
	communityIndex *CommunityIndex,
	getChunkText func(string) *string,
	minChunks int,
	level *int,
) ([]*DocumentChunk, error) {
	var results []*DocumentChunk
	for _, cid := range communityIndex.CommunityIDs(level) {
		chunkIDs := communityIndex.CommunityChunks(cid, level)
		if len(chunkIDs) < minChunks {
			continue
		}
		var texts []string
		for _, cid2 := range chunkIDs {
			t := getChunkText(cid2)
			if t != nil {
				texts = append(texts, *t)
			}
		}
		if len(texts) == 0 {
			continue
		}
		label := communityIndex.TopicLabelForCommunity(cid, level)
		var docCommunityID string
		if level != nil {
			docCommunityID = fmt.Sprintf("%d:%d", *level, cid)
		} else {
			docCommunityID = fmt.Sprintf("%d", cid)
		}
		chunk, err := cs.Summarize(docCommunityID, texts, SummarizeOptions{TopicLabel: label})
		if err != nil {
			return nil, fmt.Errorf("SummarizeAll: %w", err)
		}
		if chunk != nil {
			results = append(results, chunk)
		}
	}
	return results, nil
}

