		chunkIDs = append(chunkIDs, cid)
	}
	rows.Close()

	if len(chunkIDs) > 0 {
		placeholders := strings.Repeat("?,", len(chunkIDs))
		placeholders = placeholders[:len(placeholders)-1]
		args := make([]interface{}, len(chunkIDs))
		for i, id := range chunkIDs {
			args[i] = id
		}
		if _, err := conn.Exec(fmt.Sprintf("DELETE FROM chunk_entities WHERE chunk_id IN (%s)", placeholders), args...); err != nil {
			log.Printf("DELETE chunk_entities failed: %v", err)
			return 0, fmt.Errorf("DeleteDomain chunk_entities: %w", err)
		}
		if _, err := conn.Exec(fmt.Sprintf("DELETE FROM svo_triples WHERE chunk_id IN (%s)", placeholders), args...); err != nil {
