class _Index:
    """Pre-built lookup tables over a STIX bundle."""

    def __init__(self, objects: list[dict]) -> None:
        self.by_id: dict[str, dict] = {o["id"]: o for o in objects if "id" in o}

        # course-of-action id → mitigation dict
        self.mitigations: dict[str, dict] = {
            o["id"]: o for o in objects if o.get("type") == "course-of-action" and _is_live(o)
        }

        # attack-pattern id → list[mitigation dict]
        self.tech_mitigations: dict[str, list[dict]] = {}
        # attack-pattern id → parent attack-pattern id (for sub-techniques)
        self.parent: dict[str, str] = {}

        for rel in objects:
            if rel.get("type") != "relationship":
                continue
            rtype = rel.get("relationship_type", "")
            src, tgt = rel.get("source_ref", ""), rel.get("target_ref", "")

            if rtype == "mitigates" and src in self.mitigations:
                self.tech_mitigations.setdefault(tgt, []).append(self.mitigations[src])
            elif rtype == "subtechnique-of":
                self.parent[src] = tgt

// Index holds pre-built lookup tables over a STIX bundle.
type Index struct {
	ByID           map[string]map[string]interface{}
	Mitigations    map[string]map[string]interface{}
	TechMitigations map[string][]map[string]interface{}
	Parent         map[string]string
}

// NewIndex constructs an Index from a slice of STIX bundle objects.
func NewIndex(objects []map[string]interface{}) *Index {
	idx := &Index{
		ByID:            make(map[string]map[string]interface{}),
		Mitigations:     make(map[string]map[string]interface{}),
		TechMitigations: make(map[string][]map[string]interface{}),
		Parent:          make(map[string]string),
	}

	for _, o := range objects {
		id, _ := o["id"].(string)
		if id != "" {
			idx.ByID[id] = o
		}
	}

	for _, o := range objects {
		if o["type"] == "course-of-action" && isLive(o) {
			id, _ := o["id"].(string)
			if id != "" {
				idx.Mitigations[id] = o
			}
		}
	}

	for _, rel := range objects {
		if rel["type"] != "relationship" {
			continue
		}
		rtype, _ := rel["relationship_type"].(string)
		src, _ := rel["source_ref"].(string)
		tgt, _ := rel["target_ref"].(string)

		if rtype == "mitigates" {
			if _, ok := idx.Mitigations[src]; ok {
				idx.TechMitigations[tgt] = append(idx.TechMitigations[tgt], idx.Mitigations[src])
			}
		} else if rtype == "subtechnique-of" {
			idx.Parent[src] = tgt
		}
	}

	return idx
}

