class CsvExtractor:
    HANDLED = {"csv", "tsv"}

    def extract(self, data: bytes, source_path: str | None = None) -> str:
        try:
            text = data.decode("utf-8")
        except UnicodeDecodeError:
            text = data.decode("latin-1")

        # Sniff dialect; fall back to excel (standard CSV)
        try:
            dialect = csv.Sniffer().sniff(text[:4096], delimiters=",\t|;")
        except csv.Error:
            dialect = csv.excel

        reader = csv.reader(io.StringIO(text), dialect)
        rows = [row for row in reader if any(cell.strip() for cell in row)]
        if not rows:
            return ""

        headers = rows[0]
        body = rows[1:]

        def _cell(value: str) -> str:
            return value.replace("|", "\\|").replace("\n", " ").strip()

        header_row = "| " + " | ".join(_cell(h) for h in headers) + " |"
        sep_row = "| " + " | ".join("---" for _ in headers) + " |"
        data_rows = ["| " + " | ".join(_cell(c) for c in row) + " |" for row in body]

        return "\n".join([header_row, sep_row] + data_rows)

// CsvExtractor extracts CSV/TSV files into markdown tables.
type CsvExtractor struct{}

// cellEscape escapes pipe characters and strips newlines for markdown table cells.
func cellEscape(value string) string {
	value = strings.ReplaceAll(value, "|", "\\|")
	value = strings.ReplaceAll(value, "\n", " ")
	return strings.TrimSpace(value)
}

// Extract decodes CSV/TSV bytes and returns a markdown table string.
func (e *CsvExtractor) Extract(data []byte, sourcePath *string) (string, error) {
