var cvssKeys = []string{"cvssMetricV40", "cvssMetricV31", "cvssMetricV30", "cvssMetricV2"}

// bestCVSS returns the highest-priority CVSS base score and severity from an
// NVD metrics map. Both return values are nil when no score is found.
func bestCVSS(metrics map[string]interface{}) (*float64, *string) {
	for _, key := range cvssKeys {
		entries, _ := metrics[key].([]interface{})
		for _, item := range entries {
			entry, ok := item.(map[string]interface{})
			if !ok {
				continue
			}
			data, _ := entry["cvssData"].(map[string]interface{})
			scoreRaw, hasScore := data["baseScore"]
			if !hasScore || scoreRaw == nil {
				continue
			}
			var score float64
			switch v := scoreRaw.(type) {
			case float64:
				score = v
			case float32:
				score = float64(v)
			default:
				continue
			}
			severity := firstNonEmpty(
				strGetDef(data, "baseSeverity", ""),
				strGetDef(entry, "baseSeverity", ""),
				strGetDef(entry, "severity", ""),
			)
			sev := strings.ToUpper(severity)
			var sevPtr *string
			if sev != "" {
				sevPtr = &sev
			}
			return &score, sevPtr
		}
	}
	return nil, nil
}

