def _cpe_readable(criteria: str, match: dict) -> str:
    parts = criteria.split(":")
    base = ""
    if len(parts) >= 6:
        vendor = parts[3].replace("_", " ")
        product = parts[4].replace("_", " ")
        base = f"{vendor}/{product}"
    else:
        base = criteria

    ranges = []
    if match.get("versionStartIncluding"):
        ranges.append(f">= {match['versionStartIncluding']}")
    if match.get("versionStartExcluding"):
        ranges.append(f"> {match['versionStartExcluding']}")
    if match.get("versionEndIncluding"):
        ranges.append(f"<= {match['versionEndIncluding']}")
    if match.get("versionEndExcluding"):
        ranges.append(f"< {match['versionEndExcluding']}")

    if ranges:
        return f"{base} ({', '.join(ranges)})"
    version = parts[5] if len(parts) >= 6 and parts[5] != "*" else ""
    return f"{base} {version}".strip()

// cpeReadable converts a CPE criteria string and version-range match map into a
// human-readable vendor/product string with optional version ranges.
func cpeReadable(criteria string, match map[string]interface{}) string {
	parts := strings.Split(criteria, ":")
	var base string
	if len(parts) >= 6 {
		vendor := strings.ReplaceAll(parts[3], "_", " ")
		product := strings.ReplaceAll(parts[4], "_", " ")
		base = fmt.Sprintf("%s/%s", vendor, product)
	} else {
		base = criteria
	}

	var ranges []string
	if v := strGetDef(match, "versionStartIncluding", ""); v != "" {
		ranges = append(ranges, fmt.Sprintf(">= %s", v))
	}
	if v := strGetDef(match, "versionStartExcluding", ""); v != "" {
		ranges = append(ranges, fmt.Sprintf("> %s", v))
	}
	if v := strGetDef(match, "versionEndIncluding", ""); v != "" {
		ranges = append(ranges, fmt.Sprintf("<= %s", v))
	}
	if v := strGetDef(match, "versionEndExcluding", ""); v != "" {
		ranges = append(ranges, fmt.Sprintf("< %s", v))
	}

	if len(ranges) > 0 {
		return fmt.Sprintf("%s (%s)", base, strings.Join(ranges, ", "))
	}
	version := ""
	if len(parts) >= 6 && parts[5] != "*" {
		version = parts[5]
	}
	return strings.TrimSpace(fmt.Sprintf("%s %s", base, version))
}

