// headingFrame tracks one level of heading context.
type headingFrame struct {
	Level  int
	Anchor string
	Text   string
}

// sectionAnchor stores the resolved anchor and heading path for one heading.
type sectionAnchor struct {
	Anchor string
	Path   []string
}

// segment stores one markdown segment with its heading context.
type segment struct {
	Anchor string
	Path   []string
	Text   string
}

// Annotate attaches heading path and anchor source_detail to matching chunks.
func (e *HtmlExtractor) Annotate(chunks []*Chunk, data []byte) []*Chunk {
	html := string(data)

	scanner := newHeadingScanner()
	scanner.Feed(html)
	if len(scanner.Records) == 0 {
		return chunks
	}

	headingStack := []headingFrame{}
	sectionAnchors := []sectionAnchor{}
	for _, rec := range scanner.Records {
		level, anchor, text := rec.Level, rec.Anchor, rec.Text
		filtered := []headingFrame{}
		for _, f := range headingStack {
			if f.Level < level {
				filtered = append(filtered, f)
			}
		}
		headingStack = append(filtered, headingFrame{Level: level, Anchor: anchor, Text: text})
		path := make([]string, 0, len(headingStack))
		for _, f := range headingStack {
			path = append(path, f.Text)
		}
		topAnchor := ""
		for i := len(headingStack) - 1; i >= 0; i-- {
			if headingStack[i].Anchor != "" {
				topAnchor = headingStack[i].Anchor
				break
			}
		}
		sectionAnchors = append(sectionAnchors, sectionAnchor{Anchor: topAnchor, Path: path})
	}

	markdown := convertHTMLToMarkdown(html)
	headingIdx := 0
	segments := []segment{}
	currentAnchor := ""
	currentPath := []string{}
	currentBuf := []string{}

	headingRE := regexp.MustCompile(`^(#{1,6})\s+(.*)`)
	for _, line := range strings.Split(markdown, "\n") {
		if headingRE.MatchString(line) && headingIdx < len(sectionAnchors) {
			if len(currentBuf) > 0 {
				segments = append(segments, segment{Anchor: currentAnchor, Path: currentPath, Text: strings.Join(currentBuf, "\n")})
			}
			currentAnchor = sectionAnchors[headingIdx].Anchor
			currentPath = sectionAnchors[headingIdx].Path
			headingIdx++
			currentBuf = []string{line}
		} else {
			currentBuf = append(currentBuf, line)
		}
	}
	if len(currentBuf) > 0 {
		segments = append(segments, segment{Anchor: currentAnchor, Path: currentPath, Text: strings.Join(currentBuf, "\n")})
	}

	for _, chunk := range chunks {
		content := chunk.Content
		for _, seg := range segments {
			matched := false
			for _, frag := range strings.Split(content, "\n") {
				if len(strings.TrimSpace(frag)) > 20 && strings.Contains(seg.Text, frag) {
					matched = true
					break
				}
			}
			if matched {
				detail := map[string]interface{}{"heading_path": seg.Path}
				if seg.Anchor != "" {
					detail["anchor"] = seg.Anchor
				}
				chunk.SourceDetail = detail
				break
			}
		}
	}
	return chunks
}

