	case tag == "h1" || tag == "h2" || tag == "h3" || tag == "h4" || tag == "h5" || tag == "h6":
		m.output = append(m.output, "\n\n")
	case tag == "p":
		if !m.inCell {
			m.output = append(m.output, "\n\n")
		}
	case tag == "br":
		if m.inCell {
			m.cellBuf = append(m.cellBuf, " ")
		} else {
