		}
	case tag == "pre":
		m.inPre = true
		m.output = append(m.output, "\n\n```\n")
	case tag == "ul":
		m.listStack = append(m.listStack, "ul")
	case tag == "ol":
		m.listStack = append(m.listStack, "ol")
		m.olCounters = append(m.olCounters, 0)
	case tag == "li":
