func (m *MarkdownConverter) HandleEndTag(tag string) {
	tag = strings.ToLower(tag)
	if len(m.tagStack) > 0 && m.tagStack[len(m.tagStack)-1] == tag {
		m.tagStack = m.tagStack[:len(m.tagStack)-1]
	}

	switch {
	case tag == "h1" || tag == "h2" || tag == "h3" || tag == "h4" || tag == "h5" || tag == "h6":
		level := int(tag[1] - '0')
		prefix := strings.Repeat("#", level) + " "
		textParts := []string{}
		for len(m.output) > 0 && m.output[len(m.output)-1] != "\n\n" {
			textParts = append(textParts, m.output[len(m.output)-1])
			m.output = m.output[:len(m.output)-1]
		}
		// Reverse textParts
		for i, j := 0, len(textParts)-1; i < j; i, j = i+1, j-1 {
			textParts[i], textParts[j] = textParts[j], textParts[i]
		}
		text := strings.TrimSpace(strings.Join(textParts, ""))
		m.output = append(m.output, fmt.Sprintf("%s%s\n\n", prefix, text))
	case tag == "p":
		if !m.inCell {
			m.output = append(m.output, "\n")
		}
	case tag == "pre":
		m.inPre = false
		m.output = append(m.output, "\n```\n\n")
	case tag == "ul":
		if len(m.listStack) > 0 {
			m.listStack = m.listStack[:len(m.listStack)-1]
		}
		m.output = append(m.output, "\n")
	case tag == "ol":
		if len(m.listStack) > 0 {
			m.listStack = m.listStack[:len(m.listStack)-1]
		}
		if len(m.olCounters) > 0 {
			m.olCounters = m.olCounters[:len(m.olCounters)-1]
		}
		m.output = append(m.output, "\n")
	case tag == "strong" || tag == "b":
		m.appendText("**")
	case tag == "em" || tag == "i":
		m.appendText("*")
	case tag == "a":
		linkText := strings.TrimSpace(strings.Join(m.linkText, ""))
		var formatted string
		if m.href != "" && linkText != "" {
			formatted = fmt.Sprintf("[%s](%s)", linkText, m.href)
		} else {
			formatted = linkText
		}
		m.appendText(formatted)
		m.inLink = false
		m.href = ""
		m.linkText = []string{}
	case tag == "td" || tag == "th":
		cellText := strings.Join(strings.Fields(strings.Join(m.cellBuf, "")), " ")
		m.currentRowCells = append(m.currentRowCells, cellText)
		m.cellBuf = []string{}
		m.inCell = false
	case tag == "tr":
		if len(m.currentRowCells) > 0 {
			row := "| " + strings.Join(m.currentRowCells, " | ") + " |"
			m.output = append(m.output, fmt.Sprintf("\n%s", row))
			m.lastRowColCount = len(m.currentRowCells)
		}
	case tag == "thead":
		if m.lastRowColCount > 0 {
			dashes := make([]string, m.lastRowColCount)
			for i := range dashes {
				dashes[i] = "---"
			}
			sep := "| " + strings.Join(dashes, " | ") + " |"
			m.output = append(m.output, fmt.Sprintf("\n%s", sep))
		}
	}
}

