def detect_type_from_source(
    source_path: str | None,
    detected_mime: str | None,
) -> str:
    """Auto-detect document type from transport metadata and file extension.

    Priority: detected_mime (from HTTP Content-Type / S3 metadata) > file extension > "text" fallback.
    """
    # Try MIME from transport first
    if detected_mime:
        lower_mime = detected_mime.lower().split(";")[0].strip()
        if lower_mime in MIME_TO_SHORT:
            return MIME_TO_SHORT[lower_mime]
        # Partial match for common patterns
        if "pdf" in lower_mime:
            return "pdf"
        if "html" in lower_mime:
            return "html"
        if "markdown" in lower_mime:
            return "markdown"
        if "wordprocessingml" in lower_mime:
            return "docx"
        if "spreadsheetml" in lower_mime:
            return "xlsx"
        if "presentationml" in lower_mime:
            return "pptx"

    # Try file extension
    if source_path:
        import os
        ext = os.path.splitext(source_path)[1].lower()
        if ext in EXTENSION_TO_SHORT:
            return EXTENSION_TO_SHORT[ext]

    return "text"

// DetectTypeFromSource auto-detects document type from MIME type and file extension.
func DetectTypeFromSource(sourcePath string, detectedMIME string) string {
	// Try MIME from transport first
	if detectedMIME != "" {
		parts := strings.SplitN(detectedMIME, ";", 2)
		lowerMIME := strings.ToLower(strings.TrimSpace(parts[0]))
		if short, ok := mimeToShort[lowerMIME]; ok {
			return short
		}
		// Partial match for common patterns
		if strings.Contains(lowerMIME, "pdf") {
			return "pdf"
		}
		if strings.Contains(lowerMIME, "html") {
			return "html"
		}
		if strings.Contains(lowerMIME, "markdown") {
			return "markdown"
		}
		if strings.Contains(lowerMIME, "wordprocessingml") {
			return "docx"
		}
		if strings.Contains(lowerMIME, "spreadsheetml") {
			return "xlsx"
		}
		if strings.Contains(lowerMIME, "presentationml") {
			return "pptx"
		}
	}

	// Try file extension
	if sourcePath != "" {
		ext := strings.ToLower(filepath.Ext(sourcePath))
		if short, ok := extensionToShort[ext]; ok {
			return short
		}
	}

	return "text"
}

