type sectionInfo struct {
	LineStart int
	LineEnd   int
	Symbol    string
}

// Annotate attaches Python symbol source location to matching chunks.
func (p *PythonExtractor) Annotate(chunks []*DocumentChunk, data []byte, sourcePath string) ([]*DocumentChunk, error) {
	source, err := parseUTF8(data)
	if err != nil {
		name := sourcePath
		if name == "" {
			name = "<unknown>"
		}
		return nil, fmt.Errorf("UTF-8 decode failed in %s: %w", name, err)
	}

	tree, parseErr := parsePythonAST(source, sourcePath)
	if parseErr != nil {
		return nil, fmt.Errorf("Python parse error: %w", parseErr)
	}

	sectionMap := map[string]sectionInfo{}

	importNodes := collectImportNodes(tree)
	if len(importNodes) > 0 {
		lineStart, lineEnd := importNodeRange(importNodes)
		sectionMap["Imports"] = sectionInfo{LineStart: lineStart, LineEnd: lineEnd, Symbol: "Imports"}
	}

	for _, node := range tree.ChildNodes {
		switch n := node.(type) {
		case *ClassDef:
			methods := collectMethodNodes(n)
			if len(methods) > 0 {
				for _, item := range methods {
					key := n.Name + "." + item.Name
					sectionMap[key] = sectionInfo{
						LineStart: item.Lineno,
						LineEnd:   item.EndLineno,
						Symbol:    fmt.Sprintf("%s.%s", n.Name, item.Name),
					}
				}
			} else {
				sectionMap[n.Name] = sectionInfo{
					LineStart: n.Lineno,
					LineEnd:   n.EndLineno,
					Symbol:    n.Name,
				}
			}
		case *FunctionDef:
			sectionMap[n.Name] = sectionInfo{
				LineStart: n.Lineno,
				LineEnd:   n.EndLineno,
				Symbol:    n.Name,
			}
		}
	}

	for _, chunk := range chunks {
		key := strings.Join(chunk.Section, ".")
		if info, ok := sectionMap[key]; ok {
			chunk.SourceDetail = map[string]interface{}{
				"line_start": info.LineStart,
				"line_end":   info.LineEnd,
				"symbol":     info.Symbol,
			}
		}
	}
	return chunks, nil
