def build(
    self,
    extractor,
    chunks: list[tuple[str, str]],
    *,
    on_complete: Callable[[RelationshipIndex], None] | None = None,
) -> None:
    def _run() -> None:
        try:
            idx = RelationshipIndex()
            for chunk_id, text in chunks:
                for triple in extractor.extract(chunk_id, text):
                    idx.add(triple)
            new_version = self.ref.update(idx)
            logger.debug("RelationshipIndex version %d ready (%d triples)",
                         new_version, len(idx))
            if on_complete is not None:
                on_complete(idx)
        except Exception:
            logger.exception("RelationshipIndexBuilder background build failed")

    t = threading.Thread(target=_run, daemon=True, name="relationship-index-builder")
    self._thread = t
    t.start()

// Build spawns a background goroutine that extracts SVO triples from chunks and
// updates the VersionedRef when complete.
func (b *RelationshipIndexBuilder) Build(
	extractor SVOExtractorIface,
	chunks [][2]string,
	onComplete func(*RelationshipIndex),
) {
	var wg sync.WaitGroup
	wg.Add(1)
	b.thread = &wg
	go func() {
		defer wg.Done()
		idx := NewRelationshipIndex()
		for _, chunk := range chunks {
			chunkID, text := chunk[0], chunk[1]
			triples, err := extractor.Extract(chunkID, text)
			if err != nil {
				logger.Printf("ERROR RelationshipIndexBuilder background build failed: %v", err)
				return
			}
			for _, triple := range triples {
				idx.Add(triple)
			}
		}
		newVersion := b.ref.Update(idx)
		logger.Printf("DEBUG: RelationshipIndex version %d ready (%d triples)", newVersion, idx.Len())
		if onComplete != nil {
			onComplete(idx)
		}
	}()
}

// GetContextGraphEdges returns edges from context_graph_edges for the given entity.
// Returns an empty slice if the context graph has not been built for the namespace.
func GetContextGraphEdges(conn DBConn, entityID, namespace string, minWeight float64) ([]ContextEdge, error) {
	hasEdgesRows, err := conn.Execute(
		"SELECT 1 FROM context_graph_edges WHERE namespace = ? LIMIT 1",
		namespace,
	)
	if err != nil || len(hasEdgesRows) == 0 {
		logger.Printf("DEBUG: context graph not built for namespace %q — skipping expansion; call build_context_graph() to enable", namespace)
		return []ContextEdge{}, nil
	}

	rows, err := conn.Execute(`
		SELECT target_entity_id, weight, svo_signal, cooccur_signal, cluster_signal
		FROM context_graph_edges
		WHERE source_entity_id = ? AND namespace = ? AND weight >= ?
		ORDER BY weight DESC`,
		entityID, namespace, minWeight,
	)
	if err != nil {
		return nil, fmt.Errorf("GetContextGraphEdges query: %w", err)
	}

	edges := make([]ContextEdge, 0, len(rows))
	for _, r := range rows {
		weight, _ := strconv.ParseFloat(r[1], 64)
		svoSignal, _ := strconv.ParseFloat(r[2], 64)
		cooccurSignal, _ := strconv.ParseFloat(r[3], 64)
		clusterSignal, _ := strconv.ParseFloat(r[4], 64)
		edges = append(edges, ContextEdge{
			SourceEntityID: entityID,
			TargetEntityID: r[0],
			Weight:         weight,
			SVOSignal:      svoSignal,
			CooccurSignal:  cooccurSignal,
			ClusterSignal:  clusterSignal,
		})
	}
	return edges, nil
}

