// computeRawEdges iterates all entity pairs, computes SVO, co-occurrence, and cluster signals,
// and returns qualifying raw edges.
func computeRawEdges(
	allEntities []string,
	svoPairs map[[2]string]struct{},
	entityToChunks map[string]map[string]struct{},
	entityToClusters map[string]map[int]struct{},
) []RawEdge {
	var rawEdges []RawEdge
	for i := 0; i < len(allEntities); i++ {
		for j := i + 1; j < len(allEntities); j++ {
			a, b := allEntities[i], allEntities[j]

			// SVO signal
			pairKey := [2]string{a, b}
			if a > b {
				pairKey = [2]string{b, a}
			}
			var svoSignal float64
			if _, ok := svoPairs[pairKey]; ok {
				svoSignal = 1.0
			}

			// Cooccur signal: +0.8 per shared chunk, capped at 0.8
			sharedChunks := 0
			for cid := range entityToChunks[a] {
				if _, ok := entityToChunks[b][cid]; ok {
					sharedChunks++
				}
			}
			cooccurSignal := math.Min(float64(sharedChunks)*0.8, 0.8)

			// Cluster signal
			clustersA := entityToClusters[a]
			clustersB := entityToClusters[b]
			var clusterSignal float64
			if len(clustersA) > 0 || len(clustersB) > 0 {
				sharedClusters := 0
				for cid := range clustersA {
					if _, ok := clustersB[cid]; ok {
						sharedClusters++
					}
				}
				unionClusters := len(clustersA)
				for cid := range clustersB {
					if _, ok := clustersA[cid]; !ok {
						unionClusters++
					}
				}
				if unionClusters > 0 {
					clusterSignal = 0.4 * (float64(sharedClusters) / float64(unionClusters))
				}
			}

			rawWeight := svoSignal + cooccurSignal + clusterSignal
			if rawWeight > 0 || svoSignal > 0 || cooccurSignal > 0 || clusterSignal > 0 {
				rawEdges = append(rawEdges, RawEdge{A: a, B: b, RawWeight: rawWeight, SVOSignal: svoSignal, CooccurSignal: cooccurSignal, ClusterSignal: clusterSignal})
			}
		}
	}
	return rawEdges
}

// embedEntities builds entity text representations, encodes them with the embed model,
// deletes old entity embeddings, and writes the new ones.
func (p *EntityGraphPipeline) embedEntities(store Store, prog ProgressFn) (int, error) {
	if p.embedModel == nil {
		return 0, fmt.Errorf("embedEntities called without embedModel")
	}
	conn := store.DB().Conn()

	entityRows, err := conn.Execute(`
		SELECT e.id, e.name,
		       COALESCE(e.description, '') AS description,
		       e.entity_type
		FROM entities e`)
	if err != nil {
		return 0, fmt.Errorf("embedEntities entity query: %w", err)
	}

	if len(entityRows) == 0 {
		return 0, nil
	}

	aliasRows, err := conn.Execute(
		"SELECT entity_id, alias FROM entity_aliases WHERE namespace = ?",
		p.namespace,
	)
	if err != nil {
		aliasRows = nil
	}

	aliasesMap := make(map[string][]string)
	for _, r := range aliasRows {
		eid, alias := r[0], r[1]
		aliasesMap[eid] = append(aliasesMap[eid], alias)
	}

	var texts []string
	var chunks []DocumentChunk
	for _, r := range entityRows {
		entityID, name, description := r[0], r[1], r[2]
		parts := []string{name}
		if aliasList, ok := aliasesMap[entityID]; ok && len(aliasList) > 0 {
			parts = append(parts, strings.Join(aliasList, ", "))
		}
		if len(description) > 0 {
			parts = append(parts, description)
		}
		text := strings.Join(parts, ". ")
		texts = append(texts, text)
		chunks = append(chunks, DocumentChunk{
			DocumentName: fmt.Sprintf("__entity__%s", entityID),
			Content:      text,
			ChunkIndex:   0,
			ChunkType:    "entity",
		})
	}

	prog(PhaseEmbedEntities, 0, len(chunks))
	vecs, err := p.embedModel.Encode(texts)
	if err != nil {
		return 0, fmt.Errorf("embedEntities encode: %w", err)
	}

	if _, err := conn.Execute("DELETE FROM embeddings WHERE chunk_type = 'entity'"); err != nil {
		return 0, fmt.Errorf("embedEntities delete: %w", err)
	}
	if err := store.AddDocument(chunks, vecs); err != nil {
		return 0, fmt.Errorf("embedEntities AddDocument: %w", err)
	}
	prog(PhaseEmbedEntities, len(chunks), len(chunks))
	return len(chunks), nil
}

