			triples, descs, aliases, _, err := p.extractor.ExtractEntityAnchored(content, chunkID, entities)
			resultsCh <- result{triples: triples, descs: descs, aliases: aliases, err: err}
		}()
	}

	go func() {
		wg.Wait()
		close(resultsCh)
	}()

	done := 0
	var firstErr error
	for res := range resultsCh {
		if res.err != nil && firstErr == nil {
			firstErr = res.err
		}
		for _, t := range res.triples {
			relationshipIndex.Add(t)
		}
		for k, v := range res.descs {
			newDescriptions[k] = v
		}
		for eid, aliasList := range res.aliases {
			newAliases[eid] = append(newAliases[eid], aliasList...)
		}
		done++
		chunksProcessed++
		prog(PhaseExtract, done, total)
	}

	if firstErr != nil {
		return nil, nil, nil, chunksProcessed, fmt.Errorf("extractionPhase: %w", firstErr)
	}
	return relationshipIndex, newDescriptions, newAliases, chunksProcessed, nil
}

// LLMClient is the minimal interface an LLM backend must satisfy.
type LLMClient interface {
	Complete(prompt string) string
}

// SVOExtractor extracts SVOTriples from text via an injected LLM client.
type SVOExtractor struct {
	llm          LLMClient
	verbSet      map[string]struct{}
	userTemplate string
	system       string
}

// SVOExtractorOptions carries optional overrides for NewSVOExtractor.
type SVOExtractorOptions struct {
	VerbSet               map[string]struct{} // nil → default VERB_SET
	SystemPromptTemplate  *string             // nil → default _SYSTEM_PROMPT
	UserTemplate          *string             // nil → default _USER_TEMPLATE
}

// NewSVOExtractor constructs an SVOExtractor or returns an error if llm is nil.
func NewSVOExtractor(llm LLMClient, opts SVOExtractorOptions) (*SVOExtractor, error) {
	if llm == nil {
		return nil, fmt.Errorf("llm must implement LLMClient, got nil")
	}
	verbSet := opts.VerbSet
	if verbSet == nil {
		verbSet = defaultVerbSet()
	}
	sysTmpl := _SYSTEM_PROMPT
	if opts.SystemPromptTemplate != nil {
		sysTmpl = *opts.SystemPromptTemplate
	}
	userTmpl := _USER_TEMPLATE
	if opts.UserTemplate != nil {
		userTmpl = *opts.UserTemplate
	}
	verbs := sortedVerbs(verbSet)
	system := strings.ReplaceAll(sysTmpl, "{verbs}", strings.Join(verbs, ", "))
	return &SVOExtractor{
		llm:          llm,
		verbSet:      verbSet,
		userTemplate: userTmpl,
		system:       system,
	}, nil
}

// Extract extracts SVOTriples from a text passage.
// chunkID may be empty string when no source identifier is available.
func (e *SVOExtractor) Extract(text string, chunkID string) []SVOTriple {
	userMsg := strings.NewReplacer(
		"{chunk_id}", chunkID,
		"{text}", text,
	).Replace(e.userTemplate)
	prompt := e.system + "\n\n" + userMsg
	raw := e.llm.Complete(prompt)
	result, ok := e.parse(raw, chunkID)
	if !ok {
		raw = e.llm.Complete(prompt + _RETRY_SUFFIX)
		result, ok = e.parse(raw, chunkID)
	}
	if !ok {
		return []SVOTriple{}
	}
	return result
}

// TextChunkPair holds a text passage and its optional source chunk identifier.
type TextChunkPair struct {
	Text    string
	ChunkID string
}

// ExtractBatch extracts triples from multiple (text, chunkID) pairs and
// returns a flat slice of all valid triples across all inputs.
func (e *SVOExtractor) ExtractBatch(texts []TextChunkPair) []SVOTriple {
	results := []SVOTriple{}
	for _, pair := range texts {
		triples := e.Extract(pair.Text, pair.ChunkID)
		results = append(results, triples...)
	}
	return results
}

