// EntityInput carries the fields used by ExtractEntityAnchored.
type EntityInput struct {
	ID          string
	Type        string
	Description string
}

// EntityAnchoredResult holds the four return values from entity-anchored extraction.
type EntityAnchoredResult struct {
	Triples         []SVOTriple
	Descriptions    map[string]string
	Aliases         map[string][]string
	RelDescriptions map[string]string
}

// ExtractEntityAnchored performs entity-anchored triple extraction.
func (e *SVOExtractor) ExtractEntityAnchored(text string, chunkID string, entities []EntityInput) EntityAnchoredResult {
	empty := EntityAnchoredResult{
		Triples:         []SVOTriple{},
		Descriptions:    map[string]string{},
		Aliases:         map[string][]string{},
		RelDescriptions: map[string]string{},
	}
	if len(entities) < 2 {
		return empty
	}
	validIDs := map[string]struct{}{}
	for _, ent := range entities {
		validIDs[ent.ID] = struct{}{}
	}
	lines := []string{}
	for _, ent := range entities {
		hasDesc := len(ent.Description) > 0
		marker := " "
		if hasDesc {
			marker = "\u2713"
		}
		descPart := ""
		if hasDesc {
			descPart = fmt.Sprintf(" \u2014 %s", ent.Description)
		}
		entType := ent.Type
		if len(entType) == 0 {
			entType = "?"
		}
		lines = append(lines, fmt.Sprintf("  [%s] %s [%s]%s", marker, ent.ID, entType, descPart))
	}
	entityList := strings.Join(lines, "\n")
	verbs := sortedVerbs(e.verbSet)
	anchoredSystem := strings.ReplaceAll(_ENTITY_ANCHORED_SYSTEM_PROMPT, "{verbs}", strings.Join(verbs, ", "))
	userMsg := strings.NewReplacer(
		"{entity_list}", entityList,
		"{chunk_id}", chunkID,
		"{text}", text,
	).Replace(_ENTITY_ANCHORED_USER_TEMPLATE)
	prompt := anchoredSystem + "\n\n" + userMsg
	raw := e.llm.Complete(prompt)
	result, ok := e.parseEntityAnchored(raw, chunkID, validIDs)
	if !ok {
		raw = e.llm.Complete(prompt + _RETRY_SUFFIX)
		result, ok = e.parseEntityAnchored(raw, chunkID, validIDs)
	}
	if !ok {
		return empty
	}
	return result
}

