// SaveToDB upserts all triples into the svo_triples table and returns the count written.
// If incremental is true, existing rows are not cleared before insertion.
func (r *RelationshipIndex) SaveToDB(con DBConn, incremental bool) (int, error) {
	if err := con.Execute(`CREATE TABLE IF NOT EXISTS svo_triples (
		chunk_id    VARCHAR,
		subject_id  VARCHAR NOT NULL,
		verb        VARCHAR NOT NULL,
		object_id   VARCHAR NOT NULL,
		confidence  FLOAT   NOT NULL DEFAULT 1.0,
		namespace   VARCHAR,
		description TEXT    NOT NULL DEFAULT ''
	)`); err != nil {
		return 0, fmt.Errorf("create table: %w", err)
	}
	if err := con.Execute("ALTER TABLE svo_triples ADD COLUMN IF NOT EXISTS namespace VARCHAR"); err != nil {
		return 0, fmt.Errorf("alter namespace: %w", err)
	}
	if err := con.Execute("ALTER TABLE svo_triples ADD COLUMN IF NOT EXISTS description TEXT"); err != nil {
		return 0, fmt.Errorf("alter description: %w", err)
	}
	if !incremental {
		if err := con.Execute("DELETE FROM svo_triples"); err != nil {
			return 0, fmt.Errorf("delete svo_triples: %w", err)
		}
	}
	rows := []SVORow{}
	for _, triples := range r.bySubject {
		for _, t := range triples {
			nsRow, err := con.QueryOne("SELECT namespace FROM embeddings WHERE chunk_id = ?", t.SourceChunkID)
			var ns *string
			if err == nil && nsRow != nil {
				if s, ok := nsRow[0].(string); ok {
					ns = &s
				}
			}
			rows = append(rows, SVORow{
				ChunkID:     t.SourceChunkID,
				SubjectID:   t.SubjectID,
				Verb:        t.Verb,
				ObjectID:    t.ObjectID,
				Confidence:  t.Confidence,
				Namespace:   ns,
				Description: t.Description,
			})
		}
	}
	if len(rows) > 0 {
		if err := con.ExecuteMany("INSERT INTO svo_triples VALUES (?, ?, ?, ?, ?, ?, ?)", rows); err != nil {
			return 0, fmt.Errorf("insert svo_triples: %w", err)
		}
	}
	return len(rows), nil
}

