// persistAssociations writes associations and entities to the DB, clearing first unless incremental.
func persistAssociations(con *sql.DB, associations []map[string]interface{}, entityMeta map[string][3]string, incremental bool) error {
	if !incremental {
		if _, err := con.Exec("DELETE FROM chunk_entities"); err != nil {
			return fmt.Errorf("delete chunk_entities: %w", err)
		}
		if _, err := con.Exec("DELETE FROM entities"); err != nil {
			return fmt.Errorf("delete entities: %w", err)
		}
	}
	for _, a := range associations {
		chunkID, _ := a["chunk_id"].(string)
		entityID, _ := a["entity_id"].(string)
		frequency, _ := a["frequency"].(int)
		positions, _ := a["positions"].([]int)
		score, _ := a["score"].(float64)
		posJSON, err := json.Marshal(positions)
		if err != nil {
			return fmt.Errorf("marshal positions: %w", err)
		}
		var chunkNamespace *string
		row := con.QueryRow("SELECT namespace FROM embeddings WHERE chunk_id = ?", chunkID)
		var ns string
		if scanErr := row.Scan(&ns); scanErr == nil {
			chunkNamespace = &ns
		}
		_, err = con.Exec(
			"INSERT OR REPLACE INTO chunk_entities(chunk_id, entity_id, frequency, positions_json, score, namespace) VALUES (?,?,?,?,?,?)",
			chunkID, entityID, frequency, string(posJSON), score, chunkNamespace,
		)
		if err != nil {
			return fmt.Errorf("insert chunk_entities: %w", err)
		}
		name, displayName, entityType := entityID, entityID, "concept"
		if meta, ok := entityMeta[entityID]; ok {
			name, displayName, entityType = meta[0], meta[1], meta[2]
		}
		_, err = con.Exec(
			"INSERT OR IGNORE INTO entities(id, name, display_name, entity_type) VALUES (?,?,?,?)",
			entityID, name, displayName, entityType,
		)
		if err != nil {
			return fmt.Errorf("insert entity: %w", err)
		}
		if alias, ok := stripIDAlias(entityID); ok {
			_, err = con.Exec(
				"INSERT OR IGNORE INTO entity_aliases(alias, entity_id, source) VALUES (?,?,?)",
				alias, entityID, "strip_suffix",
			)
			if err != nil {
				return fmt.Errorf("insert entity_alias: %w", err)
			}
		}
	}
	return nil
}

