	for _, match := range matches {
		firstPos := 0
		if len(match.Positions) > 0 {
			firstPos = match.Positions[0]
		}
		score := idx.computeScore(match.Frequency, firstPos, chunkLength, match.EntityID)
		assoc := EntityAssociation{
			EntityID:    match.EntityID,
			ChunkID:     chunkID,
			Frequency:   match.Frequency,
			Positions:   match.Positions,
			Score:       score,
			ChunkLength: chunkLength,
		}
		if idx.entityToChunks[match.EntityID] == nil {
			idx.entityToChunks[match.EntityID] = make(map[string]*EntityAssociation)
		}
		idx.entityToChunks[match.EntityID][chunkID] = &assoc
		if idx.chunkToEntities[chunkID] == nil {
			idx.chunkToEntities[chunkID] = make(map[string]*EntityAssociation)
		}
		idx.chunkToEntities[chunkID][match.EntityID] = &assoc
		associations = append(associations, assoc)
	}
	return associations
}

