// computeScore computes the association score for one entity-chunk pair.
func (idx *EntityIndex) computeScore(frequency int, firstPosition int, chunkLength int, entityID string) float64 {
	df := idx.ChunksContainingEntity(entityID) + 1 // +1 for current chunk
	n := idx.totalChunks + 1
	freqScore := math.Log1p(float64(frequency))
	posScore := 1.0 - float64(firstPosition)/float64(chunkLength)
	var specScore float64
	if df > 0 {
		specScore = math.Log(float64(n) / float64(df))
	}
	return idx.fw*freqScore + idx.pw*posScore + idx.sw*specScore
}

// RecomputeScores recomputes all association scores with the current corpus size.
// Call after bulk-indexing a large corpus for accurate specificity scores.
func (idx *EntityIndex) RecomputeScores() {
	n := idx.totalChunks
	for entityID, chunkMap := range idx.entityToChunks {
		df := len(chunkMap)
		for chunkID, assoc := range chunkMap {
			freqScore := math.Log1p(float64(assoc.Frequency))
			chunkLen := assoc.ChunkLength
			if chunkLen < 1 {
				chunkLen = 1
			}
			firstPos := 0
			if len(assoc.Positions) > 0 {
				firstPos = assoc.Positions[0]
			}
			posScore := 1.0 - float64(firstPos)/float64(chunkLen)
			var specScore float64
			if df > 0 && n > 0 {
				specScore = math.Log(float64(n) / float64(df))
			}
			assoc.Score = idx.fw*freqScore + idx.pw*posScore + idx.sw*specScore
			if idx.chunkToEntities[chunkID] == nil {
				idx.chunkToEntities[chunkID] = make(map[string]*EntityAssociation)
			}
			idx.chunkToEntities[chunkID][entityID] = assoc
		}
