	'<': {}, '>': {}, '*': {}, '&': {}, '^': {}, '%': {},
	'$': {}, '#': {}, '@': {}, '!': {}, '+': {}, '=': {},
	'~': {}, '`': {}, '\'': {}, '"': {}, '\\': {}, '|': {},
	'/': {}, '?': {}, ':': {}, ';': {}, ',': {}, '.': {},
