	// Combine and dedup by entity_id.
	merged := make(map[string]*EntityMatch)
	allMatches := make([]EntityMatch, 0, len(vocabMatches)+len(survivingGeneric))
	allMatches = append(allMatches, vocabMatches...)
	allMatches = append(allMatches, survivingGeneric...)
	for _, m := range allMatches {
