			copy := EntityMatch{
				EntityID:    m.EntityID,
				Name:        m.Name,
				DisplayName: m.DisplayName,
				EntityType:  m.EntityType,
				Frequency:   0,
				Positions:   []int{},
				Spans:       [][2]int{},
