		eid := ent.ID
		dtype := ent.Type
		if dtype == "" {
			dtype = ent.EntityType
		}
		if dtype == "" {
			dtype = "concept"
		}
		vm.entities[eid] = entityMeta{
			id:          eid,
			name:        ent.Name,
			displayName: ent.DisplayName,
			entityType:  dtype,
