func normalizeSchemaTermFull(term string, toSingular bool) string {
	s := camelRE.ReplaceAllString(term, "${1} ${2}")
	s = pascalRE.ReplaceAllString(s, "${1} ${2}")
	s = strings.ReplaceAll(s, "_", " ")
	s = strings.ReplaceAll(s, "-", " ")
