			pos += start
			beforeOK := pos == 0 || !isAlnum(check[pos-1])
			afterPos := pos + len(variant)
			afterOK := afterPos >= len(check) || !isAlnum(check[afterPos])
			if beforeOK && afterOK {
				found[lv.entityID] = append(found[lv.entityID], spanPair{pos, afterPos})
			}
			start = pos + 1
		}
	}

	var results []EntityMatch
	for eid, spans := range found {
		meta := sm.entities[eid]
		seen := make(map[spanPair]struct{})
		var deduped []spanPair
		for _, s := range spans {
			if _, ok := seen[s]; !ok {
				seen[s] = struct{}{}
				deduped = append(deduped, s)
			}
		}
		sort.Slice(deduped, func(i, j int) bool { return deduped[i].start < deduped[j].start })
		positions := make([]int, len(deduped))
		spanPairs := make([][2]int, len(deduped))
		for i, s := range deduped {
			positions[i] = s.start
			spanPairs[i] = [2]int{s.start, s.end}
		}
		results = append(results, EntityMatch{
			EntityID:    eid,
			Name:        meta.canonical,
			DisplayName: meta.displayName,
			EntityType:  meta.entityType,
			Frequency:   len(deduped),
			Positions:   positions,
			Spans:       spanPairs,
		})
	}
	return results
}

