func (t *HttpTransport) Fetch(uri string, opts HttpFetchOptions) (*FetchResult, error) {
	client := getHTTPClient()

	timeout := opts.Timeout
	if timeout == 0 {
		timeout = 30 * time.Second
	}

	req, err := http.NewRequestWithContext(context.Background(), http.MethodGet, uri, nil)
	if err != nil {
		return nil, fmt.Errorf("HttpTransport.Fetch: create request: %w", err)
	}
	for k, v := range opts.Headers {
		req.Header.Set(k, v)
	}

	clientWithTimeout := *client
	clientWithTimeout.Timeout = timeout

	resp, err := clientWithTimeout.Do(req)
	if err != nil {
		return nil, fmt.Errorf("HttpTransport.Fetch: GET %s: %w", uri, err)
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return nil, fmt.Errorf("HttpTransport.Fetch: GET %s: status %d", uri, resp.StatusCode)
	}

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("HttpTransport.Fetch: read body: %w", err)
	}

	var detectedMime *string
	if ct := resp.Header.Get("Content-Type"); ct != "" {
		detectedMime = &ct
	}
	return &FetchResult{
		Data:         data,
		DetectedMime: detectedMime,
		SourcePath:   uri,
	}, nil
}

