def infer_jsonl(data: bytes, name: str) -> TableMeta:
    key_types: dict[str, str] = {}
    count = 0
    total = 0
    parse_failures = 0
    for raw in io.BytesIO(data):
        line = raw.strip()
        if not line:
            continue
        total += 1
        if count < 100:
            try:
                obj = json.loads(line)
                if isinstance(obj, dict):
                    for k, v in obj.items():
                        if k not in key_types:
                            key_types[k] = _python_type_to_str(v)
                count += 1
            except json.JSONDecodeError:
                parse_failures += 1
    if total > 0 and count == 0:
        raise ValueError(f"All {parse_failures} non-empty lines in {name!r} failed JSON parsing")
    columns = [ColumnMeta(name=k, data_type=v) for k, v in key_types.items()]
    return TableMeta(name=name, columns=columns, row_count=total)

func InferJSONL(data []byte, name string) (*TableMeta, error) {
	keyTypes := map[string]string{}
	count := 0
	total := 0
	parseFailures := 0

	scanner := bufio.NewScanner(bytes.NewReader(data))
	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line == "" {
			continue
		}
		total++
		if count < 100 {
			var obj map[string]interface{}
			if err := json.Unmarshal([]byte(line), &obj); err != nil {
				parseFailures++
			} else {
				for k, v := range obj {
					if _, exists := keyTypes[k]; !exists {
						keyTypes[k] = pythonTypeToStr(v)
					}
				}
				count++
			}
		}
	}
	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("scan jsonl: %w", err)
	}

	if total > 0 && count == 0 {
		return nil, fmt.Errorf("all %d non-empty lines in %q failed JSON parsing", parseFailures, name)
	}

	var columns []ColumnMeta
	for k, v := range keyTypes {
		columns = append(columns, ColumnMeta{Name: k, DataType: v})
	}
	return &TableMeta{Name: name, Columns: columns, RowCount: total}, nil
}

