def infer_parquet(data: bytes, ext: str, name: str) -> TableMeta:
    try:
        import pyarrow as pa
        import pyarrow.parquet as pq
        import pyarrow.feather as feather
        import pyarrow.ipc as ipc
    except ImportError as exc:
        raise ImportError("pyarrow is required for parquet/arrow/feather schema inference.") from exc

    buf = pa.BufferReader(data)

    if ext == ".arrow":
        reader = ipc.open_stream(buf)
        schema = reader.schema
        row_count = None
    elif ext == ".feather":
        table = feather.read_table(buf)
        schema = table.schema
        row_count = table.num_rows
    else:
        pf = pq.ParquetFile(buf)
        schema = pf.schema_arrow
        row_count = pf.metadata.num_rows

    columns = [
        ColumnMeta(name=field.name, data_type=_arrow_type_to_str(field.type)) for field in schema
    ]
    return TableMeta(name=name, columns=columns, row_count=row_count)

func InferParquet(data []byte, ext, name string) (*TableMeta, error) {
	reader, err := newArrowBufferReader(data)
	if err != nil {
		return nil, fmt.Errorf("buffer reader: %w", err)
	}

	var schema *arrow.Schema
	var rowCount *int64

	if ext == ".arrow" {
		r, err := ipc.NewReader(reader)
		if err != nil {
			return nil, fmt.Errorf("open arrow stream: %w", err)
		}
		defer r.Release()
		schema = r.Schema()
		// row_count remains nil for streaming IPC
	} else if ext == ".feather" {
		table, err := ipc.OpenFile(reader)
		if err != nil {
			return nil, fmt.Errorf("open feather: %w", err)
		}
		defer table.Release()
		schema = table.Schema()
		n := table.NumRows()
		rowCount = &n
	} else {
		pf, err := pqarrow.OpenParquetFile(reader, false)
		if err != nil {
			return nil, fmt.Errorf("open parquet: %w", err)
		}
		schema, err = pf.Schema()
		if err != nil {
			return nil, fmt.Errorf("parquet schema: %w", err)
		}
		n := pf.NumRows()
		rowCount = &n
	}

	var columns []ColumnMeta
	for i := 0; i < schema.NumFields(); i++ {
		f := schema.Field(i)
		columns = append(columns, ColumnMeta{Name: f.Name, DataType: arrowTypeToStr(f.Type)})
	}
	return &TableMeta{Name: name, Columns: columns, RowCount: rowCount}, nil
}

