def _resolve_domains(
    self,
    namespaces: list[str] | None,
    domains: list[str] | None,
) -> list[str] | None:
    if namespaces is None and domains is None:
        return None
    target_ns = namespaces or list(self._domain_map.keys())
    ids: list[str] = []
    if domains is not None:
        for ns in target_ns:
            ns_map = self._domain_map.get(ns, {})
            for name in domains:
                if name in ns_map:
                    ids.append(ns_map[name])
    else:
        for ns in target_ns:
            ids.extend(self._domain_map.get(ns, {}).values())
    return ids or None

func (idx *Index) resolveDomains(namespaces, domains []string) []string {
	if namespaces == nil && domains == nil {
		return nil
	}

	var targetNS []string
	if len(namespaces) > 0 {
		targetNS = namespaces
	} else {
		for ns := range idx.domainMap {
			targetNS = append(targetNS, ns)
		}
	}

	var ids []string
	if domains != nil {
		for _, ns := range targetNS {
			nsMap, ok := idx.domainMap[ns]
			if !ok {
				continue
			}
			for _, name := range domains {
				if did, found := nsMap[name]; found {
					ids = append(ids, did)
				}
			}
		}
	} else {
		for _, ns := range targetNS {
			nsMap, ok := idx.domainMap[ns]
			if !ok {
				continue
			}
			for _, did := range nsMap {
				ids = append(ids, did)
			}
		}
	}

	if len(ids) == 0 {
		return nil
	}
	return ids
}

