def _agglomerative(
    cooccurrence: dict[tuple[str, str], float],
    entities: list[str],
    distance_threshold: float,
) -> dict[str, str]:
    try:
        import numpy as np
        from sklearn.cluster import AgglomerativeClustering
    except ImportError as e:
        raise ImportError(
            "scikit-learn and numpy are required for agglomerative clustering. "
            "Install with: pip install chonk[cluster]"
        ) from e

    n = len(entities)
    idx = {e: i for i, e in enumerate(entities)}

    dist = np.ones((n, n), dtype=np.float32)
    np.fill_diagonal(dist, 0.0)

    if cooccurrence:
        vals = list(cooccurrence.values())
        lo, hi = min(vals), max(vals)
        span = hi - lo
    else:
        lo, span = 0.0, 0.0

    for (a, b), score in cooccurrence.items():
        if a not in idx or b not in idx:
            continue
        sim = (score - lo) / span if span > 0 else 1.0
        d = max(0.0, 1.0 - sim)
        dist[idx[a], idx[b]] = d
        dist[idx[b], idx[a]] = d

    model = AgglomerativeClustering(
        n_clusters=None,
        metric="precomputed",
        linkage="average",
        distance_threshold=distance_threshold,
    )
    labels = model.fit_predict(dist)

    return {e: f"cluster_{labels[i]:04d}" for i, e in enumerate(entities)}

// agglomerative clusters entities using a precomputed distance matrix.
// The sklearn AgglomerativeClustering call is represented as a stub interface
// since Go has no scikit-learn binding; callers supply a Clusterer.
func agglomerative(
	cooccurrence map[[2]string]float64,
	entities []string,
	distanceThreshold float64,
	clusterer AgglomerativeClusterer,
) (map[string]string, error) {
	if clusterer == nil {
		return nil, fmt.Errorf("agglomerative: clusterer must not be nil")
	}
	n := len(entities)
	idx := make(map[string]int, n)
	for i, e := range entities {
		idx[e] = i
	}

	// Build distance matrix initialised to 1.0; diagonal = 0.0
	dist := make([][]float32, n)
	for i := range dist {
		dist[i] = make([]float32, n)
		for j := range dist[i] {
			dist[i][j] = 1.0
		}
		dist[i][i] = 0.0
	}

	var lo, span float64
	if len(cooccurrence) > 0 {
		lo = math.MaxFloat64
		hi := -math.MaxFloat64
		for _, v := range cooccurrence {
			if v < lo {
				lo = v
			}
			if v > hi {
				hi = v
			}
		}
		span = hi - lo
	}

	for pair, score := range cooccurrence {
