	idx := make(map[string]int, n)
	for i, e := range entities {
		idx[e] = i
	}

	dist := make([][]float32, n)
	for i := range dist {
		dist[i] = make([]float32, n)
		for j := range dist[i] {
			dist[i][j] = 1.0
		}
		dist[i][i] = 0.0
	}

	var lo, span float64
	if len(cooccurrence) > 0 {
		lo = math.MaxFloat64
		hi := -math.MaxFloat64
		for _, v := range cooccurrence {
			if v < lo {
				lo = v
			}
			if v > hi {
				hi = v
			}
		}
		span = hi - lo
	}

	for pair, score := range cooccurrence {
		a, b := pair[0], pair[1]
		ai, aok := idx[a]
		bi, bok := idx[b]
		if !aok || !bok {
			continue
		}
		var sim float64
		if span > 0 {
			sim = (score - lo) / span
		} else {
			sim = 1.0
		}
		d := float32(math.Max(0.0, 1.0-sim))
		dist[ai][bi] = d
		dist[bi][ai] = d
	}

	labels, err := clusterer.FitPredict(dist, distanceThreshold)
	if err != nil {
		return nil, fmt.Errorf("dbscan: fit_predict failed: %w", err)
	}

	// Find max assigned label to seed singleton counter
