def _leiden(
    cooccurrence: dict[tuple[str, str], float],
    entities: list[str],
    resolution: float,
) -> dict[str, str]:
    try:
        import igraph as ig
        import leidenalg
    except ImportError as e:
        raise ImportError(
            "igraph and leidenalg are required for Leiden clustering. "
            "Install with: pip install chonk[leiden]"
        ) from e

    idx = {e: i for i, e in enumerate(entities)}
    edges = []
    weights = []
    if cooccurrence:
        vals = list(cooccurrence.values())
        lo, hi = min(vals), max(vals)
        span = hi - lo if hi != lo else 1.0
    else:
        lo, span = 0.0, 1.0

    for (a, b), score in cooccurrence.items():
        if a in idx and b in idx:
            edges.append((idx[a], idx[b]))
            weights.append((score - lo) / span)

    g = ig.Graph(n=len(entities), edges=edges)
    g.es["weight"] = weights if weights else []

    partition = leidenalg.find_partition(
        g,
        leidenalg.RBConfigurationVertexPartition,
        weights="weight" if weights else None,
        resolution_parameter=resolution,
    )

    result = {}
    for cluster_idx, members in enumerate(partition):
        for member_idx in members:
            result[entities[member_idx]] = f"cluster_{cluster_idx:04d}"
    return result

// leiden clusters entities using the Leiden algorithm via a LeidenClusterer interface.
func leiden(
	cooccurrence map[[2]string]float64,
	entities []string,
	resolution float64,
	clusterer LeidenClusterer,
) (map[string]string, error) {
	if clusterer == nil {
		return nil, fmt.Errorf("leiden: clusterer must not be nil")
	}
	idx := make(map[string]int, len(entities))
	for i, e := range entities {
		idx[e] = i
	}

	type edge struct{ a, b int }
	var edges []edge
	var weights []float64

	var lo, span float64
	span = 1.0
	if len(cooccurrence) > 0 {
		lo = math.MaxFloat64
		hi := -math.MaxFloat64
		for _, v := range cooccurrence {
			if v < lo {
				lo = v
			}
			if v > hi {
				hi = v
			}
		}
		if hi != lo {
			span = hi - lo
		}
	}

	for pair, score := range cooccurrence {
		a, b := pair[0], pair[1]
		ai, aok := idx[a]
		bi, bok := idx[b]
		if !aok || !bok {
			continue
		}
		edges = append(edges, edge{ai, bi})
		weights = append(weights, (score-lo)/span)
	}

	// Convert edges to [][2]int for the clusterer interface
	edgePairs := make([][2]int, len(edges))
	for i, e := range edges {
		edgePairs[i] = [2]int{e.a, e.b}
	}

	partition, err := clusterer.FindPartition(len(entities), edgePairs, weights, resolution)
	if err != nil {
		return nil, fmt.Errorf("leiden: find_partition failed: %w", err)
	}

	result := make(map[string]string, len(entities))
	for clusterIdx, members := range partition {
		for _, memberIdx := range members {
			result[entities[memberIdx]] = fmt.Sprintf("cluster_%04d", clusterIdx)
		}
	}
	return result, nil
}

