// ClusterMapFromDict reconstructs a ClusterMap from the map produced by ToDict.
func ClusterMapFromDict(data map[string]interface{}) (*ClusterMap, error) {
	cm := &ClusterMap{
		entityToCluster:   make(map[string]string),
		clusterToEntities: make(map[string][]string),
		clusters:          make(map[string]ClusterRecord),
	}

	if assignments, ok := data["assignments"]; ok {
		if amap, ok := assignments.(map[string]string); ok {
			for k, v := range amap {
				cm.entityToCluster[k] = v
			}
		}
	}

	var clustersRaw map[string]interface{}
	if v, ok := data["clusters"]; ok {
		if m, ok := v.(map[string]interface{}); ok {
			clustersRaw = m
		}
	}

	for _, clusterData := range clustersRaw {
		cd, ok := clusterData.(map[string]interface{})
		if !ok {
			return nil, fmt.Errorf("ClusterMapFromDict: invalid cluster_data entry")
		}
		cid, ok := cd["cluster_id"].(string)
		if !ok {
			return nil, fmt.Errorf("ClusterMapFromDict: cluster_id missing or not string")
		}
		var members []string
		if raw, ok := cd["entities"]; ok {
			if sl, ok := raw.([]string); ok {
				members = sl
			}
		}
		var cohesion float64
		if v, ok := cd["cohesion_score"]; ok {
			if f, ok := v.(float64); ok {
				cohesion = f
			}
		}
		cm.clusterToEntities[cid] = members
		cm.clusters[cid] = ClusterRecord{
			ClusterID:     cid,
			Entities:      members,
			CohesionScore: cohesion,
		}
	}
	return cm, nil
}

