		product := strings.ReplaceAll(parts[4], "_", " ")
		base = fmt.Sprintf("%s/%s", vendor, product)
	} else {
		base = criteria
	}

	var ranges []string
	// R11: if match.get("versionStartIncluding") → explicit string check
	if v, _ := match["versionStartIncluding"].(string); len(v) > 0 {
		ranges = append(ranges, fmt.Sprintf(">= %s", v))
	}
	if v, _ := match["versionStartExcluding"].(string); len(v) > 0 {
		ranges = append(ranges, fmt.Sprintf("> %s", v))
	}
	if v, _ := match["versionEndIncluding"].(string); len(v) > 0 {
		ranges = append(ranges, fmt.Sprintf("<= %s", v))
	}
	if v, _ := match["versionEndExcluding"].(string); len(v) > 0 {
		ranges = append(ranges, fmt.Sprintf("< %s", v))
	}

	if len(ranges) > 0 {
		return fmt.Sprintf("%s (%s)", base, strings.Join(ranges, ", "))
	}
