def _get_body(msg: Message) -> str:
    """Return the best available plain-text body."""
    if msg.is_multipart():
        # Prefer text/plain; fall back to text/html
        for preferred_type in ("text/plain", "text/html"):
            for part in msg.walk():
                if part.get_content_type() != preferred_type:
                    continue
                if "attachment" in part.get("Content-Disposition", ""):
                    continue
                payload = part.get_payload(decode=True)
                if not payload or not isinstance(payload, bytes):
                    continue
                charset = part.get_content_charset() or "utf-8"
                text = payload.decode(charset, errors="replace")
                if preferred_type == "text/html":
                    from ._html import HtmlExtractor
                    return HtmlExtractor().extract(payload)
                return text
    else:
        payload = msg.get_payload(decode=True)
        if payload and isinstance(payload, bytes):
            charset = msg.get_content_charset() or "utf-8"
            text = payload.decode(charset, errors="replace")
            if msg.get_content_type() == "text/html":
                from ._html import HtmlExtractor
                return HtmlExtractor().extract(payload)
            return text
    return ""

// getBody returns the best available plain-text body from a parsed email message.
// It prefers text/plain; falls back to text/html (which is passed through extractHTML).
func getBody(msg *mail.Message) string {
