	mediaType, params, err := mime.ParseMediaType(contentType)
	// R03: error from mime.ParseMediaType — treat as non-multipart on failure
	if err != nil {
		mediaType = "text/plain"
		params = map[string]string{}
	}

	if strings.HasPrefix(mediaType, "multipart/") {
		boundary := params["boundary"]
		body, err := io.ReadAll(msg.Body)
		if err != nil {
			return ""
		}
		// R10: for preferred_type in (...) → for _, preferredType := range ...
		for _, preferredType := range []string{"text/plain", "text/html"} {
			mr := multipart.NewReader(bytes.NewReader(body), boundary)
			for {
				part, err := mr.NextPart()
				if err != nil {
					break
				}
				partContentType := part.Header.Get("Content-Type")
				partMedia, partParams, _ := mime.ParseMediaType(partContentType)
				// R11: if part.get_content_type() != preferred_type → explicit string compare
				if partMedia != preferredType {
					continue
				}
				// R11: if "attachment" in ... → strings.Contains
				disp := part.Header.Get("Content-Disposition")
				if strings.Contains(disp, "attachment") {
					continue
				}
				payload, err := io.ReadAll(part)
				if err != nil || len(payload) == 0 {
					continue
				}
				charset := partParams["charset"]
				if len(charset) == 0 {
					charset = "utf-8"
				}
				// R03: decode with charset — use golang.org/x/text or fallback
				text, err := decodeBytes(payload, charset)
				if err != nil {
					text = string(payload)
				}
				if preferredType == "text/html" {
					return extractHTML(payload)
				}
				return text
			}
		}
	} else {
		// Non-multipart: read body directly
		payload, err := io.ReadAll(msg.Body)
		// R11: if payload and isinstance(payload, bytes) → if err == nil && len(payload) > 0
		if err == nil && len(payload) > 0 {
			charset := params["charset"]
			if len(charset) == 0 {
				charset = "utf-8"
			}
			text, err := decodeBytes(payload, charset)
			if err != nil {
				text = string(payload)
			}
			if mediaType == "text/html" {
				return extractHTML(payload)
			}
			return text
		}
	}
	return ""
}

