			}
			svoSignal := 0.0
			if _, ok := svoPairs[svoPair{pairA, pairB}]; ok {
				svoSignal = 1.0
			}

			sharedChunkCount := 0
			for cid := range entityToChunks[a] {
				if _, ok := entityToChunks[b][cid]; ok {
					sharedChunkCount++
				}
			}
			coocSignal := float64(sharedChunkCount) * 0.8
			if coocSignal > 0.8 {
				coocSignal = 0.8
			}

			clustersA := entityToClusters[a]
			clustersB := entityToClusters[b]
			clusSignal := 0.0
			if len(clustersA) > 0 || len(clustersB) > 0 {
				sharedClus := 0
				for c := range clustersA {
					if _, ok := clustersB[c]; ok {
						sharedClus++
					}
				}
				unionClus := len(clustersA) + len(clustersB) - sharedClus
				if unionClus > 0 {
					clusSignal = 0.4 * float64(sharedClus) / float64(unionClus)
				}
			}

			rawW := svoSignal + coocSignal + clusSignal
			if rawW > 0 {
				rawEdges = append(rawEdges, rawEdge{a, b, rawW, svoSignal, coocSignal, clusSignal})
			}
		}
	}

	maxRaw := 0.0
	for _, e := range rawEdges {
		if e.rawWeight > maxRaw {
			maxRaw = e.rawWeight
		}
	}

	var finalEdges []finalEdge
	for _, e := range rawEdges {
		weight := 0.0
		if maxRaw > 0 {
			weight = e.rawWeight / maxRaw
		}
		if weight >= minWeight {
			finalEdges = append(finalEdges, finalEdge{e.a, e.b, weight, e.svoS, e.coocS, e.clusS})
		}
	}

	if _, err := conn.Execute("DELETE FROM context_graph_edges WHERE namespace = ?", []interface{}{namespace}); err != nil {
		return ContextGraphStats{}, fmt.Errorf("build_context_graph_edges: delete edges: %w", err)
	}
	var insertRows [][]interface{}
	for _, e := range finalEdges {
		insertRows = append(insertRows, []interface{}{e.a, e.b, namespace, e.weight, e.svoS, e.coocS, e.clusS})
		insertRows = append(insertRows, []interface{}{e.b, e.a, namespace, e.weight, e.svoS, e.coocS, e.clusS})
	}
	if len(insertRows) > 0 {
		if err := conn.ExecuteMany(
			"INSERT INTO context_graph_edges (source_entity_id, target_entity_id, namespace, weight, svo_signal, cooccur_signal, cluster_signal) VALUES (?, ?, ?, ?, ?, ?, ?)",
			insertRows,
		); err != nil {
			return ContextGraphStats{}, fmt.Errorf("build_context_graph_edges: insert: %w", err)
		}
	}

	edgeCount := len(finalEdges) * 2
	entityCount := len(allEntities)

	if _, err := conn.Execute(
		`INSERT INTO context_graph_cache (namespace, chunk_fingerprint, entity_count, edge_count)
		VALUES (?, ?, ?, ?)
		ON CONFLICT (namespace) DO UPDATE SET
			chunk_fingerprint = excluded.chunk_fingerprint,
			entity_count = excluded.entity_count,
			edge_count = excluded.edge_count,
			created_at = now()`,
		[]interface{}{namespace, fullFingerprint, entityCount, edgeCount},
	); err != nil {
		return ContextGraphStats{}, fmt.Errorf("build_context_graph_edges: upsert cache: %w", err)
	}

	return ContextGraphStats{
		EntityCount: entityCount,
		EdgeCount:   edgeCount,
		ChunkCount:  len(chunkIDs),
	}, nil
}

// BuildContextGraphAllNamespaces builds context graph edges for every
// namespace present in chunk_entities and returns a map of namespace to stats.
func BuildContextGraphAllNamespaces(
	conn DBConn,
	minWeight float64,
	force bool,
	algorithm string,
	minChunks int,
) (map[string]ContextGraphStats, error) {
	rows, err := conn.Execute(
		"SELECT DISTINCT COALESCE(namespace, 'global') FROM chunk_entities",
		nil,
	)
	if err != nil {
		return nil, fmt.Errorf("build_context_graph_all_namespaces: query namespaces: %w", err)
	}
	var namespaces []string
	for _, r := range rows {
		namespaces = append(namespaces, r[0].(string))
	}
	results := make(map[string]ContextGraphStats, len(namespaces))
	for _, ns := range namespaces {
		stats, err := BuildContextGraphEdges(conn, ns, minWeight, force, algorithm, minChunks)
		if err != nil {
			return nil, fmt.Errorf("build_context_graph_all_namespaces: namespace %q: %w", ns, err)
		}
		results[ns] = stats
	}
	return results, nil
}

// GetContextGraphEdges fetches weighted ContextEdge neighbours for entityID
// in the given namespace, ordered by descending weight. Returns an empty slice
// (with a debug log) when the context graph has not yet been built.
func GetContextGraphEdges(
	conn DBConn,
	entityID string,
	namespace string,
	minWeight float64,
) ([]ContextEdge, error) {
	hasEdgesRow, probeErr := conn.FetchOne(
		"SELECT 1 FROM context_graph_edges WHERE namespace = ? LIMIT 1",
		[]interface{}{namespace},
	)
	hasEdges := probeErr == nil && hasEdgesRow != nil

	if !hasEdges {
		log.Printf("context graph not built for namespace %q — skipping expansion; call build_context_graph() to enable", namespace)
		return []ContextEdge{}, nil
	}

	rows, err := conn.Execute(
		`SELECT target_entity_id, weight, svo_signal, cooccur_signal, cluster_signal
		FROM context_graph_edges
		WHERE source_entity_id = ? AND namespace = ? AND weight >= ?
		ORDER BY weight DESC`,
		[]interface{}{entityID, namespace, minWeight},
	)
	if err != nil {
		return nil, fmt.Errorf("get_context_graph_edges: query: %w", err)
	}

	edges := make([]ContextEdge, 0, len(rows))
	for _, r := range rows {
		edges = append(edges, ContextEdge{
			SourceEntityID: entityID,
			TargetEntityID: r[0].(string),
			Weight:         r[1].(float64),
			SVOSignal:      r[2].(float64),
			CooccurSignal:  r[3].(float64),
			ClusterSignal:  r[4].(float64),
		})
	}
	return edges, nil
}

// embedEntities fetches all entities and their aliases, builds embedding text
// for each entity, encodes them with the embed model, removes stale entity
// embeddings, and writes fresh ones via store.AddDocument.
// Returns the number of entity chunks written.
func (p *EntityGraphPipeline) embedEntities(store Store, prog ProgressFn) (int, error) {
	if p.embedModel == nil {
		return 0, fmt.Errorf("embedEntities: called without embed_model")
	}
	conn := store.DB().Conn()

	entityRows, err := conn.Execute(`
		SELECT e.id, e.name,
		       COALESCE(e.description, '') AS description,
		       e.entity_type
		FROM entities e`, nil)
	if err != nil {
		return 0, fmt.Errorf("embedEntities: query entities: %w", err)
	}
	if len(entityRows) == 0 {
		return 0, nil
	}

	aliasQueryRows, aliasErr := conn.Execute(
		"SELECT entity_id, alias FROM entity_aliases WHERE namespace = ?",
		[]interface{}{p.namespace},
	)
	if aliasErr != nil {
		aliasQueryRows = nil
	}
	aliasesMap := make(map[string][]string)
	for _, row := range aliasQueryRows {
		eid := row[0].(string)
		alias := row[1].(string)
		aliasesMap[eid] = append(aliasesMap[eid], alias)
	}

	var texts []string
	var chunks []DocumentChunk
	for _, row := range entityRows {
		entityID := row[0].(string)
		name := row[1].(string)
		description := row[2].(string)

		aliasSlice := aliasesMap[entityID]
		aliasStr := strings.Join(aliasSlice, ", ")

		parts := []string{name}
		if len(aliasStr) > 0 {
			parts = append(parts, aliasStr)
		}
		if len(description) > 0 {
			parts = append(parts, description)
		}
		text := strings.Join(parts, ". ")
		texts = append(texts, text)
		chunks = append(chunks, DocumentChunk{
			DocumentName: fmt.Sprintf("__entity__%s", entityID),
			Content:      text,
			ChunkIndex:   0,
			ChunkType:    "entity",
		})
	}

	prog(PhaseEmbedEntities, 0, len(chunks))
	vecs, err := p.embedModel.Encode(texts)
	if err != nil {
		return 0, fmt.Errorf("embedEntities: encode: %w", err)
	}

	if _, err := conn.Execute("DELETE FROM embeddings WHERE chunk_type = 'entity'", nil); err != nil {
		return 0, fmt.Errorf("embedEntities: delete stale: %w", err)
	}
	if err := store.AddDocument(chunks, vecs); err != nil {
		return 0, fmt.Errorf("embedEntities: add_document: %w", err)
	}
	prog(PhaseEmbedEntities, len(chunks), len(chunks))
	return len(chunks), nil
}

// SVOExtractorOptions holds optional overrides for NewSVOExtractor.
type SVOExtractorOptions struct {
	// VerbSet overrides the default VERB_SET. nil uses the built-in set.
	VerbSet map[string]struct{}
	// SystemPromptTemplate overrides the default system prompt.
	// Must contain a {verbs} placeholder. Empty string uses the built-in prompt.
	SystemPromptTemplate string
	// UserTemplate overrides the default per-chunk user message.
	// Must contain {chunk_id} and {text} placeholders.
	// Empty string uses the built-in template.
	UserTemplate string
}

// SVOExtractor extracts SVOTriples from text using an injected LLMClient.
type SVOExtractor struct {
	llm          LLMClient
	verbSet      map[string]struct{}
	userTemplate string
	system       string
}

// NewSVOExtractor constructs an SVOExtractor. llm must be non-nil.
// Options fields left empty receive their documented defaults.
func NewSVOExtractor(llm LLMClient, opts SVOExtractorOptions) (*SVOExtractor, error) {
	if llm == nil {
		return nil, fmt.Errorf("NewSVOExtractor: llm must not be nil")
	}
	verbSet := opts.VerbSet
	if len(verbSet) == 0 {
		verbSet = DefaultVerbSet()
	}
	sysTmpl := opts.SystemPromptTemplate
	if len(sysTmpl) == 0 {
		sysTmpl = defaultSystemPrompt
	}
	userTmpl := opts.UserTemplate
	if len(userTmpl) == 0 {
		userTmpl = defaultUserTemplate
	}
	verbsSorted := make([]string, 0, len(verbSet))
	for v := range verbSet {
		verbsSorted = append(verbsSorted, v)
	}
	sort.Strings(verbsSorted)
	systemPrompt := strings.ReplaceAll(sysTmpl, "{verbs}", strings.Join(verbsSorted, ", "))
	return &SVOExtractor{
		llm:          llm,
		verbSet:      verbSet,
		userTemplate: userTmpl,
		system:       systemPrompt,
	}, nil
}

