def _parse(self, raw: str, chunk_id: str | None) -> list[SVOTriple] | None:
        """Parse LLM response into validated SVOTriples. Returns None on JSON failure."""
        cleaned = re.sub(r"```(?:json)?|```", "", raw).strip()
        try:
            rows = json.loads(cleaned)
        except json.JSONDecodeError:
            return None

        if not isinstance(rows, list):
            return None

        triples: list[SVOTriple] = []
        for row in rows:
            try:
                verb = str(row["verb"])
                if verb not in self._verb_set:
                    continue
                triples.append(SVOTriple(
                    subject_id=str(row["subject_id"]),
                    verb=verb,
                    object_id=str(row["object_id"]),
                    confidence=float(row["confidence"]),
                    source_chunk_id=chunk_id,
                ))
            except (KeyError, TypeError, ValueError):
                continue

        return triples

// parse strips markdown fences from raw, JSON-decodes it as an array of objects,
// validates each entry's verb against the extractor's verb set, and returns
// a slice of SVOTriples. Returns nil, nil when the JSON is invalid or not an array.
func (e *SVOExtractor) parse(raw string, chunkID *string) ([]SVOTriple, error) {
	// Strip ```json ... ``` or ``` ... ``` fences
	cleaned := markdownFenceRE.ReplaceAllString(raw, "")
	cleaned = strings.TrimSpace(cleaned)

	var decoded []interface{}
	if err := json.Unmarshal([]byte(cleaned), &decoded); err != nil {
		// Signal parse failure with nil slice and no error — caller retries
		return nil, nil
	}
	if len(decoded) == 0 {
		// Empty array is valid — return empty slice
		return []SVOTriple{}, nil
	}

	var triples []SVOTriple
	for _, item := range decoded {
		row, ok := item.(map[string]interface{})
		if !ok {
			continue
		}
		verbRaw, ok := row["verb"]
		if !ok {
			continue
		}
		verb, ok := verbRaw.(string)
		if !ok {
			continue
		}
		if _, allowed := e.verbSet[verb]; !allowed {
			continue
		}
		subjRaw, hasSubj := row["subject_id"]
		objRaw, hasObj := row["object_id"]
		confRaw, hasConf := row["confidence"]
		if !hasSubj || !hasObj || !hasConf {
			continue
		}
		subj, ok1 := subjRaw.(string)
		obj, ok2 := objRaw.(string)
		conf, ok3 := confRaw.(float64)
		if !ok1 || !ok2 || !ok3 {
			continue
		}
		triples = append(triples, SVOTriple{
			SubjectID:     subj,
			Verb:          verb,
			ObjectID:      obj,
			Confidence:    conf,
			SourceChunkID: chunkID,
		})
	}
	return triples, nil
}

Translate the Python function `_check_cache` to Go. Apply R03 (try/except -> error returns), R05 (dict/set -> map), R10 (for x in xs -> range), R11 (truthiness -> explicit checks). The function queries a DB connection, computes set differences, and returns a 3-tuple signalling early-return, incremental mode, and a skip-ID set.

def _check_cache(con, fingerprint: str, force: bool) -> tuple[bool, bool, set[str]]:
    all_chunk_ids: set[str] = {
        row[0] for row in con.execute("SELECT chunk_id FROM embeddings").fetchall()
    }
    processed_ids: set[str] = {
        row[0] for row in con.execute("SELECT DISTINCT chunk_id FROM chunk_entities").fetchall()
    }
    cached = con.execute(
        "SELECT chunk_count FROM ner_cache WHERE config_fingerprint = ?", [fingerprint]
    ).fetchone()

    config_match = cached is not None
    new_chunk_ids = all_chunk_ids - processed_ids

    if force:
        return False, False, set()
    if config_match and not new_chunk_ids:
        return True, False, set()
    if config_match and new_chunk_ids:
        return False, True, processed_ids
    return False, False, set()

// checkCache determines incremental mode and skip set.
// Returns (shouldReturnEarly, incremental, skipIDs).
func checkCache(con DB, fingerprint string, force bool) (bool, bool, map[string]struct{}, error) {
	allChunkRows, err := con.Execute("SELECT chunk_id FROM embeddings")
	if err != nil {
		return false, false, nil, fmt.Errorf("checkCache: query embeddings: %w", err)
	}
	allChunkIDs := make(map[string]struct{})
	for _, row := range allChunkRows {
		allChunkIDs[row[0]] = struct{}{}
	}

	processedRows, err := con.Execute("SELECT DISTINCT chunk_id FROM chunk_entities")
	if err != nil {
		return false, false, nil, fmt.Errorf("checkCache: query chunk_entities: %w", err)
	}
	processedIDs := make(map[string]struct{})
	for _, row := range processedRows {
		processedIDs[row[0]] = struct{}{}
	}

	cachedRow, err := con.ExecuteOne("SELECT chunk_count FROM ner_cache WHERE config_fingerprint = ?", fingerprint)
	if err != nil {
		return false, false, nil, fmt.Errorf("checkCache: query ner_cache: %w", err)
	}
	configMatch := cachedRow != nil

	newChunkIDs := make(map[string]struct{})
	for id := range allChunkIDs {
		if _, found := processedIDs[id]; !found {
			newChunkIDs[id] = struct{}{}
		}
	}

	if force {
		return false, false, make(map[string]struct{}), nil
	}
	if configMatch && len(newChunkIDs) == 0 {
		return true, false, make(map[string]struct{}), nil
	}
	if configMatch && len(newChunkIDs) > 0 {
		return false, true, processedIDs, nil
	}
	return false, false, make(map[string]struct{}), nil
}

