def _run_ner_on_chunks(
    chunks_to_process,
    matcher: SpacyMatcher,
    schema_matcher,
    data_matcher,
) -> tuple[EntityIndex, dict[str, tuple[str, str, str]]]:
    from ._merge import merge_matches

    entity_index = EntityIndex()
    entity_meta: dict[str, tuple[str, str, str]] = {}

    for chunk_id, chunk in chunks_to_process:
        if schema_matcher is not None or data_matcher is not None:
            vocab_hits: list = []
            if schema_matcher is not None:
                vocab_hits = merge_matches(
                    schema_matcher.match(chunk.content), vocab_hits,
                    source_text=chunk.content,
                )
            if data_matcher is not None:
                vocab_hits = merge_matches(
                    data_matcher.match(chunk.content), vocab_hits,
                    source_text=chunk.content,
                )
            combined = merge_matches(vocab_hits, matcher.match(chunk.content), source_text=chunk.content)
            for m in combined:
                if m.entity_id not in entity_meta:
                    entity_meta[m.entity_id] = (m.name, m.display_name, m.entity_type or "concept")
            entity_index.index_chunk(chunk_id, chunk.content, combined)
        else:
            matches = matcher.match(chunk.content)
            for m in matches:
                if m.entity_id not in entity_meta:
                    entity_meta[m.entity_id] = (m.name, m.display_name, m.entity_type or "concept")
            entity_index.index_chunk(chunk_id, chunk.content, matches)

    entity_index.recompute_scores()
    return entity_index, entity_meta

// EntityMeta holds (name, displayName, entityType) for one entity.
type EntityMeta struct {
	Name        string
	DisplayName string
	EntityType  string
}

// runNEROnChunks runs NER over chunksToProcess and returns the populated index plus entity metadata.
func runNEROnChunks(
	chunksToProcess []ChunkPair,
	matcher *SpacyMatcher,
	schemaMatcher *SchemaMatcher,
	dataMatcher *VocabularyMatcher,
) (*EntityIndex, map[string]EntityMeta, error) {
	entityIndex := NewEntityIndex(DefaultScoreWeights)
	entityMeta := make(map[string]EntityMeta)

	for _, pair := range chunksToProcess {
		chunkID := pair.ChunkID
		chunk := pair.Chunk
		if schemaMatcher != nil || dataMatcher != nil {
			var vocabHits []EntityMatch
			if schemaMatcher != nil {
				hits, err := schemaMatcher.Match(chunk.Content)
				if err != nil {
					return nil, nil, fmt.Errorf("runNEROnChunks: schema match: %w", err)
				}
				vocabHits, err = MergeMatches(hits, vocabHits, chunk.Content, true)
				if err != nil {
					return nil, nil, fmt.Errorf("runNEROnChunks: merge schema: %w", err)
				}
			}
			if dataMatcher != nil {
				hits, err := dataMatcher.Match(chunk.Content)
				if err != nil {
					return nil, nil, fmt.Errorf("runNEROnChunks: data match: %w", err)
				}
				vocabHits, err = MergeMatches(hits, vocabHits, chunk.Content, true)
				if err != nil {
					return nil, nil, fmt.Errorf("runNEROnChunks: merge data: %w", err)
				}
			}
			spacyHits, err := matcher.Match(chunk.Content)
			if err != nil {
				return nil, nil, fmt.Errorf("runNEROnChunks: spacy match: %w", err)
			}
			combined, err := MergeMatches(vocabHits, spacyHits, chunk.Content, true)
			if err != nil {
				return nil, nil, fmt.Errorf("runNEROnChunks: merge combined: %w", err)
			}
			for _, m := range combined {
				if _, exists := entityMeta[m.EntityID]; !exists {
					et := m.EntityType
					if et == "" {
						et = "concept"
					}
					entityMeta[m.EntityID] = EntityMeta{Name: m.Name, DisplayName: m.DisplayName, EntityType: et}
				}
			}
			entityIndex.IndexChunk(chunkID, chunk.Content, combined)
		} else {
			matches, err := matcher.Match(chunk.Content)
			if err != nil {
				return nil, nil, fmt.Errorf("runNEROnChunks: spacy match (no vocab): %w", err)
			}
			for _, m := range matches {
				if _, exists := entityMeta[m.EntityID]; !exists {
					et := m.EntityType
					if et == "" {
						et = "concept"
					}
					entityMeta[m.EntityID] = EntityMeta{Name: m.Name, DisplayName: m.DisplayName, EntityType: et}
				}
			}
			entityIndex.IndexChunk(chunkID, chunk.Content, matches)
		}
	}
	entityIndex.RecomputeScores()
	return entityIndex, entityMeta, nil
}

