    return new_start, new_end

// SpanBounds holds an adjusted [start, end) character span.
type SpanBounds struct {
	Start int
	End   int
}

// stripSpan trims leading and trailing boundary characters and whitespace from [start,end).
// Returns nil if the span becomes empty after stripping.
func stripSpan(text string, start, end int) *SpanBounds {
	runes := []rune(text)
	spanRunes := runes[start:end]
	newStart := start
	for _, ch := range spanRunes {
		if boundaryChars[ch] || ch == ' ' || ch == '\t' || ch == '\n' || ch == '\r' {
			newStart++
		} else {
			break
		}
	}
	newEnd := end
	inner := runes[newStart:end]
	for i := len(inner) - 1; i >= 0; i-- {
		ch := inner[i]
		if boundaryChars[ch] || ch == ' ' || ch == '\t' || ch == '\n' || ch == '\r' {
			newEnd--
		} else {
			break
		}
	}
	if newEnd <= newStart {
		return nil
	}
	return &SpanBounds{Start: newStart, End: newEnd}
}

// MergeMatches merges vocabulary and generic entity matches.
// Vocab matches take priority; generic occurrences overlapping a vocab span are suppressed.
func MergeMatches(vocabMatches, genericMatches []EntityMatch, sourceText string, boundaryStrip bool) ([]EntityMatch, error) {
	var vocabSpanSet [][2]int
	for _, m := range vocabMatches {
		for _, sp := range m.Spans {
			vocabSpanSet = append(vocabSpanSet, sp)
		}
	}

	var survivingGeneric []EntityMatch
	for _, gm := range genericMatches {
		var keptSpans [][2]int
		for _, span := range gm.Spans {
			if boundaryStrip && len(sourceText) > 0 {
				stripped := stripSpan(sourceText, span[0], span[1])
				if stripped == nil {
					continue
				}
				span = [2]int{stripped.Start, stripped.End}
			}
			overlaps := false
			for _, vs := range vocabSpanSet {
				if span[0] < vs[1] && vs[0] < span[1] {
					overlaps = true
					break
				}
			}
			if !overlaps {
				keptSpans = append(keptSpans, span)
			}
		}
		if len(keptSpans) > 0 {
			positions := make([]int, len(keptSpans))
			for i, s := range keptSpans {
				positions[i] = s[0]
			}
			survivingGeneric = append(survivingGeneric, EntityMatch{
				EntityID:    gm.EntityID,
				Name:        gm.Name,
				DisplayName: gm.DisplayName,
				EntityType:  gm.EntityType,
				Frequency:   len(keptSpans),
				Positions:   positions,
				Spans:       keptSpans,
			})
		}
	}

	merged := make(map[string]EntityMatch)
	all := append(vocabMatches, survivingGeneric...)
	for _, m := range all {
		if _, exists := merged[m.EntityID]; !exists {
			merged[m.EntityID] = EntityMatch{
				EntityID:    m.EntityID,
				Name:        m.Name,
				DisplayName: m.DisplayName,
				EntityType:  m.EntityType,
				Frequency:   0,
				Positions:   nil,
				Spans:       nil,
			}
		}
		existing := merged[m.EntityID]
		existingStarts := make(map[int]struct{})
		for _, s := range existing.Spans {
			existingStarts[s[0]] = struct{}{}
		}
		var newSpans [][2]int
		for _, s := range m.Spans {
			if _, dup := existingStarts[s[0]]; !dup {
				newSpans = append(newSpans, s)
			}
		}
		allSpans := append(existing.Spans, newSpans...)
		sort.Slice(allSpans, func(i, j int) bool { return allSpans[i][0] < allSpans[j][0] })
		positions := make([]int, len(allSpans))
		for i, s := range allSpans {
			positions[i] = s[0]
		}
		merged[m.EntityID] = EntityMatch{
			EntityID:    existing.EntityID,
			Name:        existing.Name,
			DisplayName: existing.DisplayName,
			EntityType:  existing.EntityType,
			Frequency:   len(allSpans),
			Positions:   positions,
			Spans:       allSpans,
		}
	}

	result := make([]EntityMatch, 0, len(merged))
	for _, v := range merged {
		result = append(result, v)
	}
	return result, nil
}

